using System;
using System.Reflection;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.GameApi;

/// <summary>Reflection-safe access to ENT_Player health and hand grip (stamina).</summary>
public static class PlayerAccess
{
    private static readonly FieldInfo HealthField =
        AccessTools.Field(typeof(GameEntity), "health")!;

    private static readonly FieldInfo MaxHealthField =
        AccessTools.Field(typeof(GameEntity), "maxHealth")!;

    private static readonly FieldInfo HandsField =
        AccessTools.Field(typeof(ENT_Player), "hands")!;

    private static readonly Type HandType = AccessTools.Inner(typeof(ENT_Player), "Hand")!;

    private static readonly FieldInfo GripStrengthField =
        AccessTools.Field(HandType, "gripStrength")!;

    private static readonly Type DamageInfoType =
        AccessTools.Inner(typeof(Damageable), "DamageInfo")!;

    private static readonly FieldInfo DamageAmountField =
        AccessTools.Field(DamageInfoType, "amount")!;

    private static readonly FieldInfo DamageTypeField =
        AccessTools.Field(DamageInfoType, "type")!;

    private const float MaxGrip = 1f;

    public static ENT_Player? FindPlayer() => UnityEngine.Object.FindObjectOfType<ENT_Player>();

    public static float GetHealth(ENT_Player player) =>
        (float)(HealthField.GetValue(player) ?? 0f);

    public static float GetMaxHealth(ENT_Player player) =>
        (float)(MaxHealthField.GetValue(player) ?? 1f);

    public static void SetHealth(ENT_Player player, float value)
    {
        var max = GetMaxHealth(player);
        HealthField.SetValue(player, Mathf.Clamp(value, 0f, max));
    }

    public static bool IsGrounded(ENT_Player player) => player.IsGrounded(false);

    public static float GetAverageGrip(ENT_Player player)
    {
        var hands = HandsField.GetValue(player) as Array;
        if (hands == null || hands.Length == 0)
            return 0f;

        float sum = 0f;
        for (var i = 0; i < hands.Length; i++)
            sum += (float)(GripStrengthField.GetValue(hands.GetValue(i)!) ?? 0f);
        return sum / hands.Length;
    }

    public static void AddGripToAllHands(ENT_Player player, float delta)
    {
        var hands = HandsField.GetValue(player) as Array;
        if (hands == null)
            return;

        for (var i = 0; i < hands.Length; i++)
        {
            var hand = hands.GetValue(i)!;
            var current = (float)(GripStrengthField.GetValue(hand) ?? 0f);
            GripStrengthField.SetValue(hand, Mathf.Clamp(current + delta, 0f, MaxGrip));
        }
    }

    public static void ApplyDamage(ENT_Player player, float amount, string damageType = "SpikeBalanceMod")
    {
        if (amount <= 0f)
            return;

        var info = Activator.CreateInstance(DamageInfoType)!;
        DamageAmountField.SetValue(info, amount);
        DamageTypeField.SetValue(info, damageType);
        player.Damage((DamageInfo)info);
    }
}

using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>Marks colliders created by this mod as spike ground.</summary>
public sealed class SpikeSurfaceMarker : MonoBehaviour
{
}

using System.Collections.Generic;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public readonly struct SpikePlacement
{
    public Vector3 Position { get; }
    public Vector3 Normal { get; }

    public SpikePlacement(Vector3 position, Vector3 normal)
    {
        Position = position;
        Normal = normal;
    }
}

public sealed class SpikeSurfaceScanner
{
    private readonly float _minUpDot;
    private readonly float _spacing;
    private readonly int _maxSpikes;
    private readonly HashSet<long> _occupiedCells = new();

    public SpikeSurfaceScanner(float minUpDot, float spacing, int maxSpikes)
    {
        _minUpDot = minUpDot;
        _spacing = Mathf.Max(0.25f, spacing);
        _maxSpikes = maxSpikes;
    }

    public List<SpikePlacement> ScanScene()
    {
        _occupiedCells.Clear();
        var results = new List<SpikePlacement>(_maxSpikes);
        var colliders = Object.FindObjectsOfType<Collider>();

        foreach (var col in colliders)
        {
            if (results.Count >= _maxSpikes)
                break;
            if (!ShouldScan(col))
                continue;

            switch (col)
            {
                case MeshCollider meshCol when meshCol.sharedMesh != null:
                    ScanMesh(meshCol, results);
                    break;
                case BoxCollider boxCol:
                    ScanBox(boxCol, results);
                    break;
                case TerrainCollider terrainCol when terrainCol.terrainData != null:
                    ScanTerrain(terrainCol, results);
                    break;
            }
        }

        return results;
    }

    private bool ShouldScan(Collider col)
    {
        if (!col.enabled || col.isTrigger)
            return false;
        if (col.GetComponentInParent<ENT_Player>() != null)
            return false;
        if (col.GetComponentInParent<SpikeSurfaceMarker>() != null)
            return false;
        if (col.GetComponentInParent<CL_Handhold>() != null)
            return false;

        var name = col.gameObject.name;
        if (name.Contains("Player") || name.Contains("Hand") || name.Contains("UI"))
            return false;

        return true;
    }

    private void ScanMesh(MeshCollider meshCol, List<SpikePlacement> results)
    {
        var mesh = meshCol.sharedMesh;
        var tr = meshCol.transform;
        var verts = mesh.vertices;
        var tris = mesh.triangles;

        for (var i = 0; i < tris.Length && results.Count < _maxSpikes; i += 3)
        {
            var w0 = tr.TransformPoint(verts[tris[i]]);
            var w1 = tr.TransformPoint(verts[tris[i + 1]]);
            var w2 = tr.TransformPoint(verts[tris[i + 2]]);
            var normal = Vector3.Cross(w1 - w0, w2 - w0).normalized;
            if (normal.y < _minUpDot)
                continue;

            var center = (w0 + w1 + w2) / 3f;
            TryAdd(center, normal, results);
        }
    }

    private void ScanBox(BoxCollider box, List<SpikePlacement> results)
    {
        var tr = box.transform;
        var c = box.center;
        var e = box.size * 0.5f;

        // Top face in collider local space (+Y).
        var localNormal = Vector3.up;
        var worldNormal = tr.TransformDirection(localNormal).normalized;
        if (worldNormal.y < _minUpDot)
            return;

        var steps = Mathf.Max(1, Mathf.FloorToInt(Mathf.Max(box.size.x, box.size.z) / _spacing));
        for (var x = 0; x <= steps && results.Count < _maxSpikes; x++)
        {
            for (var z = 0; z <= steps && results.Count < _maxSpikes; z++)
            {
                var lx = Mathf.Lerp(-e.x, e.x, steps == 0 ? 0.5f : (float)x / steps);
                var lz = Mathf.Lerp(-e.z, e.z, steps == 0 ? 0.5f : (float)z / steps);
                var local = c + new Vector3(lx, e.y, lz);
                var world = tr.TransformPoint(local);
                TryAdd(world, worldNormal, results);
            }
        }
    }

    private void ScanTerrain(TerrainCollider terrainCol, List<SpikePlacement> results)
    {
        var terrain = terrainCol.terrainData;
        var tr = terrainCol.transform;
        var size = terrain.size;
        var res = terrain.heightmapResolution;
        var step = Mathf.Max(1, Mathf.RoundToInt(_spacing / (size.x / res)));

        for (var y = 0; y < res && results.Count < _maxSpikes; y += step)
        {
            for (var x = 0; x < res && results.Count < _maxSpikes; x += step)
            {
                var nx = (float)x / (res - 1);
                var ny = (float)y / (res - 1);
                var normal = terrain.GetInterpolatedNormal(nx, ny);
                var worldNormal = tr.TransformDirection(normal).normalized;
                if (worldNormal.y < _minUpDot)
                    continue;

                var height = terrain.GetInterpolatedHeight(nx, ny);
                var world = tr.TransformPoint(new Vector3(nx * size.x, height, ny * size.z));
                TryAdd(world, worldNormal, results);
            }
        }
    }

    private void TryAdd(Vector3 position, Vector3 normal, List<SpikePlacement> results)
    {
        if (!TryReserveCell(position))
            return;
        results.Add(new SpikePlacement(position, normal));
    }

    private bool TryReserveCell(Vector3 position)
    {
        var cell = new Vector3Int(
            Mathf.FloorToInt(position.x / _spacing),
            Mathf.FloorToInt(position.y / _spacing),
            Mathf.FloorToInt(position.z / _spacing));
        var key = ((long)cell.x << 42) ^ ((long)cell.y << 21) ^ (uint)cell.z;
        return _occupiedCells.Add(key);
    }
}

using System.Collections.Generic;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public sealed class SpikePlacer
{
    private const string RootName = "SpikeBalanceMod_Root";
    private Transform? _root;

    public void Clear()
    {
        var existing = GameObject.Find(RootName);
        if (existing != null)
            Object.Destroy(existing);
        _root = null;
    }

    public int PlaceAll(IReadOnlyList<SpikePlacement> placements, float spikeHeight)
    {
        Clear();
        var rootGo = new GameObject(RootName);
        _root = rootGo.transform;

        var count = 0;
        foreach (var p in placements)
        {
            CreateSpike(p, spikeHeight, _root);
            count++;
        }

        return count;
    }

    private static void CreateSpike(SpikePlacement placement, float spikeHeight, Transform parent)
    {
        var go = new GameObject("Spike");
        go.transform.SetParent(parent, false);
        go.transform.position = placement.Position + placement.Normal * 0.02f;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, placement.Normal);

        var visual = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
        visual.name = "Visual";
        visual.transform.SetParent(go.transform, false);
        visual.transform.localScale = new Vector3(0.12f, spikeHeight * 0.5f, 0.12f);
        visual.transform.localPosition = new Vector3(0f, spikeHeight * 0.5f, 0f);
        Object.Destroy(visual.GetComponent<Collider>());

        var renderer = visual.GetComponent<Renderer>();
        if (renderer != null)
        {
            var mat = new Material(Shader.Find("Standard") ?? Shader.Find("Diffuse"));
            mat.color = new Color(0.55f, 0.08f, 0.08f);
            renderer.material = mat;
        }

        var trigger = go.AddComponent<BoxCollider>();
        trigger.isTrigger = true;
        trigger.size = new Vector3(0.35f, 0.15f, 0.35f);
        trigger.center = new Vector3(0f, 0.05f, 0f);

        go.AddComponent<SpikeSurfaceMarker>();
    }
}

using SpikeBalanceMod.GameApi;
using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod.Player;

public sealed class SpikeGroundDetector
{
    private readonly float _checkDistance;
    private readonly float _sphereRadius;
    private readonly bool _requireNoHandGrip;

    public bool IsOnSpikeGround { get; private set; }

    public SpikeGroundDetector(float checkDistance, float sphereRadius, bool requireNoHandGrip)
    {
        _checkDistance = checkDistance;
        _sphereRadius = sphereRadius;
        _requireNoHandGrip = requireNoHandGrip;
    }

    public void Update(ENT_Player? player)
    {
        IsOnSpikeGround = false;
        if (player == null)
            return;

        if (!PlayerAccess.IsGrounded(player))
            return;

        if (_requireNoHandGrip && !player.AreHandsFree())
            return;

        var origin = player.transform.position + Vector3.up * 0.1f;
        if (Physics.SphereCast(
                origin,
                _sphereRadius,
                Vector3.down,
                out var hit,
                _checkDistance,
                ~0,
                QueryTriggerInteraction.Collide))
        {
            IsOnSpikeGround = hit.collider.GetComponentInParent<SpikeSurfaceMarker>() != null;
        }
    }
}

using SpikeBalanceMod.GameApi;
using UnityEngine;

namespace SpikeBalanceMod.Player;

public sealed class PlayerResourceController
{
    private readonly float _spikeDamagePerSecond;
    private readonly float _staminaRegenPerSecond;
    private readonly float _healthRegenDelay;
    private readonly float _healthRegenPerSecond;

    private float _timeOffSpikeGround;

    public PlayerResourceController(
        float spikeDamagePerSecond,
        float staminaRegenPerSecond,
        float healthRegenDelay,
        float healthRegenPerSecond)
    {
        _spikeDamagePerSecond = spikeDamagePerSecond;
        _staminaRegenPerSecond = staminaRegenPerSecond;
        _healthRegenDelay = healthRegenDelay;
        _healthRegenPerSecond = healthRegenPerSecond;
    }

    public void Tick(ENT_Player? player, bool isOnSpikeGround, float deltaTime)
    {
        if (player == null || deltaTime <= 0f)
            return;

        if (isOnSpikeGround)
        {
            _timeOffSpikeGround = 0f;
            if (_spikeDamagePerSecond > 0f)
                PlayerAccess.ApplyDamage(player, _spikeDamagePerSecond * deltaTime);

            if (_staminaRegenPerSecond > 0f)
                PlayerAccess.AddGripToAllHands(player, _staminaRegenPerSecond * deltaTime);
        }
        else
        {
            _timeOffSpikeGround += deltaTime;
            if (_timeOffSpikeGround >= _healthRegenDelay && _healthRegenPerSecond > 0f)
            {
                var health = PlayerAccess.GetHealth(player);
                var max = PlayerAccess.GetMaxHealth(player);
                if (health < max)
                    PlayerAccess.SetHealth(player, health + _healthRegenPerSecond * deltaTime);
            }
        }
    }
}

using SpikeBalanceMod.GameApi;
using UnityEngine;
using UnityEngine.UI;

namespace SpikeBalanceMod.UI;

public sealed class HealthBarUI
{
    private readonly bool _showWhenFull;
    private GameObject? _root;
    private Image? _fill;
    private Image? _background;

    public HealthBarUI(bool showWhenFull)
    {
        _showWhenFull = showWhenFull;
    }

    public void EnsureCreated()
    {
        if (_root != null)
            return;

        _root = new GameObject("SpikeBalanceMod_HealthBar");
        Object.DontDestroyOnLoad(_root);

        var canvas = _root.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 5000;
        _root.AddComponent<CanvasScaler>().uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        _root.AddComponent<GraphicRaycaster>();

        var panel = new GameObject("Panel");
        panel.transform.SetParent(_root.transform, false);
        var panelRect = panel.AddComponent<RectTransform>();
        panelRect.anchorMin = new Vector2(0.5f, 0f);
        panelRect.anchorMax = new Vector2(0.5f, 0f);
        panelRect.pivot = new Vector2(0.5f, 0f);
        panelRect.anchoredPosition = new Vector2(0f, 48f);
        panelRect.sizeDelta = new Vector2(280f, 22f);

        var bgGo = new GameObject("Background");
        bgGo.transform.SetParent(panel.transform, false);
        var bgRect = bgGo.AddComponent<RectTransform>();
        bgRect.anchorMin = Vector2.zero;
        bgRect.anchorMax = Vector2.one;
        bgRect.offsetMin = Vector2.zero;
        bgRect.offsetMax = Vector2.zero;
        _background = bgGo.AddComponent<Image>();
        _background.color = new Color(0.1f, 0.1f, 0.1f, 0.85f);

        var fillGo = new GameObject("Fill");
        fillGo.transform.SetParent(panel.transform, false);
        var fillRect = fillGo.AddComponent<RectTransform>();
        fillRect.anchorMin = Vector2.zero;
        fillRect.anchorMax = Vector2.one;
        fillRect.offsetMin = new Vector2(2f, 2f);
        fillRect.offsetMax = new Vector2(-2f, -2f);
        _fill = fillGo.AddComponent<Image>();
        _fill.color = new Color(0.85f, 0.15f, 0.15f, 1f);
        _fill.type = Image.Type.Filled;
        _fill.fillMethod = Image.FillMethod.Horizontal;
        _fill.fillOrigin = (int)Image.OriginHorizontal.Left;
    }

    public void Update(ENT_Player? player)
    {
        EnsureCreated();
        if (_root == null || _fill == null)
            return;

        if (player == null)
        {
            _root.SetActive(false);
            return;
        }

        var health = PlayerAccess.GetHealth(player);
        var max = Mathf.Max(0.01f, PlayerAccess.GetMaxHealth(player));
        var ratio = Mathf.Clamp01(health / max);

        var visible = _showWhenFull || ratio < 0.999f;
        _root.SetActive(visible);
        if (!visible)
            return;

        _fill.fillAmount = ratio;
    }

    public void Destroy()
    {
        if (_root != null)
            Object.Destroy(_root);
        _root = null;
        _fill = null;
        _background = null;
    }
}

using System.Collections;
using BepInEx.Configuration;
