        var spikeDamage = Config.Bind("Resources", "SpikeDamagePerSecond", 5f, "Health damage per second while on spike ground.");
        var staminaRegen = Config.Bind("Resources", "StaminaRegenPerSecOnSpikes", 0.12f, "Grip/stamina regen per second on spike ground (grip is 0-1).");
        var healthDelay = Config.Bind("Resources", "HealthRegenDelay", 1.5f, "Seconds off spike ground before health regen starts.");
        var healthRegen = Config.Bind("Resources", "HealthRegenPerSec", 3f, "Health regen per second after delay.");

        var groundDistance = Config.Bind("Ground", "CheckDistance", 0.6f, "Downward sphere cast distance for spike ground.");
        var sphereRadius = Config.Bind("Ground", "SphereRadius", 0.25f, "Sphere cast radius for spike ground.");
        var requireFreeHands = Config.Bind("Ground", "RequireNoHandGrip", false, "Only count spike ground when hands are not gripping.");

        var showHealthBar = Config.Bind("UI", "ShowHealthBar", true, "Show the health bar overlay.");
        var showWhenFull = Config.Bind("UI", "ShowWhenFull", true, "Keep health bar visible at full health.");

        _harmony = new Harmony(PluginGuid);
        _harmony.PatchAll();

        var go = new GameObject("SpikeBalanceMod_Runtime");
        DontDestroyOnLoad(go);
        _runtime = go.AddComponent<SpikeBalanceRuntime>();
        _runtime.Configure(
            Config,
            spikesEnabled.Value,
            minUpDot.Value,
            spacing.Value,
            maxSpikes.Value,
            spikeHeight.Value,
            scanDelay.Value,
            groundDistance.Value,
            sphereRadius.Value,
            requireFreeHands.Value,
            spikeDamage.Value,
            staminaRegen.Value,
            healthDelay.Value,
            healthRegen.Value,
            showHealthBar.Value,
            showWhenFull.Value);

        Log.LogInfo($"{PluginName} loaded.");
    }

    private void OnDestroy()
    {
        _harmony?.UnpatchSelf();
        if (_runtime != null)
            Destroy(_runtime.gameObject);
    }
}

