using System.Collections;
using SpikeBalanceMod.GameApi;
using SpikeBalanceMod.Player;
using SpikeBalanceMod.Spikes;
using SpikeBalanceMod.UI;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod;

/// <summary>Runtime behaviour for spike placement and resource balancing.</summary>
public sealed class SpikeBalanceRuntime : MonoBehaviour
{
    private static readonly float[] ScanRetryDelays = { 2f, 5f, 10f, 20f, 45f };

    private SpikePlacer _placer = null!;
    private SpikeGroundDetector _groundDetector = null!;
    private PlayerResourceController _resourceController = null!;
    private HealthBarUI _healthBar = null!;

    private bool _configured;
    private bool _spikesEnabled;
    private float _minUpDot;
    private float _spacing;
    private int _maxSpikes;
    private float _spikeHeight;
    private float _scanDelaySeconds;
    private bool _showHealthBar;
    private bool _showHealthWhenFull;

    private bool _playerSeen;
    private int _lastPlacementCount = -1;
    private Coroutine? _scanRoutine;

    public void Configure(
        bool spikesEnabled,
        float minUpDot,
        float spacing,
        int maxSpikes,
        float spikeHeight,
        float scanDelaySeconds,
        float checkDistance,
        float sphereRadius,
        bool requireNoHandGrip,
        float spikeDamagePerSecond,
        float staminaRegenPerSecond,
        float healthRegenDelay,
        float healthRegenPerSecond,
        bool showHealthBar,
        bool showHealthWhenFull)
    {
        _spikesEnabled = spikesEnabled;
        _minUpDot = minUpDot;
        _spacing = spacing;
        _maxSpikes = maxSpikes;
        _spikeHeight = spikeHeight;
        _scanDelaySeconds = scanDelaySeconds;
        _showHealthBar = showHealthBar;
        _showHealthWhenFull = showHealthWhenFull;

        _placer = new SpikePlacer();
        _groundDetector = new SpikeGroundDetector(checkDistance, sphereRadius, requireNoHandGrip);
        _resourceController = new PlayerResourceController(
            spikeDamagePerSecond,
            staminaRegenPerSecond,
            healthRegenDelay,
            healthRegenPerSecond);
        _healthBar = new HealthBarUI(showHealthWhenFull);
        _configured = true;
    }

    private void Start()
    {
        if (!_configured)
        {
            SpikeBalancePlugin.Log?.LogError("SpikeBalanceRuntime started without Configure().");
            return;
        }

        SceneManager.sceneLoaded += OnSceneLoaded;
        ScheduleScan("startup");
    }

    private void OnDestroy()
    {
        SceneManager.sceneLoaded -= OnSceneLoaded;
        if (_scanRoutine != null)
            StopCoroutine(_scanRoutine);
        _placer?.Clear();
        _healthBar?.Destroy();
    }

    private void OnSceneLoaded(Scene scene, LoadSceneMode mode) =>
        ScheduleScan($"scene:{scene.name}");

    private void ScheduleScan(string reason)
    {
        if (_scanRoutine != null)
            StopCoroutine(_scanRoutine);
        _scanRoutine = StartCoroutine(ScanWithRetries(reason));
    }

    private IEnumerator ScanWithRetries(string reason)
    {
        SpikeBalancePlugin.Log?.LogInfo($"Spike scan scheduled ({reason}).");

        if (_scanDelaySeconds > 0f)
            yield return new WaitForSeconds(_scanDelaySeconds);
        else
            yield return null;

        yield return RunScan(reason);

        foreach (var delay in ScanRetryDelays)
        {
            yield return new WaitForSeconds(delay);
            if (!_spikesEnabled)
                yield break;

            var player = PlayerAccess.FindPlayer();
            if (player == null)
                continue;

            yield return RunScan($"{reason}+retry@{delay}s");
            if (_lastPlacementCount > 0)
                yield break;
        }
    }

    private IEnumerator RunScan(string reason)
    {
        if (!_spikesEnabled)
        {
            _placer.Clear();
            yield break;
        }

        var player = PlayerAccess.FindPlayer();
        var sceneName = SceneManager.GetActiveScene().name;
        var scanner = new SpikeSurfaceScanner(_minUpDot, _spacing, _maxSpikes);
        var placements = scanner.ScanScene(out var colliderCount, out var rendererCount);
        var count = _placer.PlaceAll(placements, _spikeHeight);
        _lastPlacementCount = count;

        SpikeBalancePlugin.Log?.LogInfo(
            $"Spike scan ({reason}) scene={sceneName} player={(player != null)} " +
            $"colliders={colliderCount} renderers={rendererCount} placements={placements.Count} placed={count}");
    }

    private void Update()
    {
        var player = PlayerAccess.FindPlayer();
        if (player != null && !_playerSeen)
        {
            _playerSeen = true;
            if (_showHealthBar)
                _healthBar.EnsureCreated();
            if (_lastPlacementCount <= 0)
                ScheduleScan("player_spawned");
        }

        if (_showHealthBar)
            _healthBar.Update(player);

        // Periodic re-scan for procedural rooms that spawn without sceneLoaded.
        if (_spikesEnabled && player != null && _lastPlacementCount <= 0 && Time.frameCount % 600 == 0)
            ScheduleScan("periodic");
    }

    private void FixedUpdate()
    {
        var player = PlayerAccess.FindPlayer();
        _groundDetector.Update(player);
        _resourceController.Tick(player, _groundDetector.IsOnSpikeGround, Time.fixedDeltaTime);
    }
}

using System.Collections.Generic;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public readonly struct SpikePlacement
{
    public Vector3 Position { get; }
    public Vector3 Normal { get; }

    public SpikePlacement(Vector3 position, Vector3 normal)
    {
        Position = position;
        Normal = normal;
    }
}

public sealed class SpikeSurfaceScanner
{
    private readonly float _minUpDot;
    private readonly float _spacing;
    private readonly int _maxSpikes;
    private readonly HashSet<long> _occupiedCells = new();

    public SpikeSurfaceScanner(float minUpDot, float spacing, int maxSpikes)
    {
        _minUpDot = minUpDot;
        _spacing = Mathf.Max(0.25f, spacing);
        _maxSpikes = maxSpikes;
    }

    public List<SpikePlacement> ScanScene(out int colliderCount, out int rendererCount)
    {
        _occupiedCells.Clear();
        var results = new List<SpikePlacement>(_maxSpikes);

        var colliders = Resources.FindObjectsOfTypeAll<Collider>();
        colliderCount = 0;
        foreach (var col in colliders)
        {
            if (col == null || !col.enabled || col.isTrigger)
                continue;
            if (!col.gameObject.scene.IsValid())
                continue;
            colliderCount++;

            if (results.Count >= _maxSpikes)
                break;
            if (!ShouldScan(col))
                continue;

            switch (col)
            {
                case MeshCollider meshCol when meshCol.sharedMesh != null:
                    ScanMesh(meshCol, results);
                    break;
                case BoxCollider boxCol:
                    ScanBox(boxCol, results);
                    break;
                case TerrainCollider terrainCol when terrainCol.terrainData != null:
                    ScanTerrain(terrainCol, results);
                    break;
            }
        }

        var renderers = Resources.FindObjectsOfTypeAll<MeshRenderer>();
        rendererCount = 0;
        if (results.Count < _maxSpikes / 4)
        {
            foreach (var renderer in renderers)
            {
                if (results.Count >= _maxSpikes)
                    break;
                if (renderer == null || !renderer.enabled || !renderer.gameObject.activeInHierarchy)
                    continue;
                if (!renderer.gameObject.scene.IsValid())
                    continue;
                rendererCount++;
                ScanRendererBounds(renderer, results);
            }
        }
        else
        {
            rendererCount = renderers.Length;
        }

        return results;
    }

    private bool ShouldScan(Collider col)
    {
        if (col.GetComponentInParent<ENT_Player>() != null)
            return false;
        if (col.GetComponentInParent<SpikeSurfaceMarker>() != null)
            return false;
        if (col.GetComponentInParent<CL_Handhold>() != null)
            return false;

        var name = col.gameObject.name;
        if (name.Contains("Player") || name.Contains("Hand") || name.Contains("UI"))
            return false;

        return true;
    }

    private bool ShouldScanRenderer(Renderer renderer)
    {
        if (renderer.GetComponentInParent<ENT_Player>() != null)
            return false;
        if (renderer.GetComponentInParent<SpikeSurfaceMarker>() != null)
            return false;
        if (renderer.GetComponentInParent<CL_Handhold>() != null)
            return false;

        var name = renderer.gameObject.name;
        if (name.Contains("Player") || name.Contains("Hand") || name.Contains("UI"))
            return false;

        return true;
    }

    private void ScanMesh(MeshCollider meshCol, List<SpikePlacement> results)
    {
        var mesh = meshCol.sharedMesh;
        var tr = meshCol.transform;
        var verts = mesh.vertices;
        var tris = mesh.triangles;
        if (tris == null || tris.Length < 3)
        {
            ScanBoundsTop(meshCol.bounds, Vector3.up, results);
            return;
        }

        for (var i = 0; i < tris.Length && results.Count < _maxSpikes; i += 3)
        {
            var w0 = tr.TransformPoint(verts[tris[i]]);
            var w1 = tr.TransformPoint(verts[tris[i + 1]]);
            var w2 = tr.TransformPoint(verts[tris[i + 2]]);
            var normal = Vector3.Cross(w1 - w0, w2 - w0);
            if (normal.sqrMagnitude < 1e-6f)
                continue;
            normal.Normalize();
            if (normal.y < _minUpDot)
                continue;

            var center = (w0 + w1 + w2) / 3f;
            TryAdd(center, normal, results);
        }
    }

    private void ScanBox(BoxCollider box, List<SpikePlacement> results)
    {
        var tr = box.transform;
        var c = box.center;
        var e = box.size * 0.5f;
        var worldNormal = tr.TransformDirection(Vector3.up).normalized;
        if (worldNormal.y < _minUpDot)
            return;

        var steps = Mathf.Max(1, Mathf.FloorToInt(Mathf.Max(box.size.x, box.size.z) / _spacing));
        for (var x = 0; x <= steps && results.Count < _maxSpikes; x++)
        {
            for (var z = 0; z <= steps && results.Count < _maxSpikes; z++)
            {
                var lx = Mathf.Lerp(-e.x, e.x, steps == 0 ? 0.5f : (float)x / steps);
                var lz = Mathf.Lerp(-e.z, e.z, steps == 0 ? 0.5f : (float)z / steps);
                var local = c + new Vector3(lx, e.y, lz);
                var world = tr.TransformPoint(local);
                TryAdd(world, worldNormal, results);
            }
        }
    }

    private void ScanTerrain(TerrainCollider terrainCol, List<SpikePlacement> results)
    {
        var terrain = terrainCol.terrainData;
        var tr = terrainCol.transform;
        var size = terrain.size;
        var res = terrain.heightmapResolution;
        var step = Mathf.Max(1, Mathf.RoundToInt(_spacing / (size.x / res)));

        for (var y = 0; y < res && results.Count < _maxSpikes; y += step)
        {
            for (var x = 0; x < res && results.Count < _maxSpikes; x += step)
            {
                var nx = (float)x / (res - 1);
                var ny = (float)y / (res - 1);
                var normal = terrain.GetInterpolatedNormal(nx, ny);
                var worldNormal = tr.TransformDirection(normal).normalized;
                if (worldNormal.y < _minUpDot)
                    continue;

                var height = terrain.GetInterpolatedHeight(nx, ny);
                var world = tr.TransformPoint(new Vector3(nx * size.x, height, ny * size.z));
                TryAdd(world, worldNormal, results);
            }
        }
    }

    private void ScanRendererBounds(MeshRenderer renderer, List<SpikePlacement> results)
    {
        if (!ShouldScanRenderer(renderer))
            return;
        ScanBoundsTop(renderer.bounds, Vector3.up, results);
    }

    private void ScanBoundsTop(Bounds bounds, Vector3 normal, List<SpikePlacement> results)
    {
        if (normal.y < _minUpDot)
            return;

        var min = bounds.min;
        var max = bounds.max;
        var y = max.y;
        var stepsX = Mathf.Max(1, Mathf.FloorToInt((max.x - min.x) / _spacing));
        var stepsZ = Mathf.Max(1, Mathf.FloorToInt((max.z - min.z) / _spacing));

        for (var ix = 0; ix <= stepsX && results.Count < _maxSpikes; ix++)
        {
            for (var iz = 0; iz <= stepsZ && results.Count < _maxSpikes; iz++)
            {
                var x = Mathf.Lerp(min.x, max.x, stepsX == 0 ? 0.5f : (float)ix / stepsX);
                var z = Mathf.Lerp(min.z, max.z, stepsZ == 0 ? 0.5f : (float)iz / stepsZ);
                TryAdd(new Vector3(x, y, z), normal, results);
            }
        }
    }

    private void TryAdd(Vector3 position, Vector3 normal, List<SpikePlacement> results)
    {
        if (!TryReserveCell(position))
            return;
        results.Add(new SpikePlacement(position, normal));
    }

    private bool TryReserveCell(Vector3 position)
    {
        var cell = new Vector3Int(
            Mathf.FloorToInt(position.x / _spacing),
            Mathf.FloorToInt(position.y / _spacing),
            Mathf.FloorToInt(position.z / _spacing));
        var key = ((long)cell.x << 42) ^ ((long)cell.y << 21) ^ (uint)cell.z;
        return _occupiedCells.Add(key);
    }
}

