using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.GameApi;

/// <summary>Detects whether the player is in an active campaign/run vs menus.</summary>
public static class RunState
{
    private static readonly AccessTools.FieldRef<CL_GameManager, bool> RunHasEnded =
        AccessTools.FieldRefAccess<CL_GameManager, bool>("runHasEnded");

    public static CL_GameManager? FindGameManager() =>
        Object.FindObjectOfType(typeof(CL_GameManager)) as CL_GameManager;

    /// <summary>True when a run is active (not main menu / pause / between runs).</summary>
    public static bool IsInActiveRun()
    {
        var gm = FindGameManager();
        if (gm == null)
            return false;

        if (gm.IsLoading())
            return false;

        if (!gm.IsInGame())
            return false;

        if (RunHasEnded(gm))
            return false;

        var player = gm.localPlayer;
        if (player == null)
            return false;

        var go = ((MonoBehaviour)(object)player).gameObject;
        return go.activeInHierarchy;
    }

    public static ENT_Player? GetRunPlayer()
    {
        if (!IsInActiveRun())
            return null;
        return FindGameManager()?.localPlayer;
    }
}

using System.Collections;
using SpikeBalanceMod.GameApi;
using SpikeBalanceMod.Player;
using SpikeBalanceMod.Spikes;
using SpikeBalanceMod.UI;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod;

/// <summary>Runtime behaviour for spike placement and resource balancing.</summary>
public sealed class SpikeBalanceRuntime : MonoBehaviour
{
    private static readonly float[] ScanRetryDelays = { 3f, 8f, 15f, 25f };

    private SpikePlacer _placer = null!;
    private SpikeGroundDetector _groundDetector = null!;
    private PlayerResourceController _resourceController = null!;
    private HealthBarUI _healthBar = null!;

    private bool _configured;
    private bool _spikesEnabled;
    private float _minUpDot;
    private float _spacing;
    private int _maxSpikes;
    private float _spikeHeight;
    private float _scanDelaySeconds;
    private bool _showHealthBar;
    private bool _showHealthWhenFull;

    private bool _wasInRun;
    private int _lastPlacementCount = -1;
    private Coroutine? _scanRoutine;
    private float _nextPeriodicScan;

    public void Configure(
        bool spikesEnabled,
        float minUpDot,
        float spacing,
        int maxSpikes,
        float spikeHeight,
        float scanDelaySeconds,
        float checkDistance,
        float sphereRadius,
        bool requireNoHandGrip,
        float spikeDamagePerSecond,
        float staminaRegenPerSecond,
        float healthRegenDelay,
        float healthRegenPerSecond,
        bool showHealthBar,
        bool showHealthWhenFull)
    {
        _spikesEnabled = spikesEnabled;
        _minUpDot = minUpDot;
        _spacing = spacing;
        _maxSpikes = maxSpikes;
        _spikeHeight = spikeHeight;
        _scanDelaySeconds = scanDelaySeconds;
        _showHealthBar = showHealthBar;
        _showHealthWhenFull = showHealthWhenFull;

        _placer = new SpikePlacer();
        _groundDetector = new SpikeGroundDetector(checkDistance, sphereRadius, requireNoHandGrip);
        _resourceController = new PlayerResourceController(
            spikeDamagePerSecond,
            staminaRegenPerSecond,
            healthRegenDelay,
            healthRegenPerSecond);
        _healthBar = new HealthBarUI(showHealthWhenFull);
        _configured = true;
    }

    private void Start()
    {
        if (!_configured)
        {
            SpikeBalancePlugin.Log?.LogError("SpikeBalanceRuntime started without Configure().");
            return;
        }

        SceneManager.sceneLoaded += OnSceneLoaded;
    }

    private void OnDestroy()
    {
        SceneManager.sceneLoaded -= OnSceneLoaded;
        StopScanRoutine();
        _placer?.Clear();
        _healthBar?.Destroy();
    }

    private void OnSceneLoaded(Scene scene, LoadSceneMode mode)
    {
        if (RunState.IsInActiveRun())
            ScheduleScan($"scene:{scene.name}");
    }

    private void OnRunStarted()
    {
        SpikeBalancePlugin.Log?.LogInfo("Run started — enabling spike balance mod gameplay.");
        _lastPlacementCount = -1;
        _nextPeriodicScan = Time.unscaledTime + 5f;
        ScheduleScan("run_started");
    }

    private void OnRunEnded()
    {
        SpikeBalancePlugin.Log?.LogInfo("Run ended — hiding UI and clearing spikes.");
        StopScanRoutine();
        _placer.Clear();
        _lastPlacementCount = -1;
        _healthBar.Hide();
    }

    private void StopScanRoutine()
    {
        if (_scanRoutine == null)
            return;
        StopCoroutine(_scanRoutine);
        _scanRoutine = null;
    }

    private void ScheduleScan(string reason)
    {
        if (!RunState.IsInActiveRun())
            return;

        StopScanRoutine();
        _scanRoutine = StartCoroutine(ScanWithRetries(reason));
    }

    private IEnumerator ScanWithRetries(string reason)
    {
        SpikeBalancePlugin.Log?.LogInfo($"Spike scan scheduled ({reason}).");

        if (_scanDelaySeconds > 0f)
            yield return new WaitForSeconds(_scanDelaySeconds);
        else
            yield return null;

        if (!RunState.IsInActiveRun())
            yield break;

        yield return RunScan(reason);

        foreach (var delay in ScanRetryDelays)
        {
            yield return new WaitForSeconds(delay);
            if (!_spikesEnabled || !RunState.IsInActiveRun())
                yield break;

            yield return RunScan($"{reason}+retry@{delay}s");
            if (_lastPlacementCount > 0)
                yield break;
        }
    }

    private IEnumerator RunScan(string reason)
    {
        if (!_spikesEnabled || !RunState.IsInActiveRun())
        {
            yield break;
        }

        var player = RunState.GetRunPlayer();
        var sceneName = SceneManager.GetActiveScene().name;
        var scanner = new SpikeSurfaceScanner(_minUpDot, _spacing, _maxSpikes);
        var placements = scanner.ScanScene(out var colliderCount, out var rendererCount);
        var count = _placer.PlaceAll(placements, _spikeHeight);
        _lastPlacementCount = count;

        SpikeBalancePlugin.Log?.LogInfo(
            $"Spike scan ({reason}) scene={sceneName} player={(player != null)} " +
            $"colliders={colliderCount} renderers={rendererCount} placements={placements.Count} placed={count}");
    }

    private void Update()
    {
        var inRun = RunState.IsInActiveRun();

        if (!inRun)
        {
            if (_wasInRun)
                OnRunEnded();
            _wasInRun = false;
            return;
        }

        if (!_wasInRun)
            OnRunStarted();
        _wasInRun = true;

        var player = RunState.GetRunPlayer();

        if (_showHealthBar)
            _healthBar.Update(player);

        if (_spikesEnabled && _lastPlacementCount <= 0 && Time.unscaledTime >= _nextPeriodicScan)
        {
            _nextPeriodicScan = Time.unscaledTime + 20f;
            ScheduleScan("periodic");
        }
    }

    private void FixedUpdate()
    {
        if (!RunState.IsInActiveRun())
            return;

        var player = RunState.GetRunPlayer();
        _groundDetector.Update(player);
        _resourceController.Tick(player, _groundDetector.IsOnSpikeGround, Time.fixedDeltaTime);
    }
}

