using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.GameApi;

/// <summary>Detects whether the player is in an active campaign/run vs menus.</summary>
public static class RunState
{
    private static readonly AccessTools.FieldRef<CL_GameManager, bool> RunHasEnded =
        AccessTools.FieldRefAccess<CL_GameManager, bool>("runHasEnded");

    private static readonly AccessTools.FieldRef<CL_GameManager, ENT_Player> LocalPlayer =
        AccessTools.FieldRefAccess<CL_GameManager, ENT_Player>("localPlayer");

    private static readonly string[] MenuSceneHints =
    {
        "MainMenu", "Main", "Menu", "Title", "Boot", "Intro", "Startup", "Lobby"
    };

    public static CL_GameManager? FindGameManager() =>
        Object.FindObjectOfType(typeof(CL_GameManager)) as CL_GameManager;

    public static ENT_Player? ResolvePlayer()
    {
        var gm = FindGameManager();
        if (gm != null)
        {
            var local = LocalPlayer(gm);
            if (IsPlayable(local))
                return local;
        }

        return PlayerAccess.FindPlayer();
    }

    /// <summary>True when the local player is actively in a climb/run.</summary>
    public static bool IsInActiveRun()
    {
        var player = ResolvePlayer();
        if (!IsPlayable(player))
            return false;

        var gm = FindGameManager();
        if (gm != null && RunHasEnded(gm))
            return false;

        var sceneName = ((MonoBehaviour)(object)player!).gameObject.scene.name;
        if (IsMenuScene(sceneName))
            return false;

        // Game API when it agrees we're in-game (optional boost, not required).
        if (gm != null && CL_GameManager.IsInGame())
            return true;

        // Fallback: controllable player with health in a non-menu scene.
        return PlayerAccess.GetMaxHealth(player!) > 0f;
    }

    public static ENT_Player? GetRunPlayer()
    {
        if (!IsInActiveRun())
            return null;
        return ResolvePlayer();
    }

    private static bool IsPlayable(ENT_Player? player)
    {
        if (player == null)
            return false;
        var go = ((MonoBehaviour)(object)player).gameObject;
        return go.activeInHierarchy && PlayerAccess.GetMaxHealth(player) > 0f;
    }

    private static bool IsMenuScene(string sceneName)
    {
        if (string.IsNullOrEmpty(sceneName))
            return false;
        foreach (var hint in MenuSceneHints)
        {
            if (sceneName.IndexOf(hint, System.StringComparison.OrdinalIgnoreCase) >= 0)
                return true;
        }
        return false;
    }
}

using SpikeBalanceMod.GameApi;
