namespace SpikeBalanceMod.UI;

public sealed class HealthBarUI
{
    private const float TopMargin = 8f;

    private readonly bool _showWhenFull;
    private GameObject? _root;
    private Image? _fill;
    private Text? _healthText;

    public HealthBarUI(bool showWhenFull)
    {
        _showWhenFull = showWhenFull;
    }

    public void EnsureCreated()
    {
        if (_root != null)
            return;

        _root = new GameObject("SpikeBalanceMod_HealthBar");
        Object.DontDestroyOnLoad(_root);

        var canvas = _root.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 8000;
        var scaler = _root.AddComponent<CanvasScaler>();
        scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        scaler.referenceResolution = new Vector2(1920, 1080);
        _root.AddComponent<GraphicRaycaster>();

        var panel = new GameObject("Panel");
        panel.transform.SetParent(_root.transform, false);
        var panelRect = panel.AddComponent<RectTransform>();
        panelRect.anchorMin = new Vector2(0.5f, 1f);
        panelRect.anchorMax = new Vector2(0.5f, 1f);
        panelRect.pivot = new Vector2(0.5f, 1f);
        panelRect.anchoredPosition = new Vector2(0f, -TopMargin);
        panelRect.sizeDelta = new Vector2(300f, 32f);

        var bgGo = new GameObject("Background");
        bgGo.transform.SetParent(panel.transform, false);
        var bgRect = bgGo.AddComponent<RectTransform>();
        bgRect.anchorMin = Vector2.zero;
        bgRect.anchorMax = Vector2.one;
        bgRect.offsetMin = Vector2.zero;
        bgRect.offsetMax = Vector2.zero;
        var background = bgGo.AddComponent<Image>();
        background.sprite = UiSpriteHelper.GetWhiteSprite();
        background.type = Image.Type.Sliced;
        background.color = new Color(0.08f, 0.08f, 0.08f, 0.9f);

        var fillGo = new GameObject("Fill");
        fillGo.transform.SetParent(panel.transform, false);
        var fillRect = fillGo.AddComponent<RectTransform>();
        fillRect.anchorMin = Vector2.zero;
        fillRect.anchorMax = Vector2.one;
        fillRect.offsetMin = new Vector2(2f, 2f);
        fillRect.offsetMax = new Vector2(-2f, -2f);
        _fill = fillGo.AddComponent<Image>();
        _fill.sprite = UiSpriteHelper.GetWhiteSprite();
        _fill.color = new Color(0.85f, 0.15f, 0.15f, 1f);
        _fill.type = Image.Type.Filled;
        _fill.fillMethod = Image.FillMethod.Horizontal;
        _fill.fillOrigin = (int)Image.OriginHorizontal.Left;

        var textGo = new GameObject("HealthText");
        textGo.transform.SetParent(panel.transform, false);
        var textRect = textGo.AddComponent<RectTransform>();
        textRect.anchorMin = Vector2.zero;
        textRect.anchorMax = Vector2.one;
        textRect.offsetMin = Vector2.zero;
        textRect.offsetMax = Vector2.zero;
        _healthText = textGo.AddComponent<Text>();
        _healthText.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf")
            ?? Resources.GetBuiltinResource<Font>("Arial.ttf");
        _healthText.alignment = TextAnchor.MiddleCenter;
        _healthText.fontSize = 18;
        _healthText.fontStyle = FontStyle.Bold;
        _healthText.color = Color.white;
        _healthText.raycastTarget = false;

        _root.SetActive(false);
    }

    public void Update(ENT_Player? player)
    {
        if (player == null)
        {
            Hide();
            return;
        }

        EnsureCreated();
        if (_root == null || _fill == null || _healthText == null)
            return;

        var health = PlayerAccess.GetHealth(player);
        var max = Mathf.Max(0.01f, PlayerAccess.GetMaxHealth(player));
        var ratio = Mathf.Clamp01(health / max);

        if (!_showWhenFull && ratio >= 0.999f)
        {
            Hide();
            return;
        }

        _root.SetActive(true);
        _fill.color = new Color(0.85f, 0.15f, 0.15f, 1f);
        _fill.fillAmount = ratio;
        _healthText.text = $"{Mathf.CeilToInt(health)}";
    }

    public void Hide()
    {
        if (_root != null)
            _root.SetActive(false);
    }

    public void Destroy()
    {
        if (_root != null)
            Object.Destroy(_root);
        _root = null;
        _fill = null;
        _healthText = null;
    }
}

using System.Collections;
using System.Collections.Generic;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public readonly struct SpikePlacement
{
    public Vector3 Position { get; }
    public Vector3 Normal { get; }

    public SpikePlacement(Vector3 position, Vector3 normal)
    {
        Position = position;
        Normal = normal;
    }
}

public sealed class SpikeSurfaceScanner
{
    private static readonly FieldRef<HandholdManager, IList> HandholdsList =
        AccessTools.FieldRefAccess<HandholdManager, IList>("handholds");

    private readonly float _minUpDot;
    private readonly float _spacing;
    private readonly int _maxSpikes;
    private readonly HashSet<long> _occupiedCells = new();

    public SpikeSurfaceScanner(float minUpDot, float spacing, int maxSpikes)
    {
        _minUpDot = minUpDot;
        _spacing = Mathf.Max(0.25f, spacing);
        _maxSpikes = maxSpikes;
    }

    public List<SpikePlacement> ScanScene(ENT_Player? player, out int colliderCount, out int handholdCount)
    {
        _occupiedCells.Clear();
        var results = new List<SpikePlacement>(_maxSpikes);

        handholdCount = ScanHandholds(results);
        if (player != null)
            ScanAroundPlayer(player, results);

        colliderCount = ScanCollidersAndRenderers(results);

        return results;
    }

    private int ScanHandholds(List<SpikePlacement> results)
    {
        var count = 0;
        var seen = new HashSet<int>();

        void TryHandhold(CL_Handhold? hh)
        {
            if (hh == null || results.Count >= _maxSpikes)
                return;
            var id = ((MonoBehaviour)(object)hh).GetInstanceID();
            if (!seen.Add(id))
                return;

            var tr = ((MonoBehaviour)(object)hh).transform;
            if (!tr.gameObject.activeInHierarchy)
                return;

            var normal = tr.up.normalized;
            if (normal.y < _minUpDot)
                normal = Vector3.up;
            if (normal.y < _minUpDot)
                return;

            TryAdd(tr.position, normal, results);
            count++;
        }

        var manager = Object.FindObjectOfType(typeof(HandholdManager)) as HandholdManager;
        if (manager != null)
        {
            var list = HandholdsList(manager);
            if (list != null)
            {
                foreach (var item in list)
                    TryHandhold(item as CL_Handhold);
            }
        }

        foreach (var hh in Resources.FindObjectsOfTypeAll<CL_Handhold>())
            TryHandhold(hh);

        return count;
    }

    private void ScanAroundPlayer(ENT_Player player, List<SpikePlacement> results)
    {
        var origin = ((MonoBehaviour)(object)player).transform.position;
        var radius = 40f;
        var steps = Mathf.CeilToInt(radius * 2f / _spacing);

        for (var x = 0; x <= steps && results.Count < _maxSpikes; x++)
        {
            for (var z = 0; z <= steps && results.Count < _maxSpikes; z++)
            {
                var px = origin.x - radius + (radius * 2f) * x / Mathf.Max(1, steps);
                var pz = origin.z - radius + (radius * 2f) * z / Mathf.Max(1, steps);
                var rayOrigin = new Vector3(px, origin.y + 25f, pz);

                if (!Physics.Raycast(rayOrigin, Vector3.down, out var hit, 60f, ~0, QueryTriggerInteraction.Ignore))
                    continue;

                if (hit.collider.GetComponentInParent<ENT_Player>() != null)
                    continue;
                if (hit.collider.GetComponentInParent<SpikeSurfaceMarker>() != null)
                    continue;

                var normal = hit.normal;
                if (normal.y < _minUpDot)
                    continue;

                TryAdd(hit.point, normal, results);
            }
        }
    }

    private int ScanCollidersAndRenderers(List<SpikePlacement> results)
    {
        var colliderCount = 0;
        foreach (var col in Resources.FindObjectsOfTypeAll<Collider>())
        {
            if (col == null || !col.enabled || col.isTrigger)
                continue;
            if (!col.gameObject.activeInHierarchy)
                continue;
            colliderCount++;

            if (results.Count >= _maxSpikes)
                break;
            if (!ShouldScan(col))
                continue;

            switch (col)
            {
                case MeshCollider meshCol when meshCol.sharedMesh != null:
                    ScanMesh(meshCol, results);
                    break;
                case BoxCollider boxCol:
                    ScanBox(boxCol, results);
                    break;
                case TerrainCollider terrainCol when terrainCol.terrainData != null:
                    ScanTerrain(terrainCol, results);
                    break;
            }
        }

        if (results.Count < _maxSpikes / 3)
        {
            foreach (var renderer in Resources.FindObjectsOfTypeAll<MeshRenderer>())
            {
                if (results.Count >= _maxSpikes)
                    break;
                if (renderer == null || !renderer.enabled || !renderer.gameObject.activeInHierarchy)
                    continue;
                if (!ShouldScanRenderer(renderer))
                    continue;
                ScanBoundsTop(renderer.bounds, Vector3.up, results);
            }
        }

        return colliderCount;
    }

    private bool ShouldScan(Collider col)
    {
        if (col.GetComponentInParent<ENT_Player>() != null)
            return false;
        if (col.GetComponentInParent<SpikeSurfaceMarker>() != null)
            return false;

        var name = col.gameObject.name;
        if (name.Contains("Player") || name.Contains("Hand") || name.Contains("UI"))
            return false;

        return true;
    }

    private bool ShouldScanRenderer(Renderer renderer)
    {
        if (renderer.GetComponentInParent<ENT_Player>() != null)
            return false;
        if (renderer.GetComponentInParent<SpikeSurfaceMarker>() != null)
            return false;

        var name = renderer.gameObject.name;
        if (name.Contains("Player") || name.Contains("Hand") || name.Contains("UI"))
            return false;

        return true;
    }

    private void ScanMesh(MeshCollider meshCol, List<SpikePlacement> results)
    {
        var mesh = meshCol.sharedMesh;
        var tr = meshCol.transform;
        var verts = mesh.vertices;
        var tris = mesh.triangles;
        if (tris == null || tris.Length < 3)
        {
            ScanBoundsTop(meshCol.bounds, Vector3.up, results);
            return;
        }

        var step = Mathf.Max(3, Mathf.FloorToInt(tris.Length / 3000f) * 3);
        for (var i = 0; i < tris.Length && results.Count < _maxSpikes; i += step)
        {
            var w0 = tr.TransformPoint(verts[tris[i]]);
            var w1 = tr.TransformPoint(verts[tris[i + 1]]);
            var w2 = tr.TransformPoint(verts[tris[i + 2]]);
            var normal = Vector3.Cross(w1 - w0, w2 - w0);
            if (normal.sqrMagnitude < 1e-6f)
                continue;
            normal.Normalize();
            if (normal.y < _minUpDot)
                continue;

            TryAdd((w0 + w1 + w2) / 3f, normal, results);
        }
    }

    private void ScanBox(BoxCollider box, List<SpikePlacement> results)
    {
        var tr = box.transform;
        var c = box.center;
        var e = box.size * 0.5f;
        var worldNormal = tr.TransformDirection(Vector3.up).normalized;
        if (worldNormal.y < _minUpDot)
            return;

        var steps = Mathf.Max(1, Mathf.FloorToInt(Mathf.Max(box.size.x, box.size.z) / _spacing));
        for (var x = 0; x <= steps && results.Count < _maxSpikes; x++)
        {
            for (var z = 0; z <= steps && results.Count < _maxSpikes; z++)
            {
                var lx = Mathf.Lerp(-e.x, e.x, steps == 0 ? 0.5f : (float)x / steps);
                var lz = Mathf.Lerp(-e.z, e.z, steps == 0 ? 0.5f : (float)z / steps);
                TryAdd(tr.TransformPoint(c + new Vector3(lx, e.y, lz)), worldNormal, results);
            }
        }
    }

    private void ScanTerrain(TerrainCollider terrainCol, List<SpikePlacement> results)
    {
        var terrain = terrainCol.terrainData;
        var tr = terrainCol.transform;
        var size = terrain.size;
        var res = terrain.heightmapResolution;
        var step = Mathf.Max(1, Mathf.RoundToInt(_spacing / (size.x / res)));

        for (var y = 0; y < res && results.Count < _maxSpikes; y += step)
        {
            for (var x = 0; x < res && results.Count < _maxSpikes; x += step)
            {
                var nx = (float)x / (res - 1);
                var ny = (float)y / (res - 1);
                var worldNormal = tr.TransformDirection(terrain.GetInterpolatedNormal(nx, ny)).normalized;
                if (worldNormal.y < _minUpDot)
                    continue;

                var height = terrain.GetInterpolatedHeight(nx, ny);
                TryAdd(tr.TransformPoint(new Vector3(nx * size.x, height, ny * size.z)), worldNormal, results);
            }
        }
    }

    private void ScanBoundsTop(Bounds bounds, Vector3 normal, List<SpikePlacement> results)
    {
        if (normal.y < _minUpDot || bounds.size.sqrMagnitude < 0.01f)
            return;

        var min = bounds.min;
        var max = bounds.max;
        var y = max.y;
        var stepsX = Mathf.Max(1, Mathf.FloorToInt((max.x - min.x) / _spacing));
        var stepsZ = Mathf.Max(1, Mathf.FloorToInt((max.z - min.z) / _spacing));

        for (var ix = 0; ix <= stepsX && results.Count < _maxSpikes; ix++)
        {
            for (var iz = 0; iz <= stepsZ && results.Count < _maxSpikes; iz++)
            {
                var x = Mathf.Lerp(min.x, max.x, stepsX == 0 ? 0.5f : (float)ix / stepsX);
                var z = Mathf.Lerp(min.z, max.z, stepsZ == 0 ? 0.5f : (float)iz / stepsZ);
                TryAdd(new Vector3(x, y, z), normal, results);
            }
        }
    }

    private void TryAdd(Vector3 position, Vector3 normal, List<SpikePlacement> results)
    {
        if (!TryReserveCell(position))
            return;
        results.Add(new SpikePlacement(position, normal));
    }

    private bool TryReserveCell(Vector3 position)
    {
        var cell = new Vector3Int(
            Mathf.FloorToInt(position.x / _spacing),
            Mathf.FloorToInt(position.y / _spacing),
            Mathf.FloorToInt(position.z / _spacing));
        var key = ((long)cell.x << 42) ^ ((long)cell.y << 21) ^ (uint)cell.z;
        return _occupiedCells.Add(key);
    }
}

