using HarmonyLib;
using SpikeBalanceMod.GameApi;

namespace SpikeBalanceMod.Patches;

[HarmonyPatch(typeof(ENT_Player), nameof(ENT_Player.Start))]
internal static class PlayerStartPatch
{
    private static void Postfix(ENT_Player __instance)
    {
        SpikeBalancePlugin.NotifyPlayerStarted(__instance);
    }
}

using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.GameApi;

/// <summary>Detects whether the player is in an active campaign/run vs menus.</summary>
public static class RunState
{
    private static readonly AccessTools.FieldRef<CL_GameManager, bool> RunHasEnded =
        AccessTools.FieldRefAccess<CL_GameManager, bool>("runHasEnded");

    private static readonly AccessTools.FieldRef<CL_GameManager, ENT_Player> LocalPlayer =
        AccessTools.FieldRefAccess<CL_GameManager, ENT_Player>("localPlayer");

    /// <summary>Scene name substrings that indicate menus only (avoid short tokens like "Main").</summary>
    private static readonly string[] MenuSceneHints =
    {
        "MainMenu", "TitleScreen", "Title", "Boot", "Intro", "Startup", "Lobby", "Credits"
    };

    public static CL_GameManager? FindGameManager() =>
        Object.FindObjectOfType(typeof(CL_GameManager)) as CL_GameManager;

    public static ENT_Player? ResolvePlayer()
    {
        var gm = FindGameManager();
        if (gm != null)
        {
            var local = LocalPlayer(gm);
            if (local != null && IsActiveInLoadedScene(local))
                return local;
        }

        return PlayerAccess.FindPlayer();
    }

    public static bool IsInActiveRun()
    {
        var player = ResolvePlayer();
        if (player == null)
            return false;

        if (!IsActiveInLoadedScene(player))
            return false;

        var sceneName = ((MonoBehaviour)(object)player).gameObject.scene.name;
        if (IsMenuScene(sceneName))
            return false;

        var gm = FindGameManager();
        if (gm != null && RunHasEnded(gm))
            return false;

        return true;
    }

    public static ENT_Player? GetRunPlayer() => IsInActiveRun() ? ResolvePlayer() : null;

    private static bool IsActiveInLoadedScene(ENT_Player player)
    {
        var go = ((MonoBehaviour)(object)player).gameObject;
        return go.activeInHierarchy && go.scene.IsValid() && go.scene.isLoaded;
    }

    private static bool IsMenuScene(string sceneName)
    {
        if (string.IsNullOrEmpty(sceneName))
            return false;
        foreach (var hint in MenuSceneHints)
        {
            if (sceneName.IndexOf(hint, System.StringComparison.OrdinalIgnoreCase) >= 0)
                return true;
        }
        return false;
    }
}

using BepInEx;
using BepInEx.Configuration;
using BepInEx.Logging;
using HarmonyLib;
using SpikeBalanceMod.GameApi;
using SpikeBalanceMod.Patches;
using UnityEngine;

namespace SpikeBalanceMod;

[BepInPlugin(PluginGuid, PluginName, PluginVersion)]
public sealed class SpikeBalancePlugin : BaseUnityPlugin
{
    public const string PluginGuid = "com.spikebalance.whiteknuckle";
    public const string PluginName = "Spike Balance Mod";
    public const string PluginVersion = "1.0.4";

    internal static ManualLogSource? Log { get; private set; }
    internal static SpikeBalanceRuntime? Runtime { get; private set; }

    private Harmony? _harmony;

    private void Awake()
    {
        Log = Logger;
        Log.LogInfo($"{PluginName} v{PluginVersion} loading.");

        var spikesEnabled = Config.Bind("Spikes", "Enabled", true, "Place spikes on upward-facing surfaces.");
        var minUpDot = Config.Bind("Spikes", "MinUpDot", 0.45f, "Minimum world-space normal.y for a surface to receive spikes.");
        var spacing = Config.Bind("Spikes", "Spacing", 0.75f, "Minimum distance between spike placements.");
        var maxSpikes = Config.Bind("Spikes", "MaxSpikesPerRoom", 800, "Hard cap on spikes per scene.");
        var spikeHeight = Config.Bind("Spikes", "SpikeHeight", 0.35f, "Visual spike height.");
        var scanDelay = Config.Bind("Spikes", "ScanDelaySeconds", 3f, "Delay after run/room starts before scanning (procedural rooms).");

        var spikeDamage = Config.Bind("Resources", "SpikeDamagePerSecond", 5f, "Health damage per second while on spike ground.");
        var staminaRegen = Config.Bind("Resources", "StaminaRegenPerSecOnSpikes", 0.12f, "Grip/stamina regen per second on spike ground (grip is 0-1).");
        var healthDelay = Config.Bind("Resources", "HealthRegenDelay", 1.5f, "Seconds off spike ground before health regen starts.");
        var healthRegen = Config.Bind("Resources", "HealthRegenPerSec", 3f, "Health regen per second after delay.");

        var groundDistance = Config.Bind("Ground", "CheckDistance", 0.6f, "Downward sphere cast distance for spike ground.");
        var sphereRadius = Config.Bind("Ground", "SphereRadius", 0.25f, "Sphere cast radius for spike ground.");
        var requireFreeHands = Config.Bind("Ground", "RequireNoHandGrip", false, "Only count spike ground when hands are not gripping.");

        var showHealthBar = Config.Bind("UI", "ShowHealthBar", true, "Show the health bar overlay.");
        var showWhenFull = Config.Bind("UI", "ShowWhenFull", true, "Keep health bar visible at full health.");
        var debugLog = Config.Bind("General", "DebugLog", false, "Log run detection state every few seconds.");

        _harmony = new Harmony(PluginGuid);
        _harmony.PatchAll(typeof(PlayerStartPatch).Assembly);

        // Run on the BepInEx plugin object so Unity Update/FixedUpdate always execute.
        Runtime = gameObject.AddComponent<SpikeBalanceRuntime>();
        Runtime.Configure(
            spikesEnabled.Value,
            minUpDot.Value,
            spacing.Value,
            maxSpikes.Value,
            spikeHeight.Value,
            scanDelay.Value,
            groundDistance.Value,
            sphereRadius.Value,
            requireFreeHands.Value,
            spikeDamage.Value,
            staminaRegen.Value,
            healthDelay.Value,
            healthRegen.Value,
            showHealthBar.Value,
            showWhenFull.Value,
            debugLog.Value);

        Log.LogInfo($"{PluginName} loaded (runtime on plugin GameObject).");
    }

    internal static void NotifyPlayerStarted(ENT_Player player)
    {
        Log?.LogInfo($"ENT_Player.Start detected — scene={((MonoBehaviour)(object)player).gameObject.scene.name}");
        Runtime?.OnPlayerSpawned(player);
    }

    private void OnDestroy()
    {
        _harmony?.UnpatchSelf();
        if (Runtime != null)
            Destroy(Runtime);
    }
}

using System.Collections;
using SpikeBalanceMod.GameApi;
using SpikeBalanceMod.Player;
using SpikeBalanceMod.Spikes;
using SpikeBalanceMod.UI;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod;

/// <summary>Runtime behaviour for spike placement and resource balancing.</summary>
public sealed class SpikeBalanceRuntime : MonoBehaviour
{
    private static readonly float[] ScanRetryDelays = { 2f, 5f, 10f, 20f };

    private SpikePlacer _placer = null!;
    private SpikeGroundDetector _groundDetector = null!;
    private PlayerResourceController _resourceController = null!;
    private HealthBarUI _healthBar = null!;

    private bool _configured;
    private bool _spikesEnabled;
    private bool _debugLog;
    private float _minUpDot;
    private float _spacing;
    private int _maxSpikes;
    private float _spikeHeight;
    private float _scanDelaySeconds;
    private bool _showHealthBar;
    private bool _showHealthWhenFull;

    private bool _wasInRun;
    private int _trackedPlayerId;
    private int _lastPlacementCount = -1;
    private Coroutine? _scanRoutine;
    private float _nextPeriodicScan;
    private float _nextDebugLog;

    public void Configure(
        bool spikesEnabled,
        float minUpDot,
        float spacing,
        int maxSpikes,
        float spikeHeight,
        float scanDelaySeconds,
        float checkDistance,
        float sphereRadius,
        bool requireNoHandGrip,
        float spikeDamagePerSecond,
        float staminaRegenPerSecond,
        float healthRegenDelay,
        float healthRegenPerSecond,
        bool showHealthBar,
        bool showHealthWhenFull,
        bool debugLog)
    {
        _spikesEnabled = spikesEnabled;
        _debugLog = debugLog;
        _minUpDot = minUpDot;
        _spacing = spacing;
        _maxSpikes = maxSpikes;
        _spikeHeight = spikeHeight;
        _scanDelaySeconds = scanDelaySeconds;
        _showHealthBar = showHealthBar;
        _showHealthWhenFull = showHealthWhenFull;

        _placer = new SpikePlacer();
        _groundDetector = new SpikeGroundDetector(checkDistance, sphereRadius, requireNoHandGrip);
        _resourceController = new PlayerResourceController(
            spikeDamagePerSecond,
            staminaRegenPerSecond,
            healthRegenDelay,
            healthRegenPerSecond);
        _healthBar = new HealthBarUI(showHealthWhenFull);
        _configured = true;

        SpikeBalancePlugin.Log?.LogInfo("SpikeBalanceRuntime configured.");
    }

    private void Start()
    {
        if (!_configured)
            SpikeBalancePlugin.Log?.LogError("SpikeBalanceRuntime started without Configure().");

        SceneManager.sceneLoaded += OnSceneLoaded;
        SpikeBalancePlugin.Log?.LogInfo("SpikeBalanceRuntime Start — Update loop active.");
    }

    private void OnDestroy()
    {
        SceneManager.sceneLoaded -= OnSceneLoaded;
        StopScanRoutine();
        _placer?.Clear();
        _healthBar?.Destroy();
    }

    public void OnPlayerSpawned(ENT_Player player)
    {
        var id = ((MonoBehaviour)(object)player).GetInstanceID();
        if (id == _trackedPlayerId)
            return;
        _trackedPlayerId = id;
        OnRunStarted();
    }

    private void OnSceneLoaded(Scene scene, LoadSceneMode mode)
    {
        SpikeBalancePlugin.Log?.LogInfo($"Scene loaded: {scene.name}");
        if (RunState.ResolvePlayer() != null)
            ScheduleScan($"scene:{scene.name}");
    }

    private void OnRunStarted()
    {
        SpikeBalancePlugin.Log?.LogInfo("Run started — spikes + health bar enabled.");
        _lastPlacementCount = -1;
        _nextPeriodicScan = Time.unscaledTime + 3f;
        if (_showHealthBar)
            _healthBar.EnsureCreated();
        ScheduleScan("run_started");
    }

    private void OnRunEnded()
    {
        SpikeBalancePlugin.Log?.LogInfo("Run ended — clearing spikes, hiding health bar.");
        StopScanRoutine();
        _placer.Clear();
        _lastPlacementCount = -1;
        _trackedPlayerId = 0;
        _healthBar.Hide();
    }

    private void StopScanRoutine()
    {
        if (_scanRoutine == null)
            return;
        StopCoroutine(_scanRoutine);
        _scanRoutine = null;
    }

    private void ScheduleScan(string reason)
    {
        var player = RunState.ResolvePlayer();
        if (player == null)
            return;

        StopScanRoutine();
        _scanRoutine = StartCoroutine(ScanWithRetries(reason));
    }

    private IEnumerator ScanWithRetries(string reason)
    {
        SpikeBalancePlugin.Log?.LogInfo($"Spike scan scheduled ({reason}).");

        if (_scanDelaySeconds > 0f)
            yield return new WaitForSeconds(_scanDelaySeconds);
        else
            yield return null;

        yield return RunScan(reason);

        foreach (var delay in ScanRetryDelays)
        {
            yield return new WaitForSeconds(delay);
            if (!_spikesEnabled || RunState.ResolvePlayer() == null)
                yield break;

            yield return RunScan($"{reason}+retry@{delay}s");
            if (_lastPlacementCount > 0)
                yield break;
        }
    }

    private IEnumerator RunScan(string reason)
    {
        if (!_spikesEnabled)
            yield break;

        var player = RunState.ResolvePlayer();
        if (player == null)
            yield break;

        var sceneName = SceneManager.GetActiveScene().name;
        var scanner = new SpikeSurfaceScanner(_minUpDot, _spacing, _maxSpikes);
        var placements = scanner.ScanScene(player, out var colliderCount, out var handholdCount);
        var count = _placer.PlaceAll(placements, _spikeHeight);
        _lastPlacementCount = count;

        SpikeBalancePlugin.Log?.LogInfo(
            $"Spike scan ({reason}) scene={sceneName} playerScene={((MonoBehaviour)(object)player).gameObject.scene.name} " +
            $"handholds={handholdCount} colliders={colliderCount} placements={placements.Count} placed={count}");
    }

    private void Update()
    {
        var player = RunState.ResolvePlayer();
        var inRun = player != null && RunState.IsInActiveRun();

        if (_debugLog && Time.unscaledTime >= _nextDebugLog)
        {
            _nextDebugLog = Time.unscaledTime + 8f;
            var scene = SceneManager.GetActiveScene().name;
            var pScene = player != null ? ((MonoBehaviour)(object)player).gameObject.scene.name : "none";
            var maxHp = player != null ? PlayerAccess.GetMaxHealth(player) : 0f;
            SpikeBalancePlugin.Log?.LogInfo(
                $"Debug: inRun={inRun} scene={scene} playerScene={pScene} maxHp={maxHp} spikes={_lastPlacementCount}");
        }

        if (player != null)
        {
            var id = ((MonoBehaviour)(object)player).GetInstanceID();
            if (id != _trackedPlayerId)
            {
                _trackedPlayerId = id;
                OnRunStarted();
            }
        }

        if (!inRun)
        {
            if (_wasInRun)
                OnRunEnded();
            _wasInRun = false;
            return;
        }

        if (!_wasInRun)
            OnRunStarted();
        _wasInRun = true;

        if (_showHealthBar)
            _healthBar.Update(player);

        if (_spikesEnabled && _lastPlacementCount <= 0 && Time.unscaledTime >= _nextPeriodicScan)
        {
            _nextPeriodicScan = Time.unscaledTime + 15f;
            ScheduleScan("periodic");
        }
    }

    private void FixedUpdate()
    {
        var player = RunState.GetRunPlayer();
        if (player == null)
            return;

        _groundDetector.Update(player);
        _resourceController.Tick(player, _groundDetector.IsOnSpikeGround, Time.fixedDeltaTime);
    }
}

