using System;
using System.Reflection;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.Core;

internal static class PlayerBridge
{
    private static readonly FieldInfo HealthField = AccessTools.Field(typeof(GameEntity), "health")!;
    private static readonly FieldInfo MaxHealthField = AccessTools.Field(typeof(GameEntity), "maxHealth")!;
    private static readonly FieldInfo HandsField = AccessTools.Field(typeof(ENT_Player), "hands")!;
    private static readonly Type HandType = AccessTools.Inner(typeof(ENT_Player), "Hand")!;
    private static readonly FieldInfo GripField = AccessTools.Field(HandType, "gripStrength")!;
    private static readonly Type DamageInfoType = AccessTools.Inner(typeof(Damageable), "DamageInfo")!;
    private static readonly FieldInfo DamageAmountField = AccessTools.Field(DamageInfoType, "amount")!;
    private static readonly FieldInfo DamageTypeField = AccessTools.Field(DamageInfoType, "type")!;
    private static readonly FieldInfo LocalPlayerField = AccessTools.Field(typeof(CL_GameManager), "localPlayer")!;
    private static readonly FieldInfo RunHasEndedField = AccessTools.Field(typeof(CL_GameManager), "runHasEnded")!;

    public static ENT_Player? GetPlayer()
    {
        var gm = Object.FindObjectOfType(typeof(CL_GameManager)) as CL_GameManager;
        if (gm != null)
        {
            var local = LocalPlayerField.GetValue(gm) as ENT_Player;
            if (IsAlive(local))
                return local;
        }

        return Object.FindObjectOfType(typeof(ENT_Player)) as ENT_Player;
    }

    public static bool IsInRun(ENT_Player? player)
    {
        if (!IsAlive(player))
            return false;

        var gm = Object.FindObjectOfType(typeof(CL_GameManager)) as CL_GameManager;
        if (gm != null && (bool)(RunHasEndedField.GetValue(gm) ?? false))
            return false;

        var scene = ((MonoBehaviour)(object)player!).gameObject.scene.name.ToLowerInvariant();
        if (scene.Contains("mainmenu") || scene.Contains("title") || scene.Contains("boot")
            || scene.Contains("intro") || scene.Contains("lobby") || scene.Contains("credits"))
            return false;

        return true;
    }

    public static bool IsAlive(ENT_Player? player)
    {
        if (player == null)
            return false;
        var go = ((MonoBehaviour)(object)player).gameObject;
        return go.activeInHierarchy && go.scene.IsValid() && go.scene.isLoaded;
    }

    public static float GetHealth(ENT_Player player) => (float)(HealthField.GetValue(player) ?? 0f);
    public static float GetMaxHealth(ENT_Player player) => Mathf.Max(0.01f, (float)(MaxHealthField.GetValue(player) ?? 1f));

    public static void SetHealth(ENT_Player player, float value)
    {
        HealthField.SetValue(player, Mathf.Clamp(value, 0f, GetMaxHealth(player)));
    }

    public static void AddGrip(ENT_Player player, float delta)
    {
        var hands = HandsField.GetValue(player) as Array;
        if (hands == null)
            return;
        for (var i = 0; i < hands.Length; i++)
        {
            var hand = hands.GetValue(i)!;
            var g = (float)(GripField.GetValue(hand) ?? 0f);
            GripField.SetValue(hand, Mathf.Clamp01(g + delta));
        }
    }

    public static void ApplyDamage(ENT_Player player, float amount)
    {
        if (amount <= 0f)
            return;
        var info = Activator.CreateInstance(DamageInfoType)!;
        DamageAmountField.SetValue(info, amount);
        DamageTypeField.SetValue(info, "SpikeBalance");
        AccessTools.Method(typeof(ENT_Player), "Damage")?.Invoke(player, new[] { info });
    }

    public static bool IsGrounded(ENT_Player player) => player.IsGrounded(false);

    public static Vector3 GetPosition(ENT_Player player) =>
        ((MonoBehaviour)(object)player).transform.position;
}

