using System.Collections;
using System.Collections.Generic;
using System.Reflection;
using HarmonyLib;
using SpikeBalanceMod.Core;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod.Spikes;

internal sealed class SpikeSystem
{
    private const string RootName = "SpikeBalance_Root";

    private static readonly FieldInfo? HandholdsField =
        AccessTools.Field(typeof(HandholdManager), "handholds");

    private readonly MonoBehaviour _host;
    private readonly float _minUpDot;
    private readonly float _spacing;
    private readonly int _maxSpikes;
    private readonly float _spikeHeight;

    private GameObject? _root;
    private Coroutine? _placeRoutine;
    private int _placedCount;

    public int PlacedCount => _placedCount;

    public SpikeSystem(MonoBehaviour host, float minUpDot, float spacing, int maxSpikes, float spikeHeight)
    {
        _host = host;
        _minUpDot = minUpDot;
        _spacing = Mathf.Max(0.3f, spacing);
        _maxSpikes = maxSpikes;
        _spikeHeight = spikeHeight;
    }

    public void Clear()
    {
        if (_placeRoutine != null)
        {
            _host.StopCoroutine(_placeRoutine);
            _placeRoutine = null;
        }
        if (_root != null)
            Object.Destroy(_root);
        _root = null;
        _placedCount = 0;
    }

    public void SchedulePlacement(ENT_Player player)
    {
        if (_placeRoutine != null)
            _host.StopCoroutine(_placeRoutine);
        _placeRoutine = _host.StartCoroutine(PlaceWhenReady(player));
    }

    private IEnumerator PlaceWhenReady(ENT_Player player)
    {
        float[] waits = { 2f, 5f, 10f, 20f };
        foreach (var wait in waits)
        {
            yield return new WaitForSeconds(wait);
            if (!PlayerBridge.IsInRun(player))
                yield break;

            var n = PlaceSpikes(player);
            SpikeBalancePlugin.Logger.LogInfo($"[Spikes] attempt after {wait}s -> placed {n}");
            if (n > 0)
                yield break;
        }
    }

    private int PlaceSpikes(ENT_Player player)
    {
        Clear();
        _root = new GameObject(RootName);
        var scene = ((MonoBehaviour)(object)player).gameObject.scene;
        if (scene.IsValid())
            SceneManager.MoveGameObjectToScene(_root, scene);

        var cells = new HashSet<long>();
        var points = new List<(Vector3 pos, Vector3 normal)>();

        CollectHandholds(points, cells);
        CollectRaycasts(PlayerBridge.GetPosition(player), points, cells);
        CollectColliders(points, cells);

        var count = 0;
        foreach (var (pos, normal) in points)
        {
            if (count >= _maxSpikes)
                break;
            SpawnSpike(pos, normal, _root.transform);
            count++;
        }

        _placedCount = count;
        return count;
    }

    private void CollectHandholds(List<(Vector3, Vector3)> points, HashSet<long> cells)
    {
        void Add(CL_Handhold? hh)
        {
            if (hh == null)
                return;
            var tr = ((MonoBehaviour)(object)hh).transform;
            if (!tr.gameObject.activeInHierarchy)
                return;
            var n = tr.up.normalized;
            if (n.y < _minUpDot)
                n = Vector3.up;
            TryPoint(tr.position, n, points, cells);
        }

        var mgr = Object.FindObjectOfType(typeof(HandholdManager)) as HandholdManager;
        if (mgr != null && HandholdsField?.GetValue(mgr) is IEnumerable list)
        {
            foreach (var item in list)
                Add(item as CL_Handhold);
        }

        foreach (var hh in Resources.FindObjectsOfTypeAll<CL_Handhold>())
            Add(hh);
    }

    private void CollectRaycasts(Vector3 center, List<(Vector3, Vector3)> points, HashSet<long> cells)
    {
        const float radius = 35f;
        var steps = Mathf.CeilToInt(radius * 2f / _spacing);
        for (var x = 0; x <= steps; x++)
        {
            for (var z = 0; z <= steps; z++)
            {
                var px = center.x - radius + (2f * radius * x / Mathf.Max(1, steps));
                var pz = center.z - radius + (2f * radius * z / Mathf.Max(1, steps));
                var from = new Vector3(px, center.y + 30f, pz);
                if (!Physics.Raycast(from, Vector3.down, out var hit, 80f, ~0, QueryTriggerInteraction.Ignore))
                    continue;
                if (hit.collider.GetComponentInParent<ENT_Player>() != null)
                    continue;
                if (hit.normal.y < _minUpDot)
                    continue;
                TryPoint(hit.point, hit.normal, points, cells);
            }
        }
    }

    private void CollectColliders(List<(Vector3, Vector3)> points, HashSet<long> cells)
    {
        foreach (var col in Object.FindObjectsOfType<Collider>())
        {
            if (col == null || !col.enabled || col.isTrigger || !col.gameObject.activeInHierarchy)
                continue;
            if (col.GetComponentInParent<ENT_Player>() != null || col.GetComponentInParent<SpikeMarker>() != null)
                continue;

            if (col is BoxCollider box)
            {
                var tr = box.transform;
                var n = tr.TransformDirection(Vector3.up).normalized;
                if (n.y < _minUpDot)
                    continue;
                var c = box.center;
                var e = box.size * 0.5f;
                TryPoint(tr.TransformPoint(c + new Vector3(0f, e.y, 0f)), n, points, cells);
            }
            else
            {
                var b = col.bounds;
                if (b.size.sqrMagnitude > 0.01f)
                    TryPoint(new Vector3(b.center.x, b.max.y, b.center.z), Vector3.up, points, cells);
            }
        }
    }

    private void TryPoint(Vector3 pos, Vector3 normal, List<(Vector3, Vector3)> points, HashSet<long> cells)
    {
        var key = ((long)Mathf.FloorToInt(pos.x / _spacing) << 42)
                  ^ ((long)Mathf.FloorToInt(pos.y / _spacing) << 21)
                  ^ (uint)Mathf.FloorToInt(pos.z / _spacing);
        if (!cells.Add(key))
            return;
        points.Add((pos, normal.normalized));
    }

    private void SpawnSpike(Vector3 pos, Vector3 normal, Transform parent)
    {
        var go = new GameObject("Spike");
        go.transform.SetParent(parent, false);
        go.transform.position = pos + normal * 0.03f;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);

        var vis = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
        vis.transform.SetParent(go.transform, false);
        vis.transform.localScale = new Vector3(0.22f, _spikeHeight * 0.5f, 0.22f);
        vis.transform.localPosition = new Vector3(0f, _spikeHeight * 0.5f, 0f);
        Object.Destroy(vis.GetComponent<Collider>());

        var rend = vis.GetComponent<Renderer>();
        if (rend != null)
        {
            var sh = Shader.Find("Unlit/Color") ?? Shader.Find("Sprites/Default");
            var mat = new Material(sh!);
            mat.color = new Color(1f, 0.15f, 0.1f);
            rend.material = mat;
        }

        var col = go.AddComponent<BoxCollider>();
        col.isTrigger = true;
        col.size = new Vector3(0.4f, 0.12f, 0.4f);
        go.AddComponent<SpikeMarker>();
    }

    public bool IsOnSpikeGround(ENT_Player player)
    {
        if (!PlayerBridge.IsGrounded(player))
            return false;
        var origin = PlayerBridge.GetPosition(player) + Vector3.up * 0.15f;
        return Physics.SphereCast(origin, 0.3f, Vector3.down, out var hit, 0.8f, ~0, QueryTriggerInteraction.Collide)
               && hit.collider.GetComponentInParent<SpikeMarker>() != null;
    }
}

using SpikeBalanceMod.Core;
