namespace SpikeBalanceMod.UI;

internal sealed class HealthBar
{
    private const float TopMargin = 8f;

    private GameObject? _root;
    private Image? _fill;
    private Text? _label;

    public void Destroy()
    {
        if (_root != null)
            Object.Destroy(_root);
        _root = null;
        _fill = null;
        _label = null;
    }

    public void Hide()
    {
        if (_root != null)
            _root.SetActive(false);
    }

    private void Build()
    {
        if (_root != null)
            return;

        var sprite = Resources.GetBuiltinResource<Sprite>("UI/Skin/UISprite.psd");
        if (sprite == null)
        {
            var tex = new Texture2D(4, 4);
            var cols = new Color[16];
            for (var i = 0; i < cols.Length; i++)
                cols[i] = Color.white;
            tex.SetPixels(cols);
            tex.Apply();
            sprite = Sprite.Create(tex, new Rect(0, 0, 4, 4), new Vector2(0.5f, 0.5f), 100f);
        }

        _root = new GameObject("SpikeBalance_HealthBar");
        Object.DontDestroyOnLoad(_root);

        var canvas = _root.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 10000;

        var scaler = _root.AddComponent<CanvasScaler>();
        scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        scaler.referenceResolution = new Vector2(1920, 1080);

        var panel = new GameObject("Bar");
        panel.transform.SetParent(_root.transform, false);
        var rect = panel.AddComponent<RectTransform>();
        rect.anchorMin = new Vector2(0.5f, 1f);
        rect.anchorMax = new Vector2(0.5f, 1f);
        rect.pivot = new Vector2(0.5f, 1f);
        rect.anchoredPosition = new Vector2(0f, -TopMargin);
        rect.sizeDelta = new Vector2(320f, 34f);

        var bg = panel.AddComponent<Image>();
        bg.sprite = sprite;
        bg.type = Image.Type.Sliced;
        bg.color = new Color(0.05f, 0.05f, 0.05f, 0.92f);

        var fillGo = new GameObject("Fill");
        fillGo.transform.SetParent(panel.transform, false);
        var fillRect = fillGo.AddComponent<RectTransform>();
        fillRect.anchorMin = Vector2.zero;
        fillRect.anchorMax = Vector2.one;
        fillRect.offsetMin = new Vector2(3f, 3f);
        fillRect.offsetMax = new Vector2(-3f, -3f);
        _fill = fillGo.AddComponent<Image>();
        _fill.sprite = sprite;
        _fill.type = Image.Type.Filled;
        _fill.fillMethod = Image.FillMethod.Horizontal;
        _fill.color = new Color(0.82f, 0.12f, 0.12f);

        var textGo = new GameObject("HP");
        textGo.transform.SetParent(panel.transform, false);
        var textRect = textGo.AddComponent<RectTransform>();
        textRect.anchorMin = Vector2.zero;
        textRect.anchorMax = Vector2.one;
        textRect.offsetMin = Vector2.zero;
        textRect.offsetMax = Vector2.zero;
        _label = textGo.AddComponent<Text>();
        _label.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf")
            ?? Font.CreateDynamicFontFromOSFont("Arial", 16);
        _label.alignment = TextAnchor.MiddleCenter;
        _label.fontSize = 20;
        _label.fontStyle = FontStyle.Bold;
        _label.color = Color.white;
        _label.raycastTarget = false;

        _root.SetActive(false);
    }

    public void Draw(ENT_Player player)
    {
        Build();
        if (_root == null || _fill == null || _label == null)
            return;

        var hp = PlayerBridge.GetHealth(player);
        var max = PlayerBridge.GetMaxHealth(player);
        _root.SetActive(true);
        _fill.fillAmount = Mathf.Clamp01(hp / max);
        _label.text = $"{Mathf.CeilToInt(hp)}";
    }
}

