using BepInEx;
using BepInEx.Configuration;
using BepInEx.Logging;
using HarmonyLib;
using SpikeBalanceMod.Core;
using SpikeBalanceMod.Spikes;
using SpikeBalanceMod.UI;
using UnityEngine;

namespace SpikeBalanceMod;

/// <summary>
/// All game logic runs on BaseUnityPlugin (guaranteed Update/FixedUpdate).
/// </summary>
[BepInPlugin(PluginGuid, PluginName, PluginVersion)]
public sealed class SpikeBalancePlugin : BaseUnityPlugin
{
    public const string PluginGuid = "com.spikebalance.whiteknuckle";
    public const string PluginName = "Spike Balance Mod";
    public const string PluginVersion = "2.0.0";

    internal static ManualLogSource Logger = null!;
    internal static SpikeBalancePlugin Instance = null!;

    private Harmony? _harmony;
    private SpikeSystem? _spikes;
    private HealthBar? _healthBar;

    private ConfigEntry<bool> _spikesEnabled = null!;
    private ConfigEntry<float> _minUpDot = null!;
    private ConfigEntry<float> _spacing = null!;
    private ConfigEntry<int> _maxSpikes = null!;
    private ConfigEntry<float> _spikeHeight = null!;
    private ConfigEntry<float> _spikeDamage = null!;
    private ConfigEntry<float> _staminaRegen = null!;
    private ConfigEntry<float> _healthRegenDelay = null!;
    private ConfigEntry<float> _healthRegen = null!;
    private ConfigEntry<bool> _showHealthBar = null!;

    private bool _runActive;
    private float _offSpikeTimer;
    private float _logTimer;

    private void Awake()
    {
        Instance = this;
        Logger = base.Logger;
        Logger.LogInfo($"{PluginName} v{PluginVersion} — fresh build");

        _spikesEnabled = Config.Bind("Spikes", "Enabled", true);
        _minUpDot = Config.Bind("Spikes", "MinUpDot", 0.4f);
        _spacing = Config.Bind("Spikes", "Spacing", 0.8f);
        _maxSpikes = Config.Bind("Spikes", "MaxSpikes", 600);
        _spikeHeight = Config.Bind("Spikes", "SpikeHeight", 0.4f);
        _spikeDamage = Config.Bind("Resources", "SpikeDamagePerSecond", 5f);
        _staminaRegen = Config.Bind("Resources", "StaminaRegenPerSecond", 0.15f);
        _healthRegenDelay = Config.Bind("Resources", "HealthRegenDelay", 1.5f);
        _healthRegen = Config.Bind("Resources", "HealthRegenPerSecond", 3f);
        _showHealthBar = Config.Bind("UI", "ShowHealthBar", true);

        _harmony = new Harmony(PluginGuid);
        _harmony.PatchAll();

        _spikes = new SpikeSystem(this, _minUpDot.Value, _spacing.Value, _maxSpikes.Value, _spikeHeight.Value);
        _healthBar = new HealthBar();

        Logger.LogInfo("Harmony patched, systems ready. Waiting for run...");
    }

    internal static void OnPlayerSpawned(ENT_Player player)
    {
        var scene = ((MonoBehaviour)(object)player).gameObject.scene.name;
        Logger.LogInfo($"Player spawned in scene '{scene}'");
        Instance?.EnterRun(player);
    }

    private void EnterRun(ENT_Player player)
    {
        if (_runActive)
            return;
        _runActive = true;
        _offSpikeTimer = 0f;
        Logger.LogInfo("=== RUN ACTIVE — health bar + spikes enabled ===");

        if (_showHealthBar.Value)
            _healthBar?.Draw(player);

        if (_spikesEnabled.Value)
            _spikes?.SchedulePlacement(player);
    }

    private void ExitRun()
    {
        if (!_runActive)
            return;
        _runActive = false;
        Logger.LogInfo("=== RUN ENDED — cleanup ===");
        _spikes?.Clear();
        _healthBar?.Hide();
    }

    private void Update()
    {
        var player = PlayerBridge.GetPlayer();
        var inRun = PlayerBridge.IsInRun(player);

        if (inRun != _runActive)
        {
            if (inRun && player != null)
                EnterRun(player);
            else
                ExitRun();
        }

        if (!inRun || player == null)
            return;

        if (_showHealthBar.Value)
            _healthBar?.Draw(player);

        if (Time.unscaledTime >= _logTimer)
        {
            _logTimer = Time.unscaledTime + 10f;
            Logger.LogInfo($"[Tick] scene={((MonoBehaviour)(object)player).gameObject.scene.name} hp={PlayerBridge.GetHealth(player):F0} spikes={_spikes?.PlacedCount ?? 0}");
        }

        if (_spikesEnabled.Value && (_spikes?.PlacedCount ?? 0) == 0 && Time.frameCount % 900 == 0)
            _spikes?.SchedulePlacement(player);
    }

    private void FixedUpdate()
    {
        var player = PlayerBridge.GetPlayer();
        if (!PlayerBridge.IsInRun(player) || player == null || _spikes == null)
            return;

        var onSpikes = _spikes.IsOnSpikeGround(player);
        if (onSpikes)
        {
            _offSpikeTimer = 0f;
            PlayerBridge.ApplyDamage(player, _spikeDamage.Value * Time.fixedDeltaTime);
            PlayerBridge.AddGrip(player, _staminaRegen.Value * Time.fixedDeltaTime);
        }
        else
        {
            _offSpikeTimer += Time.fixedDeltaTime;
            if (_offSpikeTimer >= _healthRegenDelay.Value)
            {
                var hp = PlayerBridge.GetHealth(player);
                var max = PlayerBridge.GetMaxHealth(player);
                if (hp < max)
                    PlayerBridge.SetHealth(player, hp + _healthRegen.Value * Time.fixedDeltaTime);
            }
        }
    }

    private void OnDestroy()
    {
        _harmony?.UnpatchSelf();
        _spikes?.Clear();
        _healthBar?.Destroy();
    }
}

using UnityEngine;

namespace SpikeBalanceMod.Core;

/// <summary>
/// Mod-owned health pool shown on the health bar. Spike damage only touches this,
/// never ENT_Player.Damage() (which also drains hand grip / stamina).
/// </summary>
internal sealed class ModHealth
{
    public float Current { get; private set; }
    public float Max { get; private set; }

    public void ResetFromPlayer(ENT_Player player)
    {
        Max = PlayerBridge.GetMaxHealth(player);
        Current = Max;
        SyncToGameHealth(player);
    }

    public void ApplySpikeDamage(ENT_Player player, float amount)
    {
        if (amount <= 0f)
            return;
        Current = Mathf.Max(0f, Current - amount);
        SyncToGameHealth(player);
    }

    public void Regenerate(ENT_Player player, float amount)
    {
        if (amount <= 0f)
            return;
        Current = Mathf.Min(Max, Current + amount);
        SyncToGameHealth(player);
    }

    /// <summary>Keep game entity health aligned for death/vanilla systems without calling Damage().</summary>
    private void SyncToGameHealth(ENT_Player player) =>
        PlayerBridge.SetHealth(player, Current);
}

