namespace SpikeBalanceMod.Core;

/// <summary>Scope flag so Harmony can block DamageGripStrength during mod-only health changes.</summary>
internal static class GripProtect
{
    public static bool Active { get; private set; }

    public static GripProtectScope Begin() => new();

    internal sealed class GripProtectScope : System.IDisposable
    {
        public GripProtectScope() => Active = true;
        public void Dispose() => Active = false;
    }
}

using HarmonyLib;
using SpikeBalanceMod.Core;

namespace SpikeBalanceMod.Patches;

/// <summary>Prevents hand grip drain when mod health changes without using Damage().</summary>
internal static class GripProtectPatches
{
    [HarmonyPrefix]
    [HarmonyPatch(typeof(ENT_Player), "DamageGripStrength")]
    private static bool BlockDamageGripStrength()
    {
        // false = skip original (no grip drain)
        return !GripProtect.Active;
    }
}

using UnityEngine;

namespace SpikeBalanceMod.Core;

/// <summary>
/// Mod-owned health pool for the health bar. Never calls ENT_Player.Damage().
/// Never writes game health (that can couple health loss to grip via game scripts).
/// </summary>
internal sealed class ModHealth
{
    public float Current { get; private set; }
    public float Max { get; private set; }

    public void ResetFromPlayer(ENT_Player player)
    {
        Max = PlayerBridge.GetMaxHealth(player);
        Current = Max;
    }

    public void ApplySpikeDamage(ENT_Player player, float amount)
    {
        if (amount <= 0f)
            return;

        var gripBefore = PlayerBridge.SnapshotGrip(player);
        using (GripProtect.Begin())
        {
            Current = Mathf.Max(0f, Current - amount);
        }
        PlayerBridge.RestoreGrip(player, gripBefore);
    }

    public void Regenerate(ENT_Player player, float amount)
    {
        if (amount <= 0f)
            return;

        var gripBefore = PlayerBridge.SnapshotGrip(player);
        using (GripProtect.Begin())
        {
            Current = Mathf.Min(Max, Current + amount);
        }
        PlayerBridge.RestoreGrip(player, gripBefore);
    }

    public bool IsDead => Current <= 0f;
}

