public static float[] SnapshotGrip(ENT_Player player)
{
    var hands = HandsField.GetValue(player) as Array;
    if (hands == null || hands.Length == 0)
        return System.Array.Empty<float>();

    var snap = new float[hands.Length];
    for (var i = 0; i < hands.Length; i++)
        snap[i] = (float)(GripField.GetValue(hands.GetValue(i)!) ?? 0f);
    return snap;
}

public static void RestoreGrip(ENT_Player player, float[] snapshot)
{
    var hands = HandsField.GetValue(player) as Array;
    if (hands == null || snapshot.Length == 0)
        return;

    for (var i = 0; i < hands.Length && i < snapshot.Length; i++)
        GripField.SetValue(hands.GetValue(i)!, Mathf.Clamp01(snapshot[i]));
}

public static void AddGrip(ENT_Player player, float delta)
{
    var hands = HandsField.GetValue(player) as Array;
    if (hands == null)
        return;
    for (var i = 0; i < hands.Length; i++)
    {
        var hand = hands.GetValue(i)!;
        var g = (float)(GripField.GetValue(hand) ?? 0f);
        GripField.SetValue(hand, Mathf.Clamp01(g + delta));
    }
}

public static bool IsGrounded(ENT_Player player) => player.IsGrounded(false);

