using UnityEngine;

namespace SpikeBalanceMod.Core;

/// <summary>
/// While on mod spike ground, grip must not decrease (game drains via Hand.DamageGripStrength / HandStamina).
/// </summary>
internal static class GripStability
{
    public static bool OnSpikeGround { get; set; }

    private static float[]? _floor;

    public static void OnSpikeContactStart(ENT_Player player)
    {
        _floor = PlayerBridge.SnapshotGrip(player);
    }

    public static void OnSpikeContactEnd() => _floor = null;

    /// <summary>After game systems run, clamp grip so it never dropped below the per-contact floor.</summary>
    public static void EnforceMonotonicGrip(ENT_Player player)
    {
        if (_floor == null)
            return;

        var hands = PlayerBridge.GetHandCount(player);
        if (hands <= 0)
            return;

        var current = PlayerBridge.SnapshotGrip(player);
        for (var i = 0; i < hands && i < _floor.Length && i < current.Length; i++)
        {
            if (current[i] < _floor[i])
                current[i] = _floor[i];
            else
                _floor[i] = current[i];
        }

        PlayerBridge.RestoreGrip(player, current);
    }
}

