using HarmonyLib;
using SpikeBalanceMod.Core;

namespace SpikeBalanceMod.Patches;

internal static class GripProtectPatches
{
    private static readonly System.Type HandType = AccessTools.Inner(typeof(ENT_Player), "Hand")!;

    [HarmonyPrefix]
    [HarmonyPatch(typeof(ENT_Player), "DamageGripStrength")]
    private static bool BlockPlayerDamageGrip() => ShouldBlock();

    /// <summary>Primary grip drain path used by HandStamina while climbing.</summary>
    [HarmonyPrefix]
    [HarmonyPatch(HandType, "DamageGripStrength", typeof(float))]
    private static bool BlockHandDamageGrip() => ShouldBlock();

    [HarmonyPrefix]
    [HarmonyPatch(typeof(ENT_Player), "SetGripStrength")]
    private static bool BlockSetGripStrength(ref float amount)
    {
        if (!ShouldBlock())
            return true;
        // Block any reduction while on spike ground (amount is target grip level in some calls).
        return amount >= 0f;
    }

    [HarmonyPostfix]
    [HarmonyPatch(typeof(ENT_Player), "HandStamina")]
    private static void AfterHandStamina(ENT_Player __instance)
    {
        if (GripStability.OnSpikeGround)
            GripStability.EnforceMonotonicGrip(__instance);
    }

    private static bool ShouldBlock() =>
        GripProtect.Active || GripStability.OnSpikeGround;
}

using BepInEx;
using BepInEx.Configuration;
using BepInEx.Logging;
using HarmonyLib;
using SpikeBalanceMod.Core;
using SpikeBalanceMod.Spikes;
using SpikeBalanceMod.UI;
using UnityEngine;

namespace SpikeBalanceMod;

[BepInPlugin(PluginGuid, PluginName, PluginVersion)]
public sealed class SpikeBalancePlugin : BaseUnityPlugin
{
    public const string PluginGuid = "com.spikebalance.whiteknuckle";
    public const string PluginName = "Spike Balance Mod";
    public const string PluginVersion = "2.1.0";

    internal static new ManualLogSource Logger = null!;
    internal static SpikeBalancePlugin Instance = null!;

    private Harmony? _harmony;
    private SpikeSystem? _spikes;
    private HealthBar? _healthBar;
    private readonly ModHealth _modHealth = new();

    private ConfigEntry<bool> _spikesEnabled = null!;
    private ConfigEntry<float> _minUpDot = null!;
    private ConfigEntry<float> _spacing = null!;
    private ConfigEntry<int> _maxSpikes = null!;
    private ConfigEntry<float> _spikeHeight = null!;
    private ConfigEntry<float> _spikeDamage = null!;
    private ConfigEntry<float> _staminaRegen = null!;
    private ConfigEntry<float> _healthRegenDelay = null!;
    private ConfigEntry<float> _healthRegen = null!;
    private ConfigEntry<bool> _showHealthBar = null!;

    private bool _runActive;
    private bool _wasOnSpikes;
    private float _offSpikeTimer;
    private float _logTimer;

    private void Awake()
    {
        Instance = this;
        Logger = base.Logger;
        Logger.LogInfo($"{PluginName} v{PluginVersion}");

        _spikesEnabled = Config.Bind("Spikes", "Enabled", true);
        _minUpDot = Config.Bind("Spikes", "MinUpDot", 0.4f);
        _spacing = Config.Bind("Spikes", "Spacing", 0.8f);
        _maxSpikes = Config.Bind("Spikes", "MaxSpikes", 600);
        _spikeHeight = Config.Bind("Spikes", "SpikeHeight", 0.4f);
        _spikeDamage = Config.Bind("Resources", "SpikeDamagePerSecond", 5f);
        _staminaRegen = Config.Bind("Resources", "StaminaRegenPerSecond", 0.15f);
        _healthRegenDelay = Config.Bind("Resources", "HealthRegenDelay", 1.5f);
        _healthRegen = Config.Bind("Resources", "HealthRegenPerSecond", 3f);
        _showHealthBar = Config.Bind("UI", "ShowHealthBar", true);

        _harmony = new Harmony(PluginGuid);
        _harmony.PatchAll();

        _spikes = new SpikeSystem(this, _minUpDot.Value, _spacing.Value, _maxSpikes.Value, _spikeHeight.Value);
        _healthBar = new HealthBar();

        Logger.LogInfo("Ready.");
    }

    internal static void OnPlayerSpawned(ENT_Player player) => Instance?.EnterRun(player);

    private void EnterRun(ENT_Player player)
    {
        if (_runActive)
            return;
        _runActive = true;
        _wasOnSpikes = false;
        _offSpikeTimer = 0f;
        _modHealth.ResetFromPlayer(player);
        Logger.LogInfo("Run active.");
        if (_showHealthBar.Value)
            _healthBar?.Draw(_modHealth.Current, _modHealth.Max);
        if (_spikesEnabled.Value)
            _spikes?.SchedulePlacement(player);
    }

    private void ExitRun()
    {
        if (!_runActive)
            return;
        _runActive = false;
        _wasOnSpikes = false;
        GripStability.OnSpikeGround = false;
        GripStability.OnSpikeContactEnd();
        _spikes?.Clear();
        _healthBar?.Hide();
        Logger.LogInfo("Run ended.");
    }

    private void Update()
    {
        var player = PlayerBridge.GetPlayer();
        var inRun = PlayerBridge.IsInRun(player);

        if (inRun != _runActive)
        {
            if (inRun && player != null)
                EnterRun(player);
            else
                ExitRun();
        }

        if (!inRun || player == null)
            return;

        if (_showHealthBar.Value)
            _healthBar?.Draw(_modHealth.Current, _modHealth.Max);

        if (Time.unscaledTime >= _logTimer)
        {
            _logTimer = Time.unscaledTime + 10f;
            var grip = PlayerBridge.SnapshotGrip(player);
            var g0 = grip.Length > 0 ? grip[0] : 0f;
            Logger.LogInfo($"[Tick] modHp={_modHealth.Current:F0} grip0={g0:F2} onSpikes={GripStability.OnSpikeGround}");
        }

        if (_spikesEnabled.Value && (_spikes?.PlacedCount ?? 0) == 0 && Time.frameCount % 900 == 0)
            _spikes?.SchedulePlacement(player);
    }

    private void FixedUpdate()
    {
        var player = PlayerBridge.GetPlayer();
        if (!PlayerBridge.IsInRun(player) || player == null || _spikes == null)
        {
            GripStability.OnSpikeGround = false;
            return;
        }

        var onSpikes = _spikes.IsOnSpikeGround(player);
        GripStability.OnSpikeGround = onSpikes;

        if (onSpikes && !_wasOnSpikes)
            GripStability.OnSpikeContactStart(player);

        if (onSpikes)
        {
            _offSpikeTimer = 0f;
            _modHealth.ApplySpikeDamage(player, _spikeDamage.Value * Time.fixedDeltaTime);
            PlayerBridge.AddGrip(player, _staminaRegen.Value * Time.fixedDeltaTime);
        }
        else
        {
            if (_wasOnSpikes)
                GripStability.OnSpikeContactEnd();

            _offSpikeTimer += Time.fixedDeltaTime;
            if (_offSpikeTimer >= _healthRegenDelay.Value && _modHealth.Current < _modHealth.Max)
                _modHealth.Regenerate(player, _healthRegen.Value * Time.fixedDeltaTime);
        }

        _wasOnSpikes = onSpikes;
    }

    private void LateUpdate()
    {
        var player = PlayerBridge.GetPlayer();
        if (!PlayerBridge.IsInRun(player) || player == null || !GripStability.OnSpikeGround)
            return;

        GripStability.EnforceMonotonicGrip(player);
    }

    private void OnDestroy()
    {
        _harmony?.UnpatchSelf();
        _spikes?.Clear();
        _healthBar?.Destroy();
    }
}

