    public ConfigEntry<float> HealthRegenOffSpikes { get; }
    public ConfigEntry<float> HealthRegenDelay { get; }
    public ConfigEntry<float> GroundCheckDistance { get; }
    public ConfigEntry<float> GroundSphereRadius { get; }
    public ConfigEntry<bool> RequireFreeHands { get; }
    public ConfigEntry<bool> DebugLog { get; }

    public ModConfig(ConfigFile cfg)
    {
        MinUpDot = cfg.Bind("Spikes", "MinUpDot", 0.55f, "Minimum surface up-dot (0–1) to place spikes.");
        SpikeSpacing = cfg.Bind("Spikes", "Spacing", 2.5f, "Grid spacing between spike points.");
        MaxSpikes = cfg.Bind("Spikes", "MaxPerRoom", 400, "Cap on spike markers per scan.");
        SpikeDps = cfg.Bind("Balance", "SpikeDamagePerSecond", 12f, "Mod health drain per second on spike ground.");
        GripRegenOnSpikes = cfg.Bind("Balance", "GripRegenOnSpikes", 0.35f, "Grip strength recovered per second on spike ground.");
        HealthRegenOffSpikes = cfg.Bind("Balance", "HealthRegenOffSpikes", 8f, "Mod health regen per second off spikes.");
        HealthRegenDelay = cfg.Bind("Balance", "HealthRegenDelay", 2f, "Seconds off spikes before health regen.");
        GroundCheckDistance = cfg.Bind("Detection", "GroundCheckDistance", 1.2f, "Downward cast distance for spike ground.");
        GroundSphereRadius = cfg.Bind("Detection", "GroundSphereRadius", 0.45f, "Sphere radius for spike ground check.");
        RequireFreeHands = cfg.Bind("Detection", "RequireFreeHands", false, "Only count spike ground when hands are not gripping.");
        DebugLog = cfg.Bind("Debug", "LogStatus", false, "Log mod HP / grip / spike state every 2s.");
    }
}

using System;
using System.Reflection;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod;

internal static class PlayerUtil
{
    private static readonly FieldRef<CL_GameManager, bool> RunHasEnded =
        AccessTools.FieldRefAccess<CL_GameManager, bool>("runHasEnded");

    private static readonly FieldRef<CL_GameManager, ENT_Player> LocalPlayer =
        AccessTools.FieldRefAccess<CL_GameManager, ENT_Player>("localPlayer");

    private static readonly FieldInfo HandsField = AccessTools.Field(typeof(ENT_Player), "hands")!;
    private static readonly Type HandType = AccessTools.Inner(typeof(ENT_Player), "Hand")!;
    private static readonly FieldInfo GripField = AccessTools.Field(HandType, "gripStrength")!;
    private static readonly FieldInfo InfiniteStaminaField = AccessTools.Field(typeof(ENT_Player), "infiniteStamina")!;
    private static readonly MethodInfo AddGripMethod = AccessTools.Method(HandType, "AddGripStrength")!;
    private static readonly MethodInfo SetGripMethod = AccessTools.Method(HandType, "SetGripStrength")!;

    public static ENT_Player? FindPlayer()
    {
        var gm = UnityEngine.Object.FindObjectOfType<CL_GameManager>();
        if (gm != null)
        {
            var lp = LocalPlayer(gm);
            if (lp != null && lp.gameObject.activeInHierarchy)
                return lp;
        }

        foreach (var p in UnityEngine.Object.FindObjectsOfType<ENT_Player>())
        {
            if (p != null && p.gameObject.activeInHierarchy && !IsMenuScene(p.gameObject.scene.name))
                return p;
        }

        return null;
    }

    public static bool IsMenuScene(string sceneName)
    {
        if (string.IsNullOrEmpty(sceneName))
            return true;
        var n = sceneName.ToLowerInvariant();
        return n.Contains("menu") || n.Contains("title") || n.Contains("bootstrap") || n == "init";
    }

    public static bool IsInActiveRun(ENT_Player? player)
    {
        if (player == null || !player.gameObject.activeInHierarchy)
            return false;
        if (IsMenuScene(player.gameObject.scene.name))
            return false;

        var gm = UnityEngine.Object.FindObjectOfType<CL_GameManager>();
        if (gm != null && RunHasEnded(gm))
            return false;

        return true;
    }

    public static Array? GetHands(ENT_Player player) => HandsField.GetValue(player) as Array;

    public static float GetGrip(object hand) => (float)GripField.GetValue(hand)!;

    public static void SetGrip(object hand, float value) => GripField.SetValue(hand, Mathf.Clamp01(value));

    public static void AddGrip(object hand, float amount)
    {
        if (amount <= 0f)
            return;
        AddGripMethod.Invoke(hand, new object[] { amount });
    }

    public static void ForceGrip(object hand, float value) => SetGripMethod.Invoke(hand, new object[] { value });

    public static bool GetInfiniteStamina(ENT_Player player) => (bool)InfiniteStaminaField.GetValue(player)!;

    public static void SetInfiniteStamina(ENT_Player player, bool value) => InfiniteStaminaField.SetValue(player, value);

    public static bool AreHandsFree(ENT_Player player)
    {
        var hands = GetHands(player);
        if (hands == null)
            return true;
        foreach (var h in hands)
        {
            if (h == null)
                continue;
            if (GetGrip(h) < 0.99f)
                return false;
        }
        return true;
    }
}

namespace SpikeBalanceMod;

/// <summary>Mod-only health pool. Never routed through ENT_Player.Damage.</summary>
internal sealed class ModHealthPool
{
    public float Current { get; private set; }
    public float Max { get; private set; } = 100f;

    public void Reset(float max = 100f)
    {
        Max = max;
        Current = max;
    }

    public void ApplyDamage(float amount)
    {
        if (amount <= 0f)
            return;
        Current = UnityEngine.Mathf.Max(0f, Current - amount);
    }

    public void Regen(float amount)
    {
        if (amount <= 0f)
            return;
        Current = UnityEngine.Mathf.Min(Max, Current + amount);
    }

    public bool IsDead => Current <= 0f;
}

