namespace SpikeBalanceMod;

/// <summary>While on spike ground: no grip drain, only recovery.</summary>
internal sealed class GripOnSpikes
{
    private float[]? _floor;
    private bool _savedInfinite;
    private bool _appliedInfinite;

    public void Enter(ENT_Player player)
    {
        _savedInfinite = PlayerUtil.GetInfiniteStamina(player);
        PlayerUtil.SetInfiniteStamina(player, true);
        _appliedInfinite = true;
        SnapshotFloor(player);
    }

    public void Exit(ENT_Player player)
    {
        if (_appliedInfinite)
        {
            PlayerUtil.SetInfiniteStamina(player, _savedInfinite);
            _appliedInfinite = false;
        }
        _floor = null;
    }

    public void TickRegen(ENT_Player player, float delta, float regenPerSecond)
    {
        if (regenPerSecond <= 0f)
            return;

        var hands = PlayerUtil.GetHands(player);
        if (hands == null)
            return;

        EnsureFloor(hands.Length);
        var add = regenPerSecond * delta;
        for (var i = 0; i < hands.Length; i++)
        {
            var hand = hands.GetValue(i);
            if (hand == null)
                continue;

            _floor![i] = Mathf.Min(1f, _floor[i] + add);
            var current = PlayerUtil.GetGrip(hand);
            if (current < _floor[i])
                PlayerUtil.SetGrip(hand, _floor[i]);
            else
                PlayerUtil.AddGrip(hand, add);
        }
    }

    public void EnforceFloor(ENT_Player player)
    {
        var hands = PlayerUtil.GetHands(player);
        if (hands == null || _floor == null)
            return;

        for (var i = 0; i < hands.Length && i < _floor.Length; i++)
        {
            var hand = hands.GetValue(i);
            if (hand == null)
                continue;
            var g = PlayerUtil.GetGrip(hand);
            if (g < _floor[i])
                PlayerUtil.SetGrip(hand, _floor[i]);
            else if (g > _floor[i])
                _floor[i] = g;
        }
    }

    private void SnapshotFloor(ENT_Player player)
    {
        var hands = PlayerUtil.GetHands(player);
        if (hands == null)
        {
            _floor = null;
            return;
        }

        _floor = new float[hands.Length];
        for (var i = 0; i < hands.Length; i++)
        {
            var hand = hands.GetValue(i);
            _floor[i] = hand == null ? 1f : PlayerUtil.GetGrip(hand);
        }
    }

    private void EnsureFloor(int count)
    {
        if (_floor != null && _floor.Length == count)
            return;
        _floor = new float[count];
    }
}

using System.Collections;
using System.Collections.Generic;
using System.Reflection;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private bool _scanScheduled;

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host)
    {
        if (_scanScheduled)
            return;
        _scanScheduled = true;
        host.StartCoroutine(ScanLoop(host));
    }

    public void Clear()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        _scanScheduled = false;
    }

    private IEnumerator ScanLoop(MonoBehaviour host)
    {
        yield return new WaitForSeconds(2f);
        TryPlace(host);
        yield return new WaitForSeconds(3f);
        TryPlace(host);
        yield return new WaitForSeconds(5f);
        TryPlace(host);
        yield return new WaitForSeconds(10f);
        TryPlace(host);
    }

    private void TryPlace(MonoBehaviour host)
    {
        if (!ModState.InRun)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        var origin = player.transform.position;
        var minUp = _cfg.MinUpDot.Value;
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;

        PlaceFromHandholds(origin, minUp, spacing, cap);
        PlaceFromRaycasts(origin, minUp, spacing, cap);
        PlaceFromColliders(origin, minUp, spacing, cap);

        SpikeBalancePlugin.LogInfoStatic($"Spike scan: {_markers.Count} markers in scene {player.gameObject.scene.name}");
    }

    private void PlaceFromHandholds(Vector3 origin, float minUp, float spacing, int cap)
    {
        foreach (var hh in Object.FindObjectsOfType<CL_Handhold>())
            TryPoint(hh.transform.position, hh.transform.up, minUp, spacing, cap);

        var mgr = Object.FindObjectOfType<HandholdManager>();
        if (mgr == null)
            return;

        var field = AccessTools.Field(typeof(HandholdManager), "handholds");
        if (field?.GetValue(mgr) is not IEnumerable list)
            return;

        foreach (var item in list)
        {
            if (item is not CL_Handhold h)
                continue;
            TryPoint(h.transform.position, h.transform.up, minUp, spacing, cap);
        }
    }

    private void PlaceFromRaycasts(Vector3 origin, float minUp, float spacing, int cap)
    {
        const float extent = 35f;
        const int steps = 18;
        var step = extent / steps;
        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extent; z += step)
            {
                var start = origin + new Vector3(x, 8f, z);
                if (Physics.Raycast(start, Vector3.down, out var hit, 20f, ~0, QueryTriggerInteraction.Ignore))
                    TryPoint(hit.point, hit.normal, minUp, spacing, cap);
            }
        }
    }

    private void PlaceFromColliders(Vector3 origin, float minUp, float spacing, int cap)
    {
        foreach (var col in Object.FindObjectsOfType<Collider>())
        {
            if (col.isTrigger)
                continue;
            if ((col.transform.position - origin).sqrMagnitude > 50f * 50f)
                continue;

            var b = col.bounds;
            TryPoint(b.center, Vector3.up, minUp, spacing, cap);
        }
    }

    private void TryPoint(Vector3 point, Vector3 normal, float minUp, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;
        if (normal.y < minUp)
            return;

        var cell = CellKey(point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        go.transform.position = point + normal * 0.02f;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);
        go.hideFlags = HideFlags.HideAndDontSave;
        var marker = go.AddComponent<SpikeMarker>();
        _markers.Add(marker);
    }

    private static int CellKey(Vector3 p, float spacing)
    {
        var ix = Mathf.FloorToInt(p.x / spacing);
        var iy = Mathf.FloorToInt(p.y / spacing);
        var iz = Mathf.FloorToInt(p.z / spacing);
        unchecked
        {
            var hash = 17;
            hash = hash * 31 + ix;
            hash = hash * 31 + iy;
            hash = hash * 31 + iz;
            return hash;
        }
    }
}

using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod;

internal sealed class SpikeGround
{
    private readonly ModConfig _cfg;

    public SpikeGround(ModConfig cfg) => _cfg = cfg;

    public bool Check(ENT_Player player)
    {
        if (_cfg.RequireFreeHands.Value && !PlayerUtil.AreHandsFree(player))
            return false;

        var origin = player.transform.position + Vector3.up * 0.1f;
        var dist = _cfg.GroundCheckDistance.Value;
        var radius = _cfg.GroundSphereRadius.Value;

        if (Physics.SphereCast(origin, radius, Vector3.down, out var hit, dist, ~0, QueryTriggerInteraction.Collide))
            return HasMarker(hit.collider);

        if (Physics.Raycast(origin, Vector3.down, out hit, dist, ~0, QueryTriggerInteraction.Collide))
            return HasMarker(hit.collider);

        return false;
    }

    private static bool HasMarker(Collider col)
    {
        if (col.GetComponentInParent<SpikeMarker>() != null)
            return true;
        if (col.GetComponentInChildren<SpikeMarker>() != null)
            return true;
        return false;
    }
}

