namespace SpikeBalanceMod.UI;

internal sealed class ModHealthBar
{
    private Canvas? _canvas;
    private Image? _fill;
    private Text? _label;
    private const float TopMarginPx = 8f;

    public void Ensure()
    {
        if (_canvas != null)
            return;

        var go = new GameObject("SpikeBalance_HealthBar");
        Object.DontDestroyOnLoad(go);

        _canvas = go.AddComponent<Canvas>();
        _canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        _canvas.sortingOrder = 9000;
        go.AddComponent<CanvasScaler>().uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        go.AddComponent<GraphicRaycaster>();

        var barWidth = 280f;
        var barHeight = 22f;
        var sprite = WhiteSprite();

        var bgGo = new GameObject("BG");
        bgGo.transform.SetParent(go.transform, false);
        var bgRect = bgGo.AddComponent<RectTransform>();
        bgRect.anchorMin = new Vector2(0.5f, 1f);
        bgRect.anchorMax = new Vector2(0.5f, 1f);
        bgRect.pivot = new Vector2(0.5f, 1f);
        bgRect.anchoredPosition = new Vector2(0f, -TopMarginPx);
        bgRect.sizeDelta = new Vector2(barWidth, barHeight);
        var bgImg = bgGo.AddComponent<Image>();
        bgImg.sprite = sprite;
        bgImg.color = new Color(0.1f, 0.1f, 0.1f, 0.85f);

        var fillGo = new GameObject("Fill");
        fillGo.transform.SetParent(bgGo.transform, false);
        var fillRect = fillGo.AddComponent<RectTransform>();
        fillRect.anchorMin = Vector2.zero;
        fillRect.anchorMax = Vector2.one;
        fillRect.offsetMin = Vector2.zero;
        fillRect.offsetMax = Vector2.zero;
        _fill = fillGo.AddComponent<Image>();
        _fill.sprite = sprite;
        _fill.type = Image.Type.Filled;
        _fill.fillMethod = Image.FillMethod.Horizontal;
        _fill.color = new Color(0.85f, 0.15f, 0.15f, 0.95f);

        var textGo = new GameObject("HP");
        textGo.transform.SetParent(bgGo.transform, false);
        var textRect = textGo.AddComponent<RectTransform>();
        textRect.anchorMin = Vector2.zero;
        textRect.anchorMax = Vector2.one;
        textRect.offsetMin = Vector2.zero;
        textRect.offsetMax = Vector2.zero;
        _label = textGo.AddComponent<Text>();
        _label.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        _label.alignment = TextAnchor.MiddleCenter;
        _label.color = Color.white;
        _label.fontSize = 14;
        _label.fontStyle = FontStyle.Bold;
    }

    public void SetVisible(bool visible)
    {
        if (_canvas != null)
            _canvas.enabled = visible;
    }

    public void Update(float current, float max)
    {
        Ensure();
        if (_fill == null || _label == null)
            return;

        var pct = max > 0f ? Mathf.Clamp01(current / max) : 0f;
        _fill.fillAmount = pct;
        _label.text = Mathf.CeilToInt(current).ToString();
    }

    public void Destroy()
    {
        if (_canvas != null)
            Object.Destroy(_canvas.gameObject);
        _canvas = null;
        _fill = null;
        _label = null;
    }

    private static Sprite? _white;

    private static Sprite WhiteSprite()
    {
        if (_white != null)
            return _white;
        var tex = new Texture2D(1, 1);
        tex.SetPixel(0, 0, Color.white);
        tex.Apply();
        _white = Sprite.Create(tex, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f));
        return _white;
    }
}

