using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>Restricts spikes to upward-facing level geometry (handholds, terrain), not props/items.</summary>
internal static class LevelSurfaceFilter
{
    private static readonly string[] ExcludedNameTokens =
    {
        "prop", "item", "pickup", "loot", "crate", "box", "barrel", "can", "bottle",
        "key", "coin", "interactable", "grabbable", "inventory", "stash", "weapon",
        "ammo", "grenade", "battery", "fuse", "door", "elevator", "platform", "moving",
    };

    public static bool IsUpwardFacing(Vector3 normal, float minUpDot) => normal.y >= minUpDot;

    public static bool IsValidHandhold(CL_Handhold handhold)
    {
        if (handhold == null || !handhold.gameObject.activeInHierarchy)
            return false;

        if (HasExcludedAncestor(handhold.transform))
            return false;

        if (handhold.transform.up.y < 0.01f)
            return false;

        var rb = handhold.GetComponentInParent<Rigidbody>();
        if (rb != null && !rb.isKinematic)
            return false;

        return true;
    }

    public static bool IsValidRaycastHit(RaycastHit hit, float minUpDot)
    {
        if (!IsUpwardFacing(hit.normal, minUpDot))
            return false;

        if (hit.collider.GetComponentInParent<SpikeMarker>() != null)
            return false;

        if (hit.collider is TerrainCollider)
            return true;

        var handhold = hit.collider.GetComponentInParent<CL_Handhold>();
        if (handhold != null)
            return IsValidHandhold(handhold);

        return false;
    }

    private static bool HasExcludedAncestor(Transform t)
    {
        for (var cur = t; cur != null; cur = cur.parent)
        {
            var name = cur.name.ToLowerInvariant();
            foreach (var token in ExcludedNameTokens)
            {
                if (name.Contains(token))
                    return true;
            }

            if (cur.GetComponent<Rigidbody>() is { isKinematic: false })
                return true;
        }

        return false;
    }
}

using System.Collections;
using System.Collections.Generic;
using System.Reflection;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private bool _scanScheduled;

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host)
    {
        if (_scanScheduled)
            return;
        _scanScheduled = true;
        host.StartCoroutine(ScanLoop(host));
    }

    public void Clear()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        _scanScheduled = false;
    }

    private IEnumerator ScanLoop(MonoBehaviour host)
    {
        yield return new WaitForSeconds(2f);
        TryPlace();
        yield return new WaitForSeconds(3f);
        TryPlace();
        yield return new WaitForSeconds(5f);
        TryPlace();
        yield return new WaitForSeconds(10f);
        TryPlace();
    }

    private void TryPlace()
    {
        if (!ModState.InRun)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        var origin = player.transform.position;
        var minUp = _cfg.MinUpDot.Value;
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;

        var placedBefore = _markers.Count;
        PlaceFromHandholds(origin, minUp, spacing, cap);
        PlaceFromTerrainRaycasts(origin, minUp, spacing, cap);

        if (_markers.Count != placedBefore)
            SpikeBalancePlugin.LogInfoStatic($"Spike scan: {_markers.Count} markers (level surfaces only)");
    }

    private void PlaceFromHandholds(Vector3 origin, float minUp, float spacing, int cap)
    {
        var seen = new HashSet<CL_Handhold>();
        foreach (var hh in Object.FindObjectsOfType<CL_Handhold>())
            TryHandhold(hh, origin, minUp, spacing, cap, seen);

        var mgr = Object.FindObjectOfType<HandholdManager>();
        if (mgr == null)
            return;

        var field = AccessTools.Field(typeof(HandholdManager), "handholds");
        if (field?.GetValue(mgr) is not IEnumerable list)
            return;

        foreach (var item in list)
        {
            if (item is CL_Handhold h)
                TryHandhold(h, origin, minUp, spacing, cap, seen);
        }
    }

    private void TryHandhold(CL_Handhold hh, Vector3 origin, float minUp, float spacing, int cap, HashSet<CL_Handhold> seen)
    {
        if (!seen.Add(hh))
            return;
        if (_markers.Count >= cap)
            return;
        if (!LevelSurfaceFilter.IsValidHandhold(hh))
            return;
        if ((hh.transform.position - origin).sqrMagnitude > 55f * 55f)
            return;

        SampleHandholdSurface(hh, minUp, spacing, cap);
    }

    private void SampleHandholdSurface(CL_Handhold hh, float minUp, float spacing, int cap)
    {
        var colliders = hh.GetComponentsInChildren<Collider>(includeInactive: false);
        if (colliders.Length == 0)
        {
            if (hh.transform.up.y >= minUp)
                TryPoint(hh.transform.position, hh.transform.up, minUp, spacing, cap);
            return;
        }

        foreach (var col in colliders)
        {
            if (col.isTrigger || col.GetComponentInParent<SpikeMarker>() != null)
                continue;

            var b = col.bounds;
            var size = b.size;
            if (size.x < 0.25f && size.z < 0.25f)
                continue;

            SampleBoundsTop(col, b, minUp, spacing, cap);
        }
    }

    private void SampleBoundsTop(Collider col, Bounds b, float minUp, float spacing, int cap)
    {
        var y = b.max.y + 0.05f;
        var xs = new[] { b.center.x, b.min.x + 0.1f, b.max.x - 0.1f };
        var zs = new[] { b.center.z, b.min.z + 0.1f, b.max.z - 0.1f };

        foreach (var x in xs)
        {
            foreach (var z in zs)
            {
                var probe = new Vector3(x, y + 1.5f, z);
                if (!Physics.Raycast(probe, Vector3.down, out var hit, 3f, ~0, QueryTriggerInteraction.Ignore))
                    continue;
                if (hit.collider != col && hit.collider.transform != col.transform &&
                    !hit.collider.transform.IsChildOf(col.transform))
                    continue;
                if (!LevelSurfaceFilter.IsValidRaycastHit(hit, minUp))
                    continue;
                TryPoint(hit.point, hit.normal, minUp, spacing, cap);
            }
        }
    }

    /// <summary>Terrain only — handhold surfaces are covered by <see cref="PlaceFromHandholds"/>.</summary>
    private void PlaceFromTerrainRaycasts(Vector3 origin, float minUp, float spacing, int cap)
    {
        const float extent = 35f;
        const int steps = 14;
        var step = extent / steps;
        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extent; z += step)
            {
                var start = origin + new Vector3(x, 12f, z);
                if (!Physics.Raycast(start, Vector3.down, out var hit, 25f, ~0, QueryTriggerInteraction.Ignore))
                    continue;
                if (hit.collider is not TerrainCollider)
                    continue;
                if (!LevelSurfaceFilter.IsValidRaycastHit(hit, minUp))
                    continue;
                TryPoint(hit.point, hit.normal, minUp, spacing, cap);
            }
        }
    }

    private void TryPoint(Vector3 point, Vector3 normal, float minUp, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;
        if (!LevelSurfaceFilter.IsUpwardFacing(normal, minUp))
            return;

        var cell = CellKey(point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        go.transform.position = point + normal * 0.02f;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);
        go.hideFlags = HideFlags.HideAndDontSave;
        var col = go.AddComponent<SphereCollider>();
        col.isTrigger = true;
        col.radius = Mathf.Max(0.35f, spacing * 0.35f);
        col.center = Vector3.zero;
        var marker = go.AddComponent<SpikeMarker>();
        _markers.Add(marker);
    }

    private static int CellKey(Vector3 p, float spacing)
    {
        var ix = Mathf.FloorToInt(p.x / spacing);
        var iy = Mathf.FloorToInt(p.y / spacing);
        var iz = Mathf.FloorToInt(p.z / spacing);
        unchecked
        {
            var hash = 17;
            hash = hash * 31 + ix;
            hash = hash * 31 + iy;
            hash = hash * 31 + iz;
            return hash;
        }
    }
}

