using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>
/// White Knuckle levels are built from <see cref="CL_Handhold"/> volumes (walls, floors, ropes, ledges).
/// Only handholds whose surface normal faces up are walkable floors for spike damage.
/// </summary>
internal static class HandholdSurface
{
    public static Vector3 GetSurfaceNormal(CL_Handhold handhold)
    {
        if (handhold.modules != null)
        {
            foreach (var module in handhold.modules)
            {
                if (module is not HandholdModule_LimitDirection limit)
                    continue;
                if (limit.normal.sqrMagnitude > 0.01f)
                    return limit.normal.normalized;
            }
        }

        return handhold.transform.up.normalized;
    }

    public static HandholdKind Classify(CL_Handhold handhold, float minUpDot)
    {
        if (handhold is CL_Handhold_Rope)
            return HandholdKind.Rope;

        var n = GetSurfaceNormal(handhold);
        if (n.y >= minUpDot)
            return HandholdKind.Floor;
        if (n.y <= -minUpDot)
            return HandholdKind.Ceiling;
        return HandholdKind.Wall;
    }

    public static bool IsSpikeSurface(CL_Handhold handhold, float minUpDot) =>
        Classify(handhold, minUpDot) == HandholdKind.Floor && LevelSurfaceFilter.IsValidHandhold(handhold);
}

internal enum HandholdKind
{
    Floor,
    Wall,
    Ceiling,
    Rope,
}

using System.Collections.Generic;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>Logs how handholds in the current scene break down (floor / wall / rope).</summary>
internal static class HandholdSurvey
{
    public static void Log( IEnumerable<CL_Handhold> handholds, float minUpDot, int markerCount)
    {
        var floor = 0;
        var wall = 0;
        var ceiling = 0;
        var rope = 0;

        foreach (var hh in handholds)
        {
            switch (HandholdSurface.Classify(hh, minUpDot))
            {
                case HandholdKind.Floor: floor++; break;
                case HandholdKind.Wall: wall++; break;
                case HandholdKind.Ceiling: ceiling++; break;
                case HandholdKind.Rope: rope++; break;
            }
        }

        var scene = PlayerUtil.FindPlayer()?.gameObject.scene.name ?? "?";
        SpikeBalancePlugin.LogInfoStatic(
            $"[{scene}] handholds: floor={floor} wall={wall} ceiling={ceiling} rope={rope} | spike markers={markerCount}");
    }
}

using System.Collections;
using System.Collections.Generic;
using System.Reflection;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private bool _scanScheduled;

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host)
    {
        if (_scanScheduled)
            return;
        _scanScheduled = true;
        host.StartCoroutine(ScanLoop());
    }

    public void Clear()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        _scanScheduled = false;
    }

    private IEnumerator ScanLoop()
    {
        yield return new WaitForSeconds(2f);
        TryPlace();
        yield return new WaitForSeconds(3f);
        TryPlace();
        yield return new WaitForSeconds(5f);
        TryPlace();
        yield return new WaitForSeconds(10f);
        TryPlace();
        yield return new WaitForSeconds(15f);
        TryPlace();
    }

    private void TryPlace()
    {
        if (!ModState.InRun)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        var origin = player.transform.position;
        var minUp = _cfg.MinUpDot.Value;
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;

        var handholds = CollectHandholds();
        var before = _markers.Count;

        foreach (var hh in handholds)
            PlaceOnFloorHandhold(hh, origin, minUp, spacing, cap);

        PlaceFromFloorRaycasts(origin, minUp, spacing, cap);
        PlaceFromTerrainRaycasts(origin, minUp, spacing, cap);

        if (_cfg.DebugLog.Value || _markers.Count != before)
            HandholdSurvey.Log(handholds, minUp, _markers.Count);
    }

    private List<CL_Handhold> CollectHandholds()
    {
        var list = new List<CL_Handhold>();
        var seen = new HashSet<int>();

        foreach (var hh in Object.FindObjectsOfType<CL_Handhold>(includeInactive: true))
            AddHandhold(list, seen, hh);

        var mgr = Object.FindObjectOfType<HandholdManager>();
        if (mgr != null)
        {
            var field = AccessTools.Field(typeof(HandholdManager), "handholds");
            if (field?.GetValue(mgr) is IEnumerable items)
            {
                foreach (var item in items)
                {
                    if (item is CL_Handhold h)
                        AddHandhold(list, seen, h);
                }
            }
        }

        return list;
    }

    private static void AddHandhold(List<CL_Handhold> list, HashSet<int> seen, CL_Handhold? hh)
    {
        if (hh == null)
            return;
        if (!seen.Add(hh.GetInstanceID()))
            return;
        list.Add(hh);
    }

    /// <summary>Only floor-class handholds (surface normal points up), not wall climb volumes.</summary>
    private void PlaceOnFloorHandhold(CL_Handhold hh, Vector3 origin, float minUp, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;
        if (!HandholdSurface.IsSpikeSurface(hh, minUp))
            return;
        if ((hh.transform.position - origin).sqrMagnitude > 70f * 70f)
            return;

        var normal = HandholdSurface.GetSurfaceNormal(hh);
        TryPoint(hh.transform.position, normal, minUp, spacing, cap);

        var bounds = GetHandholdBounds(hh);
        if (bounds.size.sqrMagnitude < 0.01f)
            return;

        SampleFloorBounds(bounds, normal, minUp, spacing, cap);
    }

    private static Bounds GetHandholdBounds(CL_Handhold hh)
    {
        var bounds = new Bounds(hh.transform.position, Vector3.zero);
        var hasBounds = false;

        foreach (var col in hh.GetComponentsInChildren<Collider>(includeInactive: false))
        {
            if (col.GetComponentInParent<SpikeMarker>() != null)
                continue;
            if (!hasBounds)
            {
                bounds = col.bounds;
                hasBounds = true;
            }
            else
                bounds.Encapsulate(col.bounds);
        }

        if (hasBounds)
            return bounds;

        foreach (var rend in hh.GetComponentsInChildren<Renderer>(includeInactive: false))
        {
            if (!hasBounds)
            {
                bounds = rend.bounds;
                hasBounds = true;
            }
            else
                bounds.Encapsulate(rend.bounds);
        }

        return bounds;
    }

    private void SampleFloorBounds(Bounds b, Vector3 normal, float minUp, float spacing, int cap)
    {
        if (!LevelSurfaceFilter.IsUpwardFacing(normal, minUp))
            return;

        var y = b.max.y;
        var step = Mathf.Max(spacing * 0.5f, 0.75f);
        for (var x = b.min.x; x <= b.max.x; x += step)
        {
            for (var z = b.min.z; z <= b.max.z; z += step)
                TryPoint(new Vector3(x, y, z), normal, minUp, spacing, cap);
        }
    }

    private void PlaceFromFloorRaycasts(Vector3 origin, float minUp, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;

        const float extent = 40f;
        const int steps = 20;
        var step = extent / steps;

        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extent; z += step)
            {
                var start = origin + new Vector3(x, 14f, z);
                if (!Physics.Raycast(start, Vector3.down, out var hit, 30f, ~0, QueryTriggerInteraction.Collide))
                    continue;

                var handhold = hit.collider.GetComponentInParent<CL_Handhold>();
                if (handhold == null)
                    continue;
                if (!HandholdSurface.IsSpikeSurface(handhold, minUp))
                    continue;
                if (!LevelSurfaceFilter.IsUpwardFacing(hit.normal, minUp))
                    continue;

                TryPoint(hit.point, hit.normal, minUp, spacing, cap);
            }
        }
    }

    private void PlaceFromTerrainRaycasts(Vector3 origin, float minUp, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;

        const float extent = 40f;
        const int steps = 14;
        var step = extent / steps;

        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extents; z += step)
            {
                var start = origin + new Vector3(x, 14f, z);
                if (!Physics.Raycast(start, Vector3.down, out var hit, 30f, ~0, QueryTriggerInteraction.Ignore))
                    continue;
                if (hit.collider is not TerrainCollider)
                    continue;
                if (!LevelSurfaceFilter.IsValidPlacementHit(hit, minUp))
                    continue;
                TryPoint(hit.point, hit.normal, minUp, spacing, cap);
            }
        }
    }

    private void TryPoint(Vector3 point, Vector3 normal, float minUp, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;
        if (!LevelSurfaceFilter.IsUpwardFacing(normal, minUp))
            return;

        var cell = CellKey(point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        go.transform.position = point + normal.normalized * 0.03f;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);
        go.hideFlags = HideFlags.HideAndDontSave;

        var col = go.AddComponent<SphereCollider>();
        col.isTrigger = true;
        col.radius = Mathf.Max(0.4f, spacing * 0.4f);

        _markers.Add(go.AddComponent<SpikeMarker>());
    }

    private static int CellKey(Vector3 p, float spacing)
    {
        unchecked
        {
            var hash = 17;
            hash = hash * 31 + Mathf.FloorToInt(p.x / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.y / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.z / spacing);
            return hash;
        }
    }
}

using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>Upward-facing static level meshes — not handhold climb volumes or props.</summary>
internal static class LevelSurfaceFilter
{
    public static float TiltDegreesToMinUpDot(float maxTiltDegrees) =>
        Mathf.Cos(maxTiltDegrees * Mathf.Deg2Rad);

    public static bool IsUpwardFacing(Vector3 normal, float minUpDot) => normal.y >= minUpDot;

    public static bool IsValidGeometryHit(RaycastHit hit, float minUpDot)
    {
        if (!IsUpwardFacing(hit.normal, minUpDot))
            return false;

        return IsValidGeometryCollider(hit.collider);
    }

    public static bool IsValidGeometryCollider(Collider col)
    {
        if (col == null || col.isTrigger)
            return false;

        if (col.GetComponentInParent<SpikeMarker>() != null)
            return false;

        // Handholds are climb helpers, not the render/collision floor mesh.
        if (col.GetComponentInParent<CL_Handhold>() != null)
            return false;

        if (col.GetComponentInParent<ENT_Player>() != null)
            return false;

        var rb = col.attachedRigidbody;
        if (rb != null && !rb.isKinematic)
            return false;

        var root = col.transform.root;
        if (root.GetComponentInParent<ENT_Player>() != null)
            return false;

        return true;
    }
}

using System.Collections;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>Places spikes on static upward-facing level colliders via raycasts (not handholds).</summary>
internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private bool _scanScheduled;

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host)
    {
        if (_scanScheduled)
            return;
        _scanScheduled = true;
        host.StartCoroutine(ScanLoop());
    }

    public void Clear()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        _scanScheduled = false;
    }

    private IEnumerator ScanLoop()
    {
        yield return new WaitForSeconds(2f);
        TryPlace();
        yield return new WaitForSeconds(3f);
        TryPlace();
        yield return new WaitForSeconds(5f);
        TryPlace();
        yield return new WaitForSeconds(10f);
        TryPlace();
        yield return new WaitForSeconds(15f);
        TryPlace();
    }

    private void TryPlace()
    {
        if (!ModState.InRun)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        var origin = player.transform.position;
        var minUp = LevelSurfaceFilter.TiltDegreesToMinUpDot(_cfg.MaxSurfaceTiltDegrees.Value);
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;
        var before = _markers.Count;

        ScanGeometryRaycasts(origin, minUp, spacing, cap);

        if (_cfg.DebugLog.Value || _markers.Count != before)
        {
            SpikeBalancePlugin.LogInfoStatic(
                $"Spike scan (geometry): tilt<={_cfg.MaxSurfaceTiltDegrees.Value:F0}° minUp={minUp:F3} markers={_markers.Count} (+{_markers.Count - before})");
        }
    }

    private void ScanGeometryRaycasts(Vector3 origin, float minUp, float spacing, int cap)
    {
        const float extent = 42f;
        const int steps = 22;
        var step = extent / steps;
        var mask = ~0;

        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extent; z += step)
            {
                if (_markers.Count >= cap)
                    return;

                var start = origin + new Vector3(x, 16f, z);
                if (!Physics.Raycast(start, Vector3.down, out var hit, 32f, mask, QueryTriggerInteraction.Ignore))
                    continue;

                if (!LevelSurfaceFilter.IsValidGeometryHit(hit, minUp))
                    continue;

                TryPoint(hit.point, hit.normal, spacing, cap);
            }
        }
    }

    private void TryPoint(Vector3 surfacePoint, Vector3 normal, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;

        var n = normal.normalized;
        var inset = _cfg.SurfaceInset.Value;
        var point = surfacePoint - n * inset;

        var cell = CellKey(point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        go.transform.position = point;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, n);
        go.hideFlags = HideFlags.HideAndDontSave;

        var col = go.AddComponent<SphereCollider>();
        col.isTrigger = true;
        col.radius = Mathf.Clamp(spacing * 0.22f, 0.22f, 0.38f);

        _markers.Add(go.AddComponent<SpikeMarker>());
    }

    private static int CellKey(Vector3 p, float spacing)
    {
        unchecked
        {
            var hash = 17;
            hash = hash * 31 + Mathf.FloorToInt(p.x / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.y / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.z / spacing);
            return hash;
        }
    }
}

using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod;

internal sealed class SpikeGround
{
    private readonly ModConfig _cfg;

    public SpikeGround(ModConfig cfg) => _cfg = cfg;

    public bool Check(ENT_Player player)
    {
        if (_cfg.RequireFreeHands.Value && !PlayerUtil.AreHandsFree(player))
            return false;

        var feet = player.transform.position;
        var origin = feet + Vector3.up * 0.05f;
        var dist = _cfg.GroundCheckDistance.Value;
        var radius = _cfg.GroundSphereRadius.Value;
        var minUp = LevelSurfaceFilter.TiltDegreesToMinUpDot(_cfg.MaxSurfaceTiltDegrees.Value);

        if (Physics.SphereCast(origin, radius, Vector3.down, out var hit, dist, ~0, QueryTriggerInteraction.Collide))
        {
            if (IsStandingOnMarker(hit, feet, minUp))
                return true;
        }

        if (Physics.Raycast(origin, Vector3.down, out hit, dist, ~0, QueryTriggerInteraction.Collide))
            return IsStandingOnMarker(hit, feet, minUp);

        return false;
    }

    /// <summary>Marker must be under the feet, not beside a wall where the body clips.</summary>
    private static bool IsStandingOnMarker(RaycastHit hit, Vector3 feet, float minUp)
    {
        if (hit.collider.GetComponentInParent<SpikeMarker>() == null)
            return false;

        if (!LevelSurfaceFilter.IsUpwardFacing(hit.normal, minUp * 0.9f))
            return false;

        var delta = hit.point - feet;
        if (delta.y > 0.35f || delta.y < -0.5f)
            return false;

        var horizontal = new Vector2(delta.x, delta.z).magnitude;
        return horizontal <= 0.55f;
    }
}

