using System.Collections.Generic;

namespace SpikeBalanceMod.Spikes;

internal static class SpikeMarkerRegistry
{
    private static readonly List<SpikeMarker> Markers = new();

    public static IReadOnlyList<SpikeMarker> Active => Markers;

    public static void Register(SpikeMarker marker)
    {
        if (!Markers.Contains(marker))
            Markers.Add(marker);
    }

    public static void Unregister(SpikeMarker marker) => Markers.Remove(marker);

    public static void Clear()
    {
        Markers.Clear();
    }
}

using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public sealed class SpikeMarker : MonoBehaviour
{
    public float ContactRadius { get; private set; }

    internal void Init(float contactRadius) => ContactRadius = contactRadius;

    private void OnEnable() => SpikeMarkerRegistry.Register(this);

    private void OnDisable() => SpikeMarkerRegistry.Unregister(this);
}

using UnityEngine;

namespace SpikeBalanceMod.Spikes;

internal static class SpikeVisual
{
    private static Material? _mat;

    public static void Attach(GameObject host, Vector3 surfaceNormal, float spacing, bool enabled)
    {
        if (!enabled)
            return;

        var mat = GetMaterial();
        var n = surfaceNormal.normalized;
        var scale = Mathf.Clamp(spacing * 0.35f, 0.5f, 1.1f);

        for (var i = 0; i < 5; i++)
        {
            var spike = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
            spike.name = "SpikeVisual";
            spike.transform.SetParent(host.transform, false);

            var angle = i * Mathf.PI * 2f / 5f;
            var offset = new Vector3(Mathf.Cos(angle), 0f, Mathf.Sin(angle)) * scale * 0.22f;
            spike.transform.localPosition = offset + Vector3.up * 0.04f;
            spike.transform.localScale = new Vector3(0.06f, 0.14f, 0.06f);
            spike.transform.rotation = Quaternion.FromToRotation(Vector3.up, n) * Quaternion.Euler(0f, angle * Mathf.Rad2Deg, 0f);

            var col = spike.GetComponent<Collider>();
            if (col != null)
                Object.Destroy(col);

            var rend = spike.GetComponent<Renderer>();
            if (rend != null)
                rend.sharedMaterial = mat;
        }

        var pad = GameObject.CreatePrimitive(PrimitiveType.Cylinder);
        pad.name = "SpikePad";
        pad.transform.SetParent(host.transform, false);
        pad.transform.localPosition = Vector3.up * 0.01f;
        pad.transform.localScale = new Vector3(scale * 0.55f, 0.01f, scale * 0.55f);
        pad.transform.rotation = Quaternion.FromToRotation(Vector3.up, n);
        Object.Destroy(pad.GetComponent<Collider>());
        pad.GetComponent<Renderer>()!.sharedMaterial = mat;
    }

    private static Material GetMaterial()
    {
        if (_mat != null)
            return _mat;

        var shader = Shader.Find("Sprites/Default") ?? Shader.Find("Unlit/Color");
        _mat = new Material(shader!) { color = new Color(0.95f, 0.12f, 0.08f, 0.9f) };
        return _mat;
    }
}

using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod;

internal sealed class SpikeGround
{
    private readonly ModConfig _cfg;

    public SpikeGround(ModConfig cfg) => _cfg = cfg;

    public bool Check(ENT_Player player)
    {
        if (_cfg.RequireFreeHands.Value && !PlayerUtil.AreHandsFree(player))
            return false;

        var feet = player.transform.position;
        var extra = _cfg.GroundSphereRadius.Value;

        foreach (var marker in SpikeMarkerRegistry.Active)
        {
            if (marker == null)
                continue;

            var center = marker.transform.position;
            var delta = feet - center;

            if (delta.y > 0.85f || delta.y < -0.55f)
                continue;

            var horizontal = new Vector2(delta.x, delta.z).magnitude;
            if (horizontal <= marker.ContactRadius + extra)
                return true;
        }

        return OverlapTriggersNearFeet(feet, extra);
    }

    private static bool OverlapTriggersNearFeet(Vector3 feet, float radius)
    {
        var hits = Physics.OverlapSphere(feet + Vector3.up * 0.15f, radius + 0.15f, ~0, QueryTriggerInteraction.Collide);
        foreach (var col in hits)
        {
            if (col.GetComponent<SpikeMarker>() != null)
                return true;
        }

        return false;
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>Places spikes on static upward-facing level colliders via raycasts (not handholds).</summary>
internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private bool _scanScheduled;

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host)
    {
        if (_scanScheduled)
            return;
        _scanScheduled = true;
        host.StartCoroutine(ScanLoop());
    }

    public void Clear()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        SpikeMarkerRegistry.Clear();
        _scanScheduled = false;
    }

    private IEnumerator ScanLoop()
    {
        yield return new WaitForSeconds(2f);
        TryPlace();
        yield return new WaitForSeconds(3f);
        TryPlace();
        yield return new WaitForSeconds(5f);
        TryPlace();
        yield return new WaitForSeconds(10f);
        TryPlace();
        yield return new WaitForSeconds(15f);
        TryPlace();
    }

    private void TryPlace()
    {
        if (!ModState.InRun)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        var origin = player.transform.position;
        var minUp = LevelSurfaceFilter.TiltDegreesToMinUpDot(_cfg.MaxSurfaceTiltDegrees.Value);
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;
        var before = _markers.Count;

        ScanGeometryRaycasts(origin, minUp, spacing, cap);

        if (_cfg.DebugLog.Value || _markers.Count != before)
        {
            SpikeBalancePlugin.LogInfoStatic(
                $"Spike scan: tilt<={_cfg.MaxSurfaceTiltDegrees.Value:F0}° markers={_markers.Count} (+{_markers.Count - before})");
        }
    }

    private void ScanGeometryRaycasts(Vector3 origin, float minUp, float spacing, int cap)
    {
        const float extent = 42f;
        const int steps = 22;
        var step = extent / steps;

        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extent; z += step)
            {
                if (_markers.Count >= cap)
                    return;

                var start = origin + new Vector3(x, 16f, z);
                if (!Physics.Raycast(start, Vector3.down, out var hit, 32f, ~0, QueryTriggerInteraction.Ignore))
                    continue;

                if (!LevelSurfaceFilter.IsValidGeometryHit(hit, minUp))
                    continue;

                TryPoint(hit.point, hit.normal, spacing, cap);
            }
        }
    }

    private void TryPoint(Vector3 surfacePoint, Vector3 normal, float spacing, int cap)
    {
        if (_markers.Count >= cap)
            return;

        var n = normal.normalized;
        var radius = Mathf.Clamp(spacing * 0.3f, 0.3f, 0.5f);
        var lift = _cfg.SurfaceOffsetAbove.Value + radius * 0.35f;
        var point = surfacePoint + n * lift;

        var cell = CellKey(point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        go.transform.position = point;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, n);

        var col = go.AddComponent<SphereCollider>();
        col.isTrigger = true;
        col.radius = radius;

        var marker = go.AddComponent<SpikeMarker>();
        marker.Init(radius);
        _markers.Add(marker);

        SpikeVisual.Attach(go, n, spacing, _cfg.ShowSpikeVisuals.Value);
    }

    private static int CellKey(Vector3 p, float spacing)
    {
        unchecked
        {
            var hash = 17;
            hash = hash * 31 + Mathf.FloorToInt(p.x / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.y / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.z / spacing);
            return hash;
        }
    }
}

