using System;
using System.Reflection;
using HarmonyLib;
using UnityEngine;

namespace SpikeBalanceMod;

internal static class PlayerUtil
{
    private static readonly FieldInfo RunHasEndedField = AccessTools.Field(typeof(CL_GameManager), "runHasEnded")!;
    private static readonly FieldInfo LocalPlayerField = AccessTools.Field(typeof(CL_GameManager), "localPlayer")!;
    private static readonly FieldInfo IsGroundedField = AccessTools.Field(typeof(ENT_Player), "isGrounded")!;

    private static readonly FieldInfo HandsField = AccessTools.Field(typeof(ENT_Player), "hands")!;
    private static readonly Type HandType = AccessTools.Inner(typeof(ENT_Player), "Hand")!;
    private static readonly FieldInfo GripField = AccessTools.Field(HandType, "gripStrength")!;
    private static readonly FieldInfo InfiniteStaminaField = AccessTools.Field(typeof(ENT_Player), "infiniteStamina")!;
    private static readonly MethodInfo AddGripMethod = AccessTools.Method(HandType, "AddGripStrength")!;
    private static readonly MethodInfo SetGripMethod = AccessTools.Method(HandType, "SetGripStrength")!;

    public static ENT_Player? FindPlayer()
    {
        var gm = UnityEngine.Object.FindObjectOfType<CL_GameManager>();
        if (gm != null)
        {
            var lp = LocalPlayerField.GetValue(gm) as ENT_Player;
            if (lp != null && lp.gameObject.activeInHierarchy)
                return lp;
        }

        foreach (var p in UnityEngine.Object.FindObjectsOfType<ENT_Player>())
        {
            if (p != null && p.gameObject.activeInHierarchy && !IsMenuScene(p.gameObject.scene.name))
                return p;
        }

        return null;
    }

    public static bool IsMenuScene(string sceneName)
    {
        if (string.IsNullOrEmpty(sceneName))
            return true;
        var n = sceneName.ToLowerInvariant();
        return n.Contains("menu") || n.Contains("title") || n.Contains("bootstrap") || n == "init";
    }

    public static bool IsInActiveRun(ENT_Player? player)
    {
        if (player == null || !player.gameObject.activeInHierarchy)
            return false;
        if (IsMenuScene(player.gameObject.scene.name))
            return false;

        var gm = UnityEngine.Object.FindObjectOfType<CL_GameManager>();
        if (gm != null && (bool)RunHasEndedField.GetValue(gm)!)
            return false;

        return true;
    }

    /// <summary>World position near the feet, not the player root (usually chest height).</summary>
    public static Vector3 GetFeetPosition(ENT_Player player)
    {
        var root = player.transform.position;
        var origin = root + Vector3.up * 0.25f;

        if (Physics.Raycast(origin, Vector3.down, out var hit, 2.5f, ~0, QueryTriggerInteraction.Ignore))
            return hit.point + Vector3.up * 0.08f;

        if ((bool)IsGroundedField.GetValue(player)!)
            return root + Vector3.down * 1.45f;

        return root + Vector3.down * 0.9f;
    }

    public static Array? GetHands(ENT_Player player) => HandsField.GetValue(player) as Array;

    public static float GetGrip(object hand) => (float)GripField.GetValue(hand)!;

    public static void SetGrip(object hand, float value) => GripField.SetValue(hand, Mathf.Clamp01(value));

    public static void AddGrip(object hand, float amount)
    {
        if (amount <= 0f)
            return;
        AddGripMethod.Invoke(hand, new object[] { amount });
    }

    public static void ForceGrip(object hand, float value) => SetGripMethod.Invoke(hand, new object[] { value });

    public static bool GetInfiniteStamina(ENT_Player player) => (bool)InfiniteStaminaField.GetValue(player)!;

    public static void SetInfiniteStamina(ENT_Player player, bool value) => InfiniteStaminaField.SetValue(player, value);

    public static bool AreHandsFree(ENT_Player player)
    {
        var hands = GetHands(player);
        if (hands == null)
            return true;
        foreach (var h in hands)
        {
            if (h == null)
                continue;
            if (GetGrip(h) < 0.99f)
                return false;
        }
        return true;
    }
}

using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod;

internal sealed class SpikeGround
{
    private readonly ModConfig _cfg;

    public SpikeGround(ModConfig cfg) => _cfg = cfg;

    public bool Check(ENT_Player player)
    {
        if (_cfg.RequireFreeHands.Value && !PlayerUtil.AreHandsFree(player))
            return false;

        var feet = PlayerUtil.GetFeetPosition(player);
        var extra = _cfg.GroundSphereRadius.Value;

        foreach (var marker in SpikeMarkerRegistry.Active)
        {
            if (marker == null)
                continue;

            var center = marker.transform.position;
            var toFeet = feet - center;
            var feetAboveMarker = toFeet.y;

            if (feetAboveMarker < -0.25f || feetAboveMarker > 1.75f)
                continue;

            var horizontal = new Vector2(toFeet.x, toFeet.z).magnitude;
            if (horizontal <= marker.ContactRadius + extra)
                return true;
        }

        return OverlapTriggersNearFeet(feet, extra);
    }

    private static bool OverlapTriggersNearFeet(Vector3 feet, float radius)
    {
        var hits = Physics.OverlapSphere(feet, radius + 0.25f, ~0, QueryTriggerInteraction.Collide);
        foreach (var col in hits)
        {
            if (col.GetComponent<SpikeMarker>() != null)
                return true;
        }

        return false;
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod.Spikes;

internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private Coroutine? _scanCoroutine;
    private string _scanScene = "";

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host) => ScheduleScans(host, clearExisting: true);

    public void OnRoomGeometryLoaded(MonoBehaviour host)
    {
        SpikeBalancePlugin.LogInfoStatic("Room geometry loaded — scanning for spike surfaces.");
        ScheduleScans(host, clearExisting: true);
    }

    private void ScheduleScans(MonoBehaviour host, bool clearExisting)
    {
        if (clearExisting)
            ClearMarkers();

        if (_scanCoroutine != null)
            host.StopCoroutine(_scanCoroutine);

        _scanCoroutine = host.StartCoroutine(ScanLoop(host));
    }

    public void Clear()
    {
        ClearMarkers();
        _scanCoroutine = null;
    }

    private void ClearMarkers()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        SpikeMarkerRegistry.Clear();
        _scanScene = "";
    }

    private IEnumerator ScanLoop(MonoBehaviour host)
    {
        yield return new WaitForSeconds(1f);
        TryPlace();
        yield return new WaitForSeconds(2f);
        TryPlace();
        yield return new WaitForSeconds(3f);
        TryPlace();
        yield return new WaitForSeconds(5f);
        TryPlace();
        yield return new WaitForSeconds(8f);
        TryPlace();
        _scanCoroutine = null;
    }

    private void TryPlace()
    {
        if (!ModState.InRun)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        var scene = player.gameObject.scene;
        if (!scene.IsValid())
            return;

        if (_scanScene != scene.name)
        {
            _placedCells.Clear();
            _scanScene = scene.name;
        }

        var origin = player.transform.position;
        var minUp = LevelSurfaceFilter.TiltDegreesToMinUpDot(_cfg.MaxSurfaceTiltDegrees.Value);
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;
        var before = _markers.Count;

        ScanGeometryRaycasts(origin, minUp, spacing, cap, scene);

        SpikeBalancePlugin.LogInfoStatic(
            $"Spike scan [{scene.name}]: markers={_markers.Count} (+{_markers.Count - before}) at player ({origin.x:F0},{origin.y:F0},{origin.z:F0})");
    }

    private void ScanGeometryRaycasts(Vector3 origin, float minUp, float spacing, int cap, Scene scene)
    {
        const float extent = 45f;
        const int steps = 24;
        var step = extent / steps;
        var sceneId = scene.handle;

        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extent; z += step)
            {
                if (_markers.Count >= cap)
                    return;

                var start = origin + new Vector3(x, 18f, z);
                if (!Physics.Raycast(start, Vector3.down, out var hit, 36f, ~0, QueryTriggerInteraction.Ignore))
                    continue;

                if (!hit.collider.gameObject.scene.Equals(scene))
                    continue;

                if (!LevelSurfaceFilter.IsValidGeometryHit(hit, minUp))
                    continue;

                TryPoint(hit.point, hit.normal, spacing, cap, sceneId);
            }
        }
    }

    private void TryPoint(Vector3 surfacePoint, Vector3 normal, float spacing, int cap, int sceneId)
    {
        if (_markers.Count >= cap)
            return;

        var n = normal.normalized;
        var radius = Mathf.Clamp(spacing * 0.32f, 0.32f, 0.55f);
        var lift = _cfg.SurfaceOffsetAbove.Value + radius * 0.25f;
        var point = surfacePoint + n * lift;

        var cell = CellKey(sceneId, point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        go.transform.position = point;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, n);

        var col = go.AddComponent<SphereCollider>();
        col.isTrigger = true;
        col.radius = radius;

        var marker = go.AddComponent<SpikeMarker>();
        marker.Init(radius);
        _markers.Add(marker);

        SpikeVisual.Attach(go, n, spacing, _cfg.ShowSpikeVisuals.Value);
    }

    private static int CellKey(int sceneId, Vector3 p, float spacing)
    {
        unchecked
        {
            var hash = sceneId * 31 + 17;
            hash = hash * 31 + Mathf.FloorToInt(p.x / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.y / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.z / spacing);
            return hash;
        }
    }
}

