using UnityEngine;
using UnityEngine.UI;

namespace SpikeBalanceMod.UI;

internal sealed class ModHealthBar
{
    private GameObject? _root;
    private Canvas? _canvas;
    private Image? _fill;
    private Text? _label;
    private const float TopMarginPx = 8f;

    public void Ensure()
    {
        if (_root != null)
            return;

        _root = new GameObject("SpikeBalance_HealthBar");
        Object.DontDestroyOnLoad(_root);

        _canvas = _root.AddComponent<Canvas>();
        _canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        _canvas.sortingOrder = 9000;
        _root.AddComponent<CanvasScaler>().uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
        _root.AddComponent<GraphicRaycaster>();

        var barWidth = 280f;
        var barHeight = 22f;
        var sprite = WhiteSprite();

        var bgGo = new GameObject("BG");
        bgGo.transform.SetParent(_root.transform, false);
        var bgRect = bgGo.AddComponent<RectTransform>();
        bgRect.anchorMin = new Vector2(0.5f, 1f);
        bgRect.anchorMax = new Vector2(0.5f, 1f);
        bgRect.pivot = new Vector2(0.5f, 1f);
        bgRect.anchoredPosition = new Vector2(0f, -TopMarginPx);
        bgRect.sizeDelta = new Vector2(barWidth, barHeight);
        var bgImg = bgGo.AddComponent<Image>();
        bgImg.sprite = sprite;
        bgImg.color = new Color(0.1f, 0.1f, 0.1f, 0.85f);

        var fillGo = new GameObject("Fill");
        fillGo.transform.SetParent(bgGo.transform, false);
        var fillRect = fillGo.AddComponent<RectTransform>();
        fillRect.anchorMin = Vector2.zero;
        fillRect.anchorMax = Vector2.one;
        fillRect.offsetMin = Vector2.zero;
        fillRect.offsetMax = Vector2.zero;
        _fill = fillGo.AddComponent<Image>();
        _fill.sprite = sprite;
        _fill.type = Image.Type.Filled;
        _fill.fillMethod = Image.FillMethod.Horizontal;
        _fill.color = new Color(0.85f, 0.15f, 0.15f, 0.95f);

        var textGo = new GameObject("HP");
        textGo.transform.SetParent(bgGo.transform, false);
        var textRect = textGo.AddComponent<RectTransform>();
        textRect.anchorMin = Vector2.zero;
        textRect.anchorMax = Vector2.one;
        textRect.offsetMin = Vector2.zero;
        textRect.offsetMax = Vector2.zero;
        _label = textGo.AddComponent<Text>();
        _label.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        _label.alignment = TextAnchor.MiddleCenter;
        _label.color = Color.white;
        _label.fontSize = 14;
        _label.fontStyle = FontStyle.Bold;
    }

    public void SetVisible(bool visible)
    {
        Ensure();
        if (_canvas != null)
            _canvas.enabled = visible;
    }

    public void Update(float current, float max)
    {
        Ensure();
        if (_fill == null || _label == null)
            return;

        var pct = max > 0f ? Mathf.Clamp01(current / max) : 0f;
        _fill.fillAmount = pct;
        _label.text = Mathf.CeilToInt(current).ToString();
    }

    public void Destroy()
    {
        if (_root != null)
            Object.Destroy(_root);
        _root = null;
        _canvas = null;
        _fill = null;
        _label = null;
    }

    private static Sprite? _white;

    private static Sprite WhiteSprite()
    {
        if (_white != null)
            return _white;
        var tex = new Texture2D(1, 1);
        tex.SetPixel(0, 0, Color.white);
        tex.Apply();
        _white = Sprite.Create(tex, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f));
        return _white;
    }
}

using BepInEx;
using BepInEx.Logging;
using HarmonyLib;
using SpikeBalanceMod.Spikes;
using SpikeBalanceMod.UI;
using UnityEngine;

namespace SpikeBalanceMod;

[BepInPlugin(PluginGuid, PluginName, PluginVersion)]
public sealed class SpikeBalancePlugin : BaseUnityPlugin
{
    public const string PluginGuid = "com.spikebalance.whiteknuckle";
    public const string PluginName = "Spike Balance Mod";
    public const string PluginVersion = "3.5.0";

    public static SpikeBalancePlugin? Instance { get; private set; }
    public static bool RunActive => Instance?._runInitialized == true;

    private static ManualLogSource Log => Instance!.Logger;

    private Harmony? _harmony;
    private ModConfig? _cfg;
    private ModHealthPool? _health;
    private SpikePlacer? _spikes;
    private SpikeGround? _ground;
    private GripOnSpikes? _grip;
    private ModHealthBar? _bar;

    private float _offSpikeTimer;
    private float _debugTimer;
    private bool _wasOnSpikes;
    private bool _runInitialized;
    private string? _lastPlayerScene;
    private Vector3 _lastRoomScanPos;
    private bool _hasScanPosition;

    private void Awake()
    {
        Instance = this;
        _cfg = new ModConfig(Config);
        _health = new ModHealthPool();
        _spikes = new SpikePlacer(_cfg);
        _ground = new SpikeGround(_cfg);
        _grip = new GripOnSpikes();
        _bar = new ModHealthBar();

        _harmony = new Harmony(PluginGuid);
        _harmony.PatchAll(typeof(SpikeBalancePlugin).Assembly);
        HarmonyBootstrap.ApplyHandPatches(_harmony);

        LogInfoStatic($"{PluginName} v{PluginVersion} loaded.");
    }

    private void OnDestroy()
    {
        _harmony?.UnpatchSelf();
        _bar?.Destroy();
        Instance = null;
    }

    public void OnPlayerStarted(ENT_Player player)
    {
        _runInitialized = false;
        _lastPlayerScene = null;
        _hasScanPosition = false;
        BeginRun(player);
    }

    public void OnRoomGeometryLoaded(bool clearAllMarkers) => OnRoomGeometryLoaded(this, clearAllMarkers);

    private void OnRoomGeometryLoaded(MonoBehaviour host, bool clearAllMarkers)
    {
        if (!_runInitialized)
            return;
        ModState.InRun = true;
        _spikes?.OnRoomGeometryLoaded(host, clearAllMarkers);
    }

    private void Update()
    {
        if (ShouldEndRun())
        {
            EndRun();
            return;
        }

        var player = PlayerUtil.FindPlayer();

        if (!_runInitialized)
        {
            if (player != null && PlayerUtil.IsInActiveRun(player))
                BeginRun(player);
            return;
        }

        ModState.InRun = true;

        if (player != null)
        {
            TrackRoomChange(player);
            UpdateGameplay(player);
        }
        else
        {
            DrawHealthBar();
        }
    }

    private void UpdateGameplay(ENT_Player player)
    {
        if (_health!.IsDead)
        {
            _bar!.SetVisible(false);
            return;
        }

        DrawHealthBar();

        var onSpikes = _ground!.Check(player);
        ModState.OnSpikeGround = onSpikes;

        if (onSpikes && !_wasOnSpikes)
            _grip!.Enter(player);
        else if (!onSpikes && _wasOnSpikes)
            _grip!.Exit(player);

        _wasOnSpikes = onSpikes;

        if (onSpikes)
        {
            _offSpikeTimer = 0f;
            _health.ApplyDamage(_cfg!.SpikeDps.Value * Time.deltaTime);
        }
        else
        {
            _offSpikeTimer += Time.deltaTime;
            if (_offSpikeTimer >= _cfg!.HealthRegenDelay.Value)
                _health.Regen(_cfg.HealthRegenOffSpikes.Value * Time.deltaTime);
        }

        if (_cfg!.DebugLog.Value)
        {
            _debugTimer += Time.deltaTime;
            if (_debugTimer >= 2f)
            {
                _debugTimer = 0f;
                var hands = PlayerUtil.GetHands(player);
                var g0 = hands != null && hands.Length > 0 && hands.GetValue(0) != null
                    ? PlayerUtil.GetGrip(hands.GetValue(0)!).ToString("F2")
                    : "n/a";
                LogInfoStatic(
                    $"spikes={onSpikes} modHp={_health.Current:F0} grip0={g0} markers={SpikeMarkerRegistry.Active.Count}");
            }
        }
    }

    private void DrawHealthBar()
    {
        _bar!.Ensure();
        _bar.SetVisible(true);
        _bar.Update(_health!.Current, _health.Max);
    }

    private bool ShouldEndRun()
    {
        if (!_runInitialized)
            return false;

        var gm = Object.FindObjectOfType<CL_GameManager>();
        if (gm != null)
        {
            var ended = (bool)AccessTools.Field(typeof(CL_GameManager), "runHasEnded")!.GetValue(gm)!;
            if (ended)
                return true;
        }

        var player = PlayerUtil.FindPlayer();
        return player != null && PlayerUtil.IsMenuScene(player.gameObject.scene.name);
    }

    private void TrackRoomChange(ENT_Player player)
    {
        var scene = player.gameObject.scene.name;
        var pos = player.transform.position;

        if (_lastPlayerScene == null)
        {
            _lastPlayerScene = scene;
            _lastRoomScanPos = pos;
            _hasScanPosition = true;
            return;
        }

        if (scene != _lastPlayerScene)
        {
            _lastPlayerScene = scene;
            _lastRoomScanPos = pos;
            _hasScanPosition = true;
            LogInfoStatic($"Scene changed to {scene} — rescanning spikes.");
            OnRoomGeometryLoaded(false);
            return;
        }

        if (!_hasScanPosition)
        {
            _lastRoomScanPos = pos;
            _hasScanPosition = true;
            return;
        }

        if (Vector3.Distance(pos, _lastRoomScanPos) < 32f)
            return;

        _lastRoomScanPos = pos;
        LogInfoStatic($"New room area ({pos.x:F0},{pos.y:F0},{pos.z:F0}) — rescanning spikes.");
        OnRoomGeometryLoaded(false);
    }

    private void FixedUpdate()
    {
        if (!_runInitialized || !ModState.OnSpikeGround)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        _grip!.TickRegen(player, Time.fixedDeltaTime, _cfg!.GripRegenOnSpikes.Value);
    }

    private void LateUpdate()
    {
        if (!_runInitialized || !ModState.OnSpikeGround)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        _grip!.EnforceFloor(player);
    }

    internal void ClampHandGrip(object hand)
    {
        if (!ModState.OnSpikeGround)
            return;
        var player = PlayerUtil.FindPlayer();
        if (player != null)
            _grip?.EnforceFloor(player);
    }

    private void BeginRun(ENT_Player player)
    {
        if (_runInitialized)
            return;

        _runInitialized = true;
        _health!.Reset(100f);
        _offSpikeTimer = 0f;
        _wasOnSpikes = false;
        ModState.OnSpikeGround = false;
        ModState.InRun = true;
        _lastRoomScanPos = player.transform.position;
        _hasScanPosition = true;
        _lastPlayerScene = player.gameObject.scene.name;
        _spikes!.Clear();
        _spikes.ScheduleScans(this);
        DrawHealthBar();
        LogInfoStatic($"Run started in {player.gameObject.scene.name}");
    }

    private void EndRun()
    {
        if (!_runInitialized)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player != null && _wasOnSpikes)
            _grip?.Exit(player);

        _runInitialized = false;
        ModState.InRun = false;
        ModState.OnSpikeGround = false;
        _wasOnSpikes = false;
        _hasScanPosition = false;
        _bar?.SetVisible(false);
        _spikes?.Clear();
    }

    public static void LogInfoStatic(string msg) => Log?.LogInfo(msg);
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod.Spikes;

internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private Coroutine? _scanCoroutine;

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host) => ScheduleScans(host, clearAllMarkers: true);

    public void OnRoomGeometryLoaded(MonoBehaviour host, bool clearAllMarkers)
    {
        SpikeBalancePlugin.LogInfoStatic(
            clearAllMarkers ? "Room load — full spike rescan." : "New area — additive spike scan.");
        ScheduleScans(host, clearAllMarkers);
    }

    private void ScheduleScans(MonoBehaviour host, bool clearAllMarkers)
    {
        if (clearAllMarkers)
            ClearMarkers();
        else
            _placedCells.Clear();

        if (_scanCoroutine != null)
            host.StopCoroutine(_scanCoroutine);

        _scanCoroutine = host.StartCoroutine(ScanLoop(host));
    }

    public void Clear()
    {
        ClearMarkers();
        _scanCoroutine = null;
    }

    private void ClearMarkers()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        SpikeMarkerRegistry.Clear();
    }

    private IEnumerator ScanLoop(MonoBehaviour host)
    {
        yield return new WaitForSeconds(0.5f);
        TryPlace();
        yield return new WaitForSeconds(1.5f);
        TryPlace();
        yield return new WaitForSeconds(2f);
        TryPlace();
        yield return new WaitForSeconds(3f);
        TryPlace();
        yield return new WaitForSeconds(5f);
        TryPlace();
        _scanCoroutine = null;
    }

    private void TryPlace()
    {
        if (!SpikeBalancePlugin.RunActive)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        ModState.InRun = true;

        var origin = player.transform.position;
        var minUp = LevelSurfaceFilter.TiltDegreesToMinUpDot(_cfg.MaxSurfaceTiltDegrees.Value);
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;
        var before = _markers.Count;
        var scene = player.gameObject.scene;

        ScanGeometryRaycasts(origin, minUp, spacing, cap, scene);

        SpikeBalancePlugin.LogInfoStatic(
            $"Spike scan: markers={_markers.Count} (+{_markers.Count - before}) near ({origin.x:F0},{origin.y:F0},{origin.z:F0})");
    }

    private void ScanGeometryRaycasts(Vector3 origin, float minUp, float spacing, int cap, Scene playerScene)
    {
        const float extent = 48f;
        const int steps = 26;
        var step = extent / steps;
        var regionId = RegionId(origin);

        for (var x = -extent; x <= extent; x += step)
        {
            for (var z = -extent; z <= extent; z += step)
            {
                if (_markers.Count >= cap)
                    return;

                var start = origin + new Vector3(x, 20f, z);
                if (!Physics.Raycast(start, Vector3.down, out var hit, 40f, ~0, QueryTriggerInteraction.Ignore))
                    continue;

                if (!LevelSurfaceFilter.IsValidGeometryHit(hit, minUp))
                    continue;

                TryPoint(hit.point, hit.normal, spacing, cap, regionId, playerScene);
            }
        }
    }

    private void TryPoint(Vector3 surfacePoint, Vector3 normal, float spacing, int cap, int regionId, Scene playerScene)
    {
        if (_markers.Count >= cap)
            return;

        var n = normal.normalized;
        var radius = Mathf.Clamp(spacing * 0.32f, 0.32f, 0.55f);
        var lift = _cfg.SurfaceOffsetAbove.Value + radius * 0.25f;
        var point = surfacePoint + n * lift;

        var cell = CellKey(regionId, point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        if (playerScene.IsValid())
            SceneManager.MoveGameObjectToScene(go, playerScene);

        go.transform.position = point;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, n);

        var col = go.AddComponent<SphereCollider>();
        col.isTrigger = true;
        col.radius = radius;

        var marker = go.AddComponent<SpikeMarker>();
        marker.Init(radius);
        _markers.Add(marker);

        SpikeVisual.Attach(go, n, spacing, _cfg.ShowSpikeVisuals.Value);
    }

    private static int RegionId(Vector3 origin)
    {
        unchecked
        {
            var x = Mathf.FloorToInt(origin.x / 40f);
            var z = Mathf.FloorToInt(origin.z / 40f);
            return x * 73856093 ^ z * 19349663;
        }
    }

    private static int CellKey(int regionId, Vector3 p, float spacing)
    {
        unchecked
        {
            var hash = regionId * 31 + 17;
            hash = hash * 31 + Mathf.FloorToInt(p.x / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.y / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.z / spacing);
            return hash;
        }
    }
}

