using UnityEngine;

namespace SpikeBalanceMod;

internal sealed class SpikeGround
{
    private readonly ModConfig _cfg;

    public SpikeGround(ModConfig cfg) => _cfg = cfg;

    public bool Check(ENT_Player player)
    {
        if (_cfg.RequireFreeHands.Value && !PlayerUtil.AreHandsFree(player))
            return false;

        var body = player.transform.position;
        var feet = PlayerUtil.GetFeetPosition(player);
        var probe = new Vector3(body.x, feet.y, body.z);
        var touchDist = _cfg.GroundSphereRadius.Value;

        foreach (var marker in SpikeMarkerRegistry.Active)
        {
            if (marker == null)
                continue;

            var col = marker.GetComponent<SphereCollider>();
            if (col == null)
                continue;

            var closest = col.ClosestPoint(probe);
            if (Vector3.Distance(closest, probe) <= touchDist)
                return true;

            closest = col.ClosestPoint(body);
            if (Vector3.Distance(closest, body) <= touchDist + 0.35f)
                return true;
        }

        return false;
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod.Spikes;

internal sealed class SpikePlacer
{
    private readonly ModConfig _cfg;
    private readonly HashSet<int> _placedCells = new();
    private readonly List<SpikeMarker> _markers = new();
    private Coroutine? _scanCoroutine;
    private Vector3 _lastContinuousScanPos;
    private bool _hasContinuousScanPos;
    private float _continuousScanTimer;

    public SpikePlacer(ModConfig cfg) => _cfg = cfg;

    public void ScheduleScans(MonoBehaviour host) => ScheduleScans(host, clearAllMarkers: true);

    public void OnRoomGeometryLoaded(MonoBehaviour host, bool clearAllMarkers)
    {
        SpikeBalancePlugin.LogInfoStatic(
            clearAllMarkers ? "Room load — full spike rescan." : "New area — additive spike scan.");
        ScheduleScans(host, clearAllMarkers);
    }

    public void TickContinuous(ENT_Player player, float deltaTime)
    {
        if (!SpikeBalancePlugin.RunActive)
            return;

        _continuousScanTimer += deltaTime;
        var pos = player.transform.position;
        var moved = !_hasContinuousScanPos || Vector3.Distance(pos, _lastContinuousScanPos) >= _cfg.ContinuousScanMoveDistance.Value;
        var timed = _continuousScanTimer >= _cfg.ContinuousScanInterval.Value;

        if (!moved && !timed)
            return;

        _continuousScanTimer = 0f;
        _lastContinuousScanPos = pos;
        _hasContinuousScanPos = true;
        PruneDistantMarkers(pos, _cfg.MarkerPruneDistance.Value);
        TryPlace();
    }

    private void ScheduleScans(MonoBehaviour host, bool clearAllMarkers)
    {
        if (clearAllMarkers)
            ClearMarkers();
        else
            _placedCells.Clear();

        if (_scanCoroutine != null)
            host.StopCoroutine(_scanCoroutine);

        _scanCoroutine = host.StartCoroutine(ScanLoop(host));
    }

    public void Clear()
    {
        ClearMarkers();
        _scanCoroutine = null;
        _hasContinuousScanPos = false;
        _continuousScanTimer = 0f;
    }

    private void ClearMarkers()
    {
        foreach (var m in _markers)
        {
            if (m != null)
                Object.Destroy(m.gameObject);
        }
        _markers.Clear();
        _placedCells.Clear();
        SpikeMarkerRegistry.Clear();
    }

    private void PruneDistantMarkers(Vector3 playerPos, float distance)
    {
        if (_markers.Count < _cfg.MaxSpikes.Value * 0.85f)
            return;

        var maxSq = distance * distance;
        for (var i = _markers.Count - 1; i >= 0; i--)
        {
            var m = _markers[i];
            if (m == null)
            {
                _markers.RemoveAt(i);
                continue;
            }

            if ((m.transform.position - playerPos).sqrMagnitude <= maxSq)
                continue;

            Object.Destroy(m.gameObject);
            _markers.RemoveAt(i);
        }
    }

    private IEnumerator ScanLoop(MonoBehaviour host)
    {
        yield return new WaitForSeconds(0.5f);
        TryPlace();
        yield return new WaitForSeconds(1f);
        TryPlace();
        yield return new WaitForSeconds(2f);
        TryPlace();
        yield return new WaitForSeconds(3f);
        TryPlace();
        _scanCoroutine = null;
    }

    private void TryPlace()
    {
        if (!SpikeBalancePlugin.RunActive)
            return;

        var player = PlayerUtil.FindPlayer();
        if (player == null)
            return;

        ModState.InRun = true;

        var origin = player.transform.position;
        var minUp = LevelSurfaceFilter.TiltDegreesToMinUpDot(_cfg.MaxSurfaceTiltDegrees.Value);
        var spacing = Mathf.Max(0.5f, _cfg.SpikeSpacing.Value);
        var cap = _cfg.MaxSpikes.Value;
        var before = _markers.Count;
        var scene = player.gameObject.scene;

        ScanGeometryRaycasts(origin, minUp, spacing, cap, scene);

        if (_markers.Count != before)
        {
            SpikeBalancePlugin.LogInfoStatic(
                $"Spike scan: markers={_markers.Count} (+{_markers.Count - before}) near ({origin.x:F0},{origin.y:F0},{origin.z:F0})");
        }
    }

    private void ScanGeometryRaycasts(Vector3 origin, float minUp, float spacing, int cap, Scene playerScene)
    {
        var extent = _cfg.ScanExtent.Value;
        var step = Mathf.Max(spacing * 0.45f, 0.6f);
        var steps = Mathf.CeilToInt(extent / step);
        var regionId = RegionId(origin);

        for (var ix = -steps; ix <= steps; ix++)
        {
            for (var iz = -steps; iz <= steps; iz++)
            {
                if (_markers.Count >= cap)
                    return;

                var x = ix * step;
                var z = iz * step;

                foreach (var rayUp in _cfg.ScanHeightOffsets.Value)
                {
                    if (_markers.Count >= cap)
                        return;

                    var start = origin + new Vector3(x, rayUp, z);
                    if (!Physics.Raycast(start, Vector3.down, out var hit, rayUp + 12f, ~0, QueryTriggerInteraction.Ignore))
                        continue;

                    if (!LevelSurfaceFilter.IsValidGeometryHit(hit, minUp))
                        continue;

                    TryPoint(hit.point, hit.normal, spacing, cap, regionId, playerScene);
                }
            }
        }
    }

    private void TryPoint(Vector3 surfacePoint, Vector3 normal, float spacing, int cap, int regionId, Scene playerScene)
    {
        if (_markers.Count >= cap)
            return;

        var n = normal.normalized;
        var radius = Mathf.Clamp(spacing * 0.34f, 0.34f, 0.58f);
        var lift = _cfg.SurfaceOffsetAbove.Value;
        var point = surfacePoint + n * lift;

        var cell = CellKey(regionId, point, spacing);
        if (!_placedCells.Add(cell))
            return;

        var go = new GameObject("SpikeMarker");
        if (playerScene.IsValid())
            SceneManager.MoveGameObjectToScene(go, playerScene);

        go.transform.position = point;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, n);

        var col = go.AddComponent<SphereCollider>();
        col.isTrigger = true;
        col.radius = radius;

        var marker = go.AddComponent<SpikeMarker>();
        marker.Init(radius);
        _markers.Add(marker);

        SpikeVisual.Attach(go, n, spacing, _cfg.ShowSpikeVisuals.Value);
    }

    private static int RegionId(Vector3 origin)
    {
        unchecked
        {
            var x = Mathf.FloorToInt(origin.x / 36f);
            var z = Mathf.FloorToInt(origin.z / 36f);
            var y = Mathf.FloorToInt(origin.y / 12f);
            return (x * 73856093) ^ (z * 19349663) ^ (y * 83492791);
        }
    }

    private static int CellKey(int regionId, Vector3 p, float spacing)
    {
        unchecked
        {
            var hash = regionId * 31 + 17;
            hash = hash * 31 + Mathf.FloorToInt(p.x / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.y / spacing);
            hash = hash * 31 + Mathf.FloorToInt(p.z / spacing);
            return hash;
        }
    }
}

