using System.Collections.Generic;
using UnityEngine;

namespace SpikeBalanceMod.Spikes;

internal static class SpikeMarkerRegistry
{
    private static readonly List<SpikeMarker> Markers = new();

    public static IReadOnlyList<SpikeMarker> Active => Markers;

    public static void Register(SpikeMarker marker)
    {
        if (!Markers.Contains(marker))
            Markers.Add(marker);
    }

    public static void Unregister(SpikeMarker marker) => Markers.Remove(marker);

    public static void Clear() => Markers.Clear();

    public static float GetNearestDistance(Vector3 position)
    {
        var best = float.MaxValue;
        foreach (var marker in Markers)
        {
            if (marker == null)
                continue;
            var col = marker.GetComponent<Collider>();
            if (col == null)
            {
                var d = Vector3.Distance(position, marker.transform.position);
                if (d < best)
                    best = d;
                continue;
            }

            var closest = col.ClosestPoint(position);
            var dist = Vector3.Distance(closest, position);
            if (dist < best)
                best = dist;
        }

        return best == float.MaxValue ? -1f : best;
    }
}

