namespace SpikeBalanceMod;

internal sealed class Config
{
    public ConfigEntry<float> MaxTiltDegrees { get; }
    public ConfigEntry<float> SpikeSpacing { get; }
    public ConfigEntry<float> ScanRadius { get; }
    public ConfigEntry<int> MaxZones { get; }
    public ConfigEntry<float> ScanInterval { get; }
    public ConfigEntry<float> ScanMoveDistance { get; }
    public ConfigEntry<float> TouchDistance { get; }
    public ConfigEntry<bool> ShowVisuals { get; }
    public ConfigEntry<float> SpikeDps { get; }
    public ConfigEntry<float> GripRegen { get; }
    public ConfigEntry<float> HealthRegen { get; }
    public ConfigEntry<float> HealthRegenDelay { get; }
    public ConfigEntry<bool> DebugLog { get; }

    public Config(BepInEx.Configuration.ConfigFile file)
    {
        MaxTiltDegrees = file.Bind("Spikes", "MaxTiltDegrees", 20f, "Max surface tilt from horizontal (degrees).");
        SpikeSpacing = file.Bind("Spikes", "Spacing", 1.8f, "Distance between spike zones in the grid.");
        ScanRadius = file.Bind("Spikes", "ScanRadius", 48f, "Half-width of the scan square around the player.");
        MaxZones = file.Bind("Spikes", "MaxZones", 1500, "Maximum spike zones per run.");
        ScanInterval = file.Bind("Spikes", "ScanInterval", 2.5f, "Seconds between automatic scans.");
        ScanMoveDistance = file.Bind("Spikes", "ScanMoveDistance", 5f, "Also scan after moving this many meters.");
        TouchDistance = file.Bind("Spikes", "TouchDistance", 1f, "Distance to a zone center to count as on spikes.");
        ShowVisuals = file.Bind("Spikes", "ShowVisuals", true, "Show red spike meshes.");
        SpikeDps = file.Bind("Balance", "SpikeDamagePerSecond", 15f, "Mod HP damage per second on spikes.");
        GripRegen = file.Bind("Balance", "GripRegenPerSecond", 0.4f, "Grip added per second on spikes.");
        HealthRegen = file.Bind("Balance", "HealthRegenPerSecond", 10f, "Mod HP regen per second off spikes.");
        HealthRegenDelay = file.Bind("Balance", "HealthRegenDelay", 2f, "Delay before HP regen off spikes.");
        DebugLog = file.Bind("Debug", "LogStatus", false, "Log spike state every 2 seconds.");
    }
}

