internal sealed class HealthPool
{
    public float Current { get; private set; }
    public float Max { get; private set; } = 100f;
    public bool Dead => Current <= 0f;

    public void Reset(float max = 100f)
    {
        Max = max;
        Current = max;
    }

    public void Damage(float amount) => Current = Mathf.Max(0f, Current - amount);

    public void Heal(float amount) => Current = Mathf.Min(Max, Current + amount);
}

using UnityEngine;
using UnityEngine.UI;

namespace SpikeBalanceMod;

internal sealed class HealthBar
{
    private GameObject? _root;
    private Image? _fill;
    private Text? _label;

    public void Show(float current, float max)
    {
        Build();
        if (_root != null)
            _root.SetActive(true);
        if (_fill == null || _label == null)
            return;
        _fill.fillAmount = max > 0f ? Mathf.Clamp01(current / max) : 0f;
        _label.text = Mathf.CeilToInt(current).ToString();
    }

    public void Hide()
    {
        if (_root != null)
            _root.SetActive(false);
    }

    public void Destroy()
    {
        if (_root != null)
            Object.Destroy(_root);
        _root = null;
        _fill = null;
        _label = null;
    }

    private void Build()
    {
        if (_root != null)
            return;

        _root = new GameObject("SpikeBalance_HealthUI");
        Object.DontDestroyOnLoad(_root);

        var canvas = _root.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 9500;
        _root.AddComponent<CanvasScaler>().uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;

        var sprite = WhiteSprite();
        var bg = new GameObject("BG");
        bg.transform.SetParent(_root.transform, false);
        var bgR = bg.AddComponent<RectTransform>();
        bgR.anchorMin = new Vector2(0.5f, 1f);
        bgR.anchorMax = new Vector2(0.5f, 1f);
        bgR.pivot = new Vector2(0.5f, 1f);
        bgR.anchoredPosition = new Vector2(0f, -8f);
        bgR.sizeDelta = new Vector2(280f, 22f);
        bg.AddComponent<Image>().sprite = sprite;

        var fillGo = new GameObject("Fill");
        fillGo.transform.SetParent(bg.transform, false);
        var fillR = fillGo.AddComponent<RectTransform>();
        fillR.anchorMin = Vector2.zero;
        fillR.anchorMax = Vector2.one;
        fillR.offsetMin = Vector2.zero;
        fillR.offsetMax = Vector2.zero;
        _fill = fillGo.AddComponent<Image>();
        _fill.sprite = sprite;
        _fill.type = Image.Type.Filled;
        _fill.fillMethod = Image.FillMethod.Horizontal;
        _fill.color = new Color(0.9f, 0.12f, 0.1f);

        var txtGo = new GameObject("HP");
        txtGo.transform.SetParent(bg.transform, false);
        var txtR = txtGo.AddComponent<RectTransform>();
        txtR.anchorMin = Vector2.zero;
        txtR.anchorMax = Vector2.one;
        txtR.offsetMin = Vector2.zero;
        txtR.offsetMax = Vector2.zero;
        _label = txtGo.AddComponent<Text>();
        _label.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        _label.alignment = TextAnchor.MiddleCenter;
        _label.fontStyle = FontStyle.Bold;
        _label.color = Color.white;
        _label.fontSize = 14;
    }

    private static Sprite? _white;

    private static Sprite WhiteSprite()
    {
        if (_white != null)
            return _white;
        var t = new Texture2D(1, 1);
        t.SetPixel(0, 0, Color.white);
        t.Apply();
        _white = Sprite.Create(t, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f));
        return _white;
    }
}

