using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public sealed class SpikeZone : MonoBehaviour
{
    public float Radius { get; private set; }
    private SphereCollider? _col;

    public void Setup(float radius)
    {
        Radius = radius;
        _col = gameObject.AddComponent<SphereCollider>();
        _col.isTrigger = true;
        _col.radius = radius;
    }

    public bool Touches(Vector3 point, float extra)
    {
        if (_col == null)
            return Vector3.Distance(transform.position, point) <= Radius + extra;

        var closest = _col.ClosestPoint(point);
        return (closest - point).sqrMagnitude <= (Radius + extra) * (Radius + extra);
    }
}

using UnityEngine;

namespace SpikeBalanceMod.Spikes;

internal static class LevelGeom
{
    public static float MinUpDot(float maxTiltDegrees) =>
        Mathf.Cos(maxTiltDegrees * Mathf.Deg2Rad);

    public static bool IsFloorHit(RaycastHit hit, float minUpDot)
    {
        if (hit.normal.y < minUpDot)
            return false;
        return IsFloorCollider(hit.collider);
    }

    public static bool IsFloorCollider(Collider col)
    {
        if (col == null || col.isTrigger)
            return false;
        if (col.GetComponentInParent<SpikeZone>() != null)
            return false;
        if (col.GetComponentInParent<CL_Handhold>() != null)
            return false;
        if (col.GetComponentInParent<ENT_Player>() != null)
            return false;

        var rb = col.attachedRigidbody;
        return rb == null || rb.isKinematic;
    }
}

using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod.Spikes;

/// <summary>Scans level geometry, spawns spike zones, detects player contact.</summary>
internal sealed class SpikeField
{
    private readonly Config _cfg;
    private readonly List<SpikeZone> _zones = new();
    private readonly HashSet<long> _cells = new();
    private Vector3 _lastScanPos;
    private float _scanTimer;
    private bool _hasScanPos;

    public int Count => _zones.Count;

    public SpikeField(Config cfg) => _cfg = cfg;

    public void Clear()
    {
        foreach (var z in _zones)
        {
            if (z != null)
                Object.Destroy(z.gameObject);
        }
        _zones.Clear();
        _cells.Clear();
        _hasScanPos = false;
        _scanTimer = 0f;
    }

    public void Tick(ENT_Player player, float dt)
    {
        _scanTimer += dt;
        var pos = GameRefs.BodyPosition(player);
        var moved = !_hasScanPos || Vector3.Distance(pos, _lastScanPos) >= _cfg.ScanMoveDistance.Value;
        var timed = _scanTimer >= _cfg.ScanInterval.Value;
        if (!moved && !timed)
            return;

        _scanTimer = 0f;
        _lastScanPos = pos;
        _hasScanPos = true;
        PruneFar(pos);
        Scan(pos, player.gameObject.scene);
    }

    public void ScanNow(ENT_Player player)
    {
        var pos = GameRefs.BodyPosition(player);
        _lastScanPos = pos;
        _hasScanPos = true;
        _scanTimer = 0f;
        Scan(pos, player.gameObject.scene);
    }

    public bool PlayerOnSpikes(ENT_Player player)
    {
        var touch = _cfg.TouchDistance.Value;
        var body = GameRefs.BodyPosition(player);
        var feet = GameRefs.FeetPosition(player);

        foreach (var zone in _zones)
        {
            if (zone == null)
                continue;
            if (zone.Touches(body, touch) || zone.Touches(feet, touch))
                return true;
        }

        return false;
    }

    public float NearestDistance(Vector3 point)
    {
        var best = float.MaxValue;
        var touch = _cfg.TouchDistance.Value;
        foreach (var zone in _zones)
        {
            if (zone == null)
                continue;
            var col = zone.GetComponent<SphereCollider>();
            if (col != null)
            {
                var d = Vector3.Distance(col.ClosestPoint(point), point) - touch;
                if (d < best)
                    best = d;
            }
            else
            {
                var d = Vector3.Distance(zone.transform.position, point) - zone.Radius;
                if (d < best)
                    best = d;
            }
        }

        return best == float.MaxValue ? -1f : Mathf.Max(0f, best);
    }

    private void Scan(Vector3 center, Scene scene)
    {
        var minUp = LevelGeom.MinUpDot(_cfg.MaxTiltDegrees.Value);
        var spacing = _cfg.SpikeSpacing.Value;
        var radius = _cfg.ScanRadius.Value;
        var step = Mathf.Max(spacing * 0.5f, 0.7f);
        var steps = Mathf.CeilToInt(radius / step);
        var cap = _cfg.MaxZones.Value;
        var region = RegionKey(center);
        var before = _zones.Count;

        for (var ix = -steps; ix <= steps; ix++)
        {
            for (var iz = -steps; iz <= steps; iz++)
            {
                if (_zones.Count >= cap)
                    return;

                var offset = new Vector3(ix * step, 0f, iz * step);
                foreach (var rayHeight in new[] { 14f, 6f, 24f })
                {
                    if (_zones.Count >= cap)
                        return;

                    var start = center + offset + Vector3.up * rayHeight;
                    if (!Physics.Raycast(start, Vector3.down, out var hit, rayHeight + 10f, ~0, QueryTriggerInteraction.Ignore))
                        continue;
                    if (!LevelGeom.IsFloorHit(hit, minUp))
                        continue;

                    SpawnZone(hit.point, hit.normal, spacing, region, scene);
                }
            }
        }

        if (_zones.Count != before)
            Plugin.LogInfo($"SpikeField: {_zones.Count} zones (+{_zones.Count - before})");
    }

    private void SpawnZone(Vector3 surface, Vector3 normal, float spacing, long region, Scene scene)
    {
        var zoneRadius = Mathf.Clamp(spacing * 0.38f, 0.38f, 0.65f);
        var pos = surface + normal.normalized * 0.03f;
        var cell = CellKey(region, pos, spacing);
        if (!_cells.Add(cell))
            return;

        var go = new GameObject("SpikeZone");
        if (scene.IsValid())
            SceneManager.MoveGameObjectToScene(go, scene);

        go.transform.position = pos;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);

        var zone = go.AddComponent<SpikeZone>();
        zone.Setup(zoneRadius);
        _zones.Add(zone);

        if (_cfg.ShowVisuals.Value)
            BuildVisual(go, normal, spacing);
    }

    private static void BuildVisual(GameObject host, Vector3 normal, float spacing)
    {
        var mat = VisualMaterial.Get();
        var scale = Mathf.Clamp(spacing * 0.4f, 0.55f, 1.2f);
        for (var i = 0; i < 4; i++)
        {
            var peg = GameObject.CreatePrimitive(PrimitiveType.Cube);
            peg.transform.SetParent(host.transform, false);
            var a = i * 90f * Mathf.Deg2Rad;
            peg.transform.localPosition = new Vector3(Mathf.Cos(a), 0.05f, Mathf.Sin(a)) * scale * 0.25f;
            peg.transform.localScale = new Vector3(0.07f, 0.18f, 0.07f);
            peg.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);
            Object.Destroy(peg.GetComponent<Collider>());
            peg.GetComponent<Renderer>()!.sharedMaterial = mat;
        }
    }

    private void PruneFar(Vector3 pos)
    {
        if (_zones.Count < _cfg.MaxZones.Value * 0.9f)
            return;

        var maxSq = 100f * 100f;
        for (var i = _zones.Count - 1; i >= 0; i--)
        {
            var z = _zones[i];
            if (z == null)
            {
                _zones.RemoveAt(i);
                continue;
            }

            if ((z.transform.position - pos).sqrMagnitude > maxSq)
            {
                Object.Destroy(z.gameObject);
                _zones.RemoveAt(i);
            }
        }
    }

    private static long RegionKey(Vector3 p)
    {
        var x = Mathf.FloorToInt(p.x / 32f);
        var z = Mathf.FloorToInt(p.z / 32f);
        var y = Mathf.FloorToInt(p.y / 10f);
        return ((long)x << 42) ^ ((long)z << 21) ^ (uint)y;
    }

    private static long CellKey(long region, Vector3 p, float spacing)
    {
        var ix = Mathf.FloorToInt(p.x / spacing);
        var iy = Mathf.FloorToInt(p.y / spacing);
        var iz = Mathf.FloorToInt(p.z / spacing);
        return region ^ ((long)ix << 40) ^ ((long)iy << 20) ^ (uint)iz;
    }

    private static class VisualMaterial
    {
        private static Material? _m;

        public static Material Get()
        {
            if (_m != null)
                return _m;
            var shader = Shader.Find("Sprites/Default") ?? Shader.Find("Unlit/Color");
            _m = new Material(shader!) { color = new Color(1f, 0.1f, 0.05f, 0.92f) };
            return _m;
        }
    }
}

