using System.Collections;
using BepInEx;
using BepInEx.Logging;
using HarmonyLib;
using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod;

[BepInPlugin(Id, Name, Version)]
public sealed class Plugin : BaseUnityPlugin
{
    public const string Id = "com.spikebalance.whiteknuckle";
    public const string Name = "Spike Balance Mod";
    public const string Version = "4.0.0";

    public static Plugin? Instance { get; private set; }
    private static ManualLogSource Log => Instance!.Logger;

    private Config? _cfg;
    private HealthPool? _hp;
    private HealthBar? _ui;
    private SpikeField? _spikes;
    private Grip? _grip;

    private bool _run;
    private float _offSpikeTimer;
    private float _debugTimer;
    private bool _onSpikes;
    private Coroutine? _bootScan;

    private void Awake()
    {
        Instance = this;
        _cfg = new Config(Config);
        _hp = new HealthPool();
        _ui = new HealthBar();
        _spikes = new SpikeField(_cfg);
        _grip = new Grip();
        HarmonySetup.Apply(new Harmony(Id));
        LogInfo($"{Name} {Version}");
    }

    private void OnDestroy()
    {
        Harmony.CreateAndPatchAll(typeof(Plugin).Assembly, Id)?.UnpatchSelf();
        _ui?.Destroy();
        Instance = null;
    }

    public void NotifyPlayerSpawned() => TryStartRun();

    public void NotifyRoomLoaded()
    {
        if (!_run)
            return;
        var p = GameRefs.Player();
        if (p != null)
        {
            LogInfo("Room loaded — scanning spikes.");
            _spikes!.ScanNow(p);
        }
    }

    private void Update()
    {
        if (ShouldStopRun())
        {
            StopRun();
            return;
        }

        var player = GameRefs.Player();
        if (!_run)
        {
            if (player != null && GameRefs.InRun(player))
                StartRun(player);
            return;
        }

        ModState.RunActive = true;

        if (player == null)
        {
            _ui!.Show(_hp!.Current, _hp.Max);
            return;
        }

        _spikes!.Tick(player, Time.deltaTime);
        _ui!.Show(_hp!.Current, _hp.Max);

        var onSpikes = _spikes.PlayerOnSpikes(player);
        ModState.OnSpikeZone = onSpikes;

        if (onSpikes && !_onSpikes)
            _grip!.Enter(player);
        else if (!onSpikes && _onSpikes)
            _grip!.Exit(player);

        _onSpikes = onSpikes;

        if (onSpikes)
        {
            _offSpikeTimer = 0f;
            _hp.Damage(_cfg!.SpikeDps.Value * Time.deltaTime);
        }
        else
        {
            _offSpikeTimer += Time.deltaTime;
            if (_offSpikeTimer >= _cfg!.HealthRegenDelay.Value)
                _hp.Heal(_cfg.HealthRegen.Value * Time.deltaTime);
        }

        if (_cfg.DebugLog.Value)
        {
            _debugTimer += Time.deltaTime;
            if (_debugTimer >= 2f)
            {
                _debugTimer = 0f;
                LogInfo($"onSpikes={onSpikes} hp={_hp.Current:F0} grip0={GameRefs.Grip0(player):F2} zones={_spikes.Count} near={_spikes.NearestDistance(GameRefs.BodyPosition(player)):F2}m");
            }
        }
    }

    private void FixedUpdate()
    {
        if (!_run || !ModState.OnSpikeZone)
            return;
        var p = GameRefs.Player();
        if (p != null)
            _grip!.Regen(p, Time.fixedDeltaTime, _cfg!.GripRegen.Value);
    }

    private void TryStartRun()
    {
        var p = GameRefs.Player();
        if (p != null && GameRefs.InRun(p))
            StartRun(p);
    }

    private void StartRun(ENT_Player player)
    {
        if (_run)
            return;

        _run = true;
        ModState.RunActive = true;
        ModState.OnSpikeZone = false;
        _onSpikes = false;
        _offSpikeTimer = 0f;
        _hp!.Reset(100f);
        _spikes!.Clear();
        _ui!.Show(_hp.Current, _hp.Max);

        if (_bootScan != null)
            StopCoroutine(_bootScan);
        _bootScan = StartCoroutine(BootScan(player));

        LogInfo($"Run started ({player.gameObject.scene.name})");
    }

    private IEnumerator BootScan(ENT_Player player)
    {
        yield return new WaitForSeconds(0.5f);
        _spikes!.ScanNow(player);
        yield return new WaitForSeconds(1.5f);
        _spikes.ScanNow(player);
        yield return new WaitForSeconds(2f);
        _spikes.ScanNow(player);
        yield return new WaitForSeconds(3f);
        _spikes.ScanNow(player);
        _bootScan = null;
    }

    private bool ShouldStopRun()
    {
        if (!_run)
            return false;
        if (GameRefs.RunEndedCheck())
            return true;
        var p = GameRefs.Player();
        return p != null && GameRefs.IsMenu(p.gameObject.scene.name);
    }

    private void StopRun()
    {
        if (!_run)
            return;

        var p = GameRefs.Player();
        if (p != null && _onSpikes)
            _grip!.Exit(p);

        _run = false;
        ModState.RunActive = false;
        ModState.OnSpikeZone = false;
        _onSpikes = false;
        _spikes?.Clear();
        _ui?.Hide();
    }

    public static void LogInfo(string msg) => Log?.LogInfo(msg);
}

