using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod.Spikes;

/// <summary>Fills all upward-facing level colliders in each loaded room with lava zones.</summary>
internal sealed class SpikeField
{
    private readonly Config _cfg;
    private readonly List<SpikeZone> _zones = new();
    private readonly HashSet<long> _cells = new();
    private readonly HashSet<int> _filledRooms = new();
    private Vector3 _lastExplorePos;
    private float _exploreTimer;
    private bool _hasExplorePos;

    public int Count => _zones.Count;

    public SpikeField(Config cfg) => _cfg = cfg;

    public void Clear()
    {
        foreach (var z in _zones)
        {
            if (z != null)
                UnityEngine.Object.Destroy(z.gameObject);
        }
        _zones.Clear();
        _cells.Clear();
        _filledRooms.Clear();
        _hasExplorePos = false;
        _exploreTimer = 0f;
    }

    /// <summary>Fill an entire room hierarchy (all floors/ledges).</summary>
    public int LavaFillRoom(GameObject? roomRoot, Scene scene)
    {
        if (roomRoot == null)
            return 0;

        var roomId = roomRoot.GetInstanceID();
        if (_filledRooms.Contains(roomId))
            return 0;

        _filledRooms.Add(roomId);
        var minUp = LevelGeom.MinUpDot(_cfg.MaxTiltDegrees.Value);
        var spacing = _cfg.SpikeSpacing.Value;
        var cap = _cfg.MaxZones.Value;
        var before = _zones.Count;
        var region = (long)roomId << 32;

        var colliders = roomRoot.GetComponentsInChildren<Collider>(includeInactive: true);
        foreach (var col in colliders)
        {
            if (_zones.Count >= cap)
                break;
            if (!LevelGeom.IsFloorCollider(col))
                continue;
            FillCollider(col, minUp, spacing, region, scene, cap);
        }

        var added = _zones.Count - before;
        Plugin.LogInfo($"Lava fill '{roomRoot.name}': +{added} zones (total {_zones.Count})");
        return added;
    }

    public IEnumerator LavaFillRoomDelayed(GameObject? roomRoot, Scene scene)
    {
        yield return null;
        yield return new WaitForSeconds(0.25f);
        LavaFillRoom(roomRoot, scene);
        yield return new WaitForSeconds(1f);
        LavaFillRoom(roomRoot, scene);
        yield return new WaitForSeconds(2f);
        LavaFillRoom(roomRoot, scene);
    }

    /// <summary>Small follow-up scan near the player for anything missed.</summary>
    public void ExploreNearPlayer(ENT_Player player, float dt)
    {
        _exploreTimer += dt;
        var pos = GameRefs.BodyPosition(player);
        var moved = !_hasExplorePos || Vector3.Distance(pos, _lastExplorePos) >= _cfg.ScanMoveDistance.Value;
        if (!moved && _exploreTimer < _cfg.ScanInterval.Value)
            return;

        _exploreTimer = 0f;
        _lastExplorePos = pos;
        _hasExplorePos = true;

        var minUp = LevelGeom.MinUpDot(_cfg.MaxTiltDegrees.Value);
        var spacing = _cfg.SpikeSpacing.Value;
        var region = RegionKey(pos);
        var before = _zones.Count;
        var cap = _cfg.MaxZones.Value;
        var radius = _cfg.ScanRadius.Value;
        var step = Mathf.Max(spacing * 0.45f, 0.6f);
        var steps = Mathf.CeilToInt(radius / step);

        for (var ix = -steps; ix <= steps; ix++)
        {
            for (var iz = -steps; iz <= steps; iz++)
            {
                if (_zones.Count >= cap)
                    return;

                var offset = new Vector3(ix * step, 0f, iz * step);
                foreach (var up in new[] { 6f, 16f, 28f, 40f })
                {
                    var start = pos + offset + Vector3.up * up;
                    if (!Physics.Raycast(start, Vector3.down, out var hit, up + 12f, ~0, QueryTriggerInteraction.Ignore))
                        continue;
                    if (!LevelGeom.IsFloorHit(hit, minUp))
                        continue;
                    SpawnZone(hit.point, hit.normal, spacing, region, player.gameObject.scene);
                }
            }
        }

        if (_zones.Count != before)
            Plugin.LogInfo($"Lava explore: +{_zones.Count - before} zones (total {_zones.Count})");
    }

    public bool PlayerOnSpikes(ENT_Player player)
    {
        var touch = _cfg.TouchDistance.Value;
        var body = GameRefs.BodyPosition(player);
        var feet = GameRefs.FeetPosition(player);

        foreach (var zone in _zones)
        {
            if (zone == null)
                continue;
            if (zone.Touches(body, touch) || zone.Touches(feet, touch))
                return true;
        }

        return false;
    }

    public float NearestDistance(Vector3 point)
    {
        var best = float.MaxValue;
        var touch = _cfg.TouchDistance.Value;
        foreach (var zone in _zones)
        {
            if (zone == null)
                continue;
            var col = zone.GetComponent<SphereCollider>();
            if (col != null)
            {
                var d = Vector3.Distance(col.ClosestPoint(point), point) - touch;
                if (d < best)
                    best = d;
            }
        }

        return best == float.MaxValue ? -1f : Mathf.Max(0f, best);
    }

    private void FillCollider(Collider col, float minUp, float spacing, long region, Scene scene, int cap)
    {
        var bounds = col.bounds;
        if (bounds.size.x < 0.2f && bounds.size.z < 0.2f)
            return;

        var step = Mathf.Max(spacing * 0.55f, 0.55f);
        var y = bounds.max.y + 0.15f;

        for (var x = bounds.min.x; x <= bounds.max.x + 0.01f; x += step)
        {
            for (var z = bounds.min.z; z <= bounds.max.z + 0.01f; z += step)
            {
                if (_zones.Count >= cap)
                    return;

                var probe = new Vector3(x, y, z);
                if (!Physics.Raycast(probe, Vector3.down, out var hit, 2.5f, ~0, QueryTriggerInteraction.Ignore))
                    continue;

                if (!IsHitOnCollider(hit, col))
                    continue;
                if (!LevelGeom.IsFloorHit(hit, minUp))
                    continue;

                SpawnZone(hit.point, hit.normal, spacing, region, scene);
            }
        }
    }

    private static bool IsHitOnCollider(RaycastHit hit, Collider target)
    {
        if (hit.collider == target)
            return true;
        return hit.collider.transform.IsChildOf(target.transform) ||
               target.transform.IsChildOf(hit.collider.transform);
    }

    private void SpawnZone(Vector3 surface, Vector3 normal, float spacing, long region, Scene scene)
    {
        var zoneRadius = Mathf.Clamp(spacing * 0.4f, 0.36f, 0.62f);
        var pos = surface + normal.normalized * 0.03f;
        var cell = CellKey(region, pos, spacing);
        if (!_cells.Add(cell))
            return;

        var go = new GameObject("LavaZone");
        if (scene.IsValid())
            SceneManager.MoveGameObjectToScene(go, scene);

        go.transform.position = pos;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);

        var zone = go.AddComponent<SpikeZone>();
        zone.Setup(zoneRadius);
        _zones.Add(zone);

        if (_cfg.ShowVisuals.Value)
            BuildVisual(go, normal, spacing);
    }

    private static void BuildVisual(GameObject host, Vector3 normal, float spacing)
    {
        var mat = VisualMaterial.Get();
        var scale = Mathf.Clamp(spacing * 0.38f, 0.5f, 1.1f);
        for (var i = 0; i < 4; i++)
        {
            var peg = GameObject.CreatePrimitive(PrimitiveType.Cube);
            peg.transform.SetParent(host.transform, false);
            var a = i * Mathf.PI * 0.5f;
            peg.transform.localPosition = new Vector3(Mathf.Cos(a), 0.04f, Mathf.Sin(a)) * scale * 0.22f;
            peg.transform.localScale = new Vector3(0.07f, 0.16f, 0.07f);
            peg.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);
            UnityEngine.Object.Destroy(peg.GetComponent<Collider>());
            peg.GetComponent<Renderer>()!.sharedMaterial = mat;
        }
    }

    private static long RegionKey(Vector3 p)
    {
        var x = Mathf.FloorToInt(p.x / 48f);
        var z = Mathf.FloorToInt(p.z / 48f);
        var y = Mathf.FloorToInt(p.y / 12f);
        return ((long)x << 42) ^ ((long)z << 21) ^ (uint)y;
    }

    private static long CellKey(long region, Vector3 p, float spacing)
    {
        var ix = Mathf.FloorToInt(p.x / spacing);
        var iy = Mathf.FloorToInt(p.y / spacing);
        var iz = Mathf.FloorToInt(p.z / spacing);
        return region ^ ((long)ix << 40) ^ ((long)iy << 20) ^ (uint)iz;
    }

    private static class VisualMaterial
    {
        private static Material? _m;

        public static Material Get()
        {
            if (_m != null)
                return _m;
            var shader = Shader.Find("Sprites/Default") ?? Shader.Find("Unlit/Color");
            _m = new Material(shader!) { color = new Color(1f, 0.2f, 0.02f, 0.92f) };
            return _m;
        }
    }
}

using System.Collections;
using BepInEx;
using BepInEx.Logging;
using HarmonyLib;
using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod;

[BepInPlugin(Id, Name, Version)]
public sealed class Plugin : BaseUnityPlugin
{
    public const string Id = "com.thefloorislava.whiteknuckle";
    public const string Name = "The Floor Is Lava";
    public const string Version = "1.0.0";

    public static Plugin? Instance { get; private set; }
    private static ManualLogSource Log => Instance!.Logger;

    private Config? _cfg;
    private HealthPool? _hp;
    private HealthBar? _ui;
    private SpikeField? _lava;
    private Grip? _grip;

    private bool _run;
    private float _offSpikeTimer;
    private float _debugTimer;
    private bool _onSpikes;
    private Harmony? _harmony;

    private void Awake()
    {
        Instance = this;
        _cfg = new Config(Config);
        _hp = new HealthPool();
        _ui = new HealthBar();
        _lava = new SpikeField(_cfg);
        _grip = new Grip();
        _harmony = new Harmony(Id);
        HarmonySetup.Apply(_harmony);
        LogInfo($"{Name} v{Version}");
    }

    private void OnDestroy()
    {
        _harmony?.UnpatchSelf();
        _ui?.Destroy();
        Instance = null;
    }

    public void NotifyPlayerSpawned() => TryStartRun();

    public void NotifyRoomLoaded(GameObject roomRoot)
    {
        if (!_run)
            return;
        var scene = roomRoot != null ? roomRoot.scene : GameRefs.Player()?.gameObject.scene ?? default;
        LogInfo($"Room loaded: '{roomRoot?.name ?? "?"}' — filling upward surfaces with lava.");
        StartCoroutine(_lava!.LavaFillRoomDelayed(roomRoot, scene));
    }

    private void Update()
    {
        if (ShouldStopRun())
        {
            StopRun();
            return;
        }

        var player = GameRefs.Player();
        if (!_run)
        {
            if (player != null && GameRefs.InRun(player))
                StartRun(player);
            return;
        }

        ModState.RunActive = true;

        if (player == null)
        {
            if (!_hp!.Dead)
                _ui!.Show(_hp.Current, _hp.Max);
            return;
        }

        if (_hp!.Dead)
        {
            _ui!.Hide();
            return;
        }

        _lava!.ExploreNearPlayer(player, Time.deltaTime);
        _ui!.Show(_hp.Current, _hp.Max);

        var onSpikes = _lava.PlayerOnSpikes(player);
        ModState.OnSpikeZone = onSpikes;

        if (onSpikes && !_onSpikes)
            _grip!.Enter(player);
        else if (!onSpikes && _onSpikes)
            _grip!.Exit(player);

        _onSpikes = onSpikes;

        if (onSpikes)
        {
            _offSpikeTimer = 0f;
            _hp.Damage(_cfg!.SpikeDps.Value * Time.deltaTime);
        }
        else
        {
            _offSpikeTimer += Time.deltaTime;
            if (_offSpikeTimer >= _cfg!.HealthRegenDelay.Value)
                _hp.Heal(_cfg.HealthRegen.Value * Time.deltaTime);
        }

        if (_cfg.DebugLog.Value)
        {
            _debugTimer += Time.deltaTime;
            if (_debugTimer >= 2f)
            {
                _debugTimer = 0f;
                LogInfo(
                    $"onLava={onSpikes} hp={_hp.Current:F0} grip0={GameRefs.Grip0(player):F2} zones={_lava.Count} near={_lava.NearestDistance(GameRefs.BodyPosition(player)):F2}m");
            }
        }
    }

    private void FixedUpdate()
    {
        if (!_run || !ModState.OnSpikeZone)
            return;
        var p = GameRefs.Player();
        if (p != null)
            _grip!.Regen(p, Time.fixedDeltaTime, _cfg!.GripRegen.Value);
    }

    private void TryStartRun()
    {
        var p = GameRefs.Player();
        if (p != null && GameRefs.InRun(p))
            StartRun(p);
    }

    private void StartRun(ENT_Player player)
    {
        if (_run)
            return;

        _run = true;
        ModState.RunActive = true;
        ModState.OnSpikeZone = false;
        _onSpikes = false;
        _offSpikeTimer = 0f;
        _hp!.Reset(100f);
        _lava!.Clear();
        _ui!.Show(_hp.Current, _hp.Max);

        var hm = Object.FindObjectOfType<HandholdManager>();
        if (hm != null)
            NotifyRoomLoaded(hm.gameObject);

        LogInfo($"Run started ({player.gameObject.scene.name})");
    }

    private bool ShouldStopRun()
    {
        if (!_run)
            return false;
        if (GameRefs.RunEndedCheck())
            return true;
        var p = GameRefs.Player();
        return p != null && GameRefs.IsMenu(p.gameObject.scene.name);
    }

    private void StopRun()
    {
        if (!_run)
            return;

        var p = GameRefs.Player();
        if (p != null && _onSpikes)
            _grip!.Exit(p);

        _run = false;
        ModState.RunActive = false;
        ModState.OnSpikeZone = false;
        _onSpikes = false;
        _lava?.Clear();
        _ui?.Hide();
    }

    public static void LogInfo(string msg) => Log?.LogInfo(msg);
}

