using UnityEngine;

namespace SpikeBalanceMod.Spikes;

/// <summary>Tracks player inside lava triggers (requires kinematic Rigidbody on zones).</summary>
internal static class LavaContact
{
    private static ENT_Player? _player;
    private static float _lastTouchTime;

    public static void Report(ENT_Player player)
    {
        _player = player;
        _lastTouchTime = Time.time;
    }

    public static bool IsActive(ENT_Player player) =>
        _player == player && Time.time - _lastTouchTime < 0.25f;

    public static void Clear()
    {
        _player = null;
        _lastTouchTime = 0f;
    }
}

using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public sealed class SpikeZone : MonoBehaviour
{
    public float Radius { get; private set; }
    private SphereCollider? _col;

    public void Setup(float radius)
    {
        Radius = radius;

        var rb = gameObject.AddComponent<Rigidbody>();
        rb.isKinematic = true;
        rb.useGravity = false;

        _col = gameObject.AddComponent<SphereCollider>();
