using UnityEngine;

namespace SpikeBalanceMod.Spikes;

public sealed class SpikeZone : MonoBehaviour
{
    public float Radius { get; private set; }
    private Collider? _col;

    public void Setup(float radius)
    {
        Radius = radius;

        var rb = gameObject.AddComponent<Rigidbody>();
        rb.isKinematic = true;
        rb.useGravity = false;

        var box = gameObject.AddComponent<BoxCollider>();
        box.isTrigger = true;
        box.size = new Vector3(radius * 2.4f, 0.4f, radius * 2.4f);
        box.center = new Vector3(0f, 0.05f, 0f);
        _col = box;
    }

    private void OnTriggerStay(Collider other)
    {
        var player = other.GetComponentInParent<ENT_Player>();
        if (player != null)
            LavaContact.Report(player);
    }

    public bool Touches(Vector3 point, float extra)
    {
        if (_col == null)
            return Vector3.Distance(transform.position, point) <= Radius + extra;

        var closest = _col.ClosestPoint(point);
        return (closest - point).sqrMagnitude <= (Radius + extra) * (Radius + extra);
    }
}

