    public ConfigEntry<float> WorldScanInterval { get; }
    public ConfigEntry<float> WorldScanHorizRange { get; }
    public ConfigEntry<float> WorldScanVertRange { get; }
    public ConfigEntry<float> TouchDistance { get; }
    public ConfigEntry<float> VerticalAbove { get; }
    public ConfigEntry<float> VerticalBelow { get; }
    public ConfigEntry<bool> ShowVisuals { get; }
    public ConfigEntry<float> SpikeDps { get; }
    public ConfigEntry<float> GripRegen { get; }
    public ConfigEntry<float> HealthRegen { get; }
    public ConfigEntry<float> HealthRegenDelay { get; }
    public ConfigEntry<bool> DebugLog { get; }

    public Config(ConfigFile file)
    {
        MaxTiltDegrees = file.Bind("Lava", "MaxTiltDegrees", 20f,
            "Max surface tilt from horizontal (degrees).");
        SpikeSpacing = file.Bind("Lava", "Spacing", 1.6f,
            "Distance between lava zone centers in the surface grid.");
        MaxZones = file.Bind("Lava", "MaxZones", 12000,
            "Maximum lava zones per run.");
        WorldScanInterval = file.Bind("Lava", "WorldScanInterval", 1.0f,
            "Seconds between continuous world scans.");
        WorldScanHorizRange = file.Bind("Lava", "WorldScanHorizRange", 80f,
            "Max horizontal distance from the player to scan for new floors.");
        WorldScanVertRange = file.Bind("Lava", "WorldScanVertRange", 60f,
            "Max vertical distance from the player to scan (up & down).");
        TouchDistance = file.Bind("Lava", "TouchDistance", 1.4f,
            "Extra horizontal distance to a zone center for it to count as 'on lava'.");
        VerticalAbove = file.Bind("Lava", "VerticalAbove", 1.8f,
            "Max feet height above a zone to still count as standing on it.");
        VerticalBelow = file.Bind("Lava", "VerticalBelow", 1f,
            "Max feet height below a zone to still count as touching it.");
        ShowVisuals = file.Bind("Lava", "ShowVisuals", true,
            "Show orange lava pegs on every floor zone.");
        SpikeDps = file.Bind("Balance", "LavaDamagePerSecond", 15f,
            "Mod HP damage per second while standing on lava.");
        GripRegen = file.Bind("Balance", "GripRegenPerSecond", 0.4f,
            "Grip strength recovered per second on lava.");
        HealthRegen = file.Bind("Balance", "HealthRegenPerSecond", 10f,
            "Mod HP regen per second when off lava.");
        HealthRegenDelay = file.Bind("Balance", "HealthRegenDelay", 2f,
            "Seconds off lava before HP starts regenerating.");
        DebugLog = file.Bind("Debug", "LogStatus", true,
            "Log lava state and damage diagnostics every second.");
    }
}

using System.Collections.Generic;
using UnityEngine;
using UnityEngine.SceneManagement;

namespace SpikeBalanceMod.Spikes;

/// <summary>
/// Lava zone manager. Continuously scans level geometry around the player and
/// detects player contact with pure arithmetic (no physics overlap dependency).
/// </summary>
internal sealed class SpikeField
{
    private readonly Config _cfg;
    private readonly List<SpikeZone> _zones = new();
    private readonly HashSet<long> _cells = new();
    private float _worldScanTimer;

    public int Count => _zones.Count;

    public SpikeField(Config cfg) => _cfg = cfg;

    public void Clear()
    {
        foreach (var z in _zones)
        {
            if (z != null)
                Object.Destroy(z.gameObject);
        }
        _zones.Clear();
        _cells.Clear();
        _worldScanTimer = 0f;
    }

    /// <summary>
    /// Always-running scan around the player. Walks every scene root, finds upward-facing
    /// static floor colliders within range, fills them with lava zones. Self-healing.
    /// </summary>
    public void TickWorldScan(ENT_Player player, float dt)
    {
        _worldScanTimer += dt;
        if (_worldScanTimer < _cfg.WorldScanInterval.Value)
            return;
        _worldScanTimer = 0f;
        ScanScene(player);
    }

    public void ForceScan(ENT_Player player) => ScanScene(player);

    private void ScanScene(ENT_Player player)
    {
        var scene = player.gameObject.scene;
        if (!scene.IsValid())
            return;

        var minUp = LevelGeom.MinUpDot(_cfg.MaxTiltDegrees.Value);
        var spacing = _cfg.SpikeSpacing.Value;
        var cap = _cfg.MaxZones.Value;
        var before = _zones.Count;
        var playerPos = player.transform.position;
        var horizMax = _cfg.WorldScanHorizRange.Value;
        var vertMax = _cfg.WorldScanVertRange.Value;
        var horizMaxSq = horizMax * horizMax;

        foreach (var root in scene.GetRootGameObjects())
        {
            if (_zones.Count >= cap)
                break;
            ScanRoot(root, minUp, spacing, scene, cap, playerPos, horizMaxSq, vertMax);
        }

        var added = _zones.Count - before;
        if (added > 0)
            Plugin.LogInfo($"Lava scan: +{added} zones (total {_zones.Count}) near ({playerPos.x:F0},{playerPos.y:F0},{playerPos.z:F0})");
    }

    private void ScanRoot(GameObject root, float minUp, float spacing, Scene scene, int cap,
                          Vector3 playerPos, float horizMaxSq, float vertMax)
    {
        var colliders = root.GetComponentsInChildren<Collider>(includeInactive: false);
        foreach (var col in colliders)
        {
            if (_zones.Count >= cap)
                return;
            if (!LevelGeom.IsFloorCollider(col))
                continue;

            var b = col.bounds;
            var dxc = Mathf.Max(0f, Mathf.Abs(b.center.x - playerPos.x) - b.extents.x);
            var dzc = Mathf.Max(0f, Mathf.Abs(b.center.z - playerPos.z) - b.extents.z);
            var dyc = Mathf.Max(0f, Mathf.Abs(b.center.y - playerPos.y) - b.extents.y);
            if (dxc * dxc + dzc * dzc > horizMaxSq)
                continue;
            if (dyc > vertMax)
                continue;

            FillCollider(col, minUp, spacing, scene, cap);
        }
    }

    private void FillCollider(Collider col, float minUp, float spacing, Scene scene, int cap)
    {
        var bounds = col.bounds;
        if (bounds.size.x < 0.2f && bounds.size.z < 0.2f)
            return;

        var step = Mathf.Max(spacing * 0.55f, 0.55f);
        var probeY = bounds.max.y + 0.2f;

        for (var x = bounds.min.x; x <= bounds.max.x + 0.01f; x += step)
        {
            for (var z = bounds.min.z; z <= bounds.max.z + 0.01f; z += step)
            {
                if (_zones.Count >= cap)
                    return;

                var probe = new Vector3(x, probeY, z);
                if (!Physics.Raycast(probe, Vector3.down, out var hit, bounds.size.y + 1f, ~0,
                        QueryTriggerInteraction.Ignore))
                    continue;
                if (!IsHitOnCollider(hit, col))
                    continue;
                if (!LevelGeom.IsFloorHit(hit, minUp))
                    continue;

                SpawnZone(hit.point, hit.normal, spacing, scene);
            }
        }
    }

    private static bool IsHitOnCollider(RaycastHit hit, Collider target)
    {
        if (hit.collider == target)
            return true;
        return hit.collider.transform.IsChildOf(target.transform) ||
               target.transform.IsChildOf(hit.collider.transform);
    }

    private void SpawnZone(Vector3 surface, Vector3 normal, float spacing, Scene scene)
    {
        var n = normal.normalized;
        var zoneRadius = Mathf.Clamp(spacing * 0.45f, 0.4f, 0.7f);
        var pos = surface + n * 0.03f;
        var cell = CellKey(pos, spacing);
        if (!_cells.Add(cell))
            return;

        var go = new GameObject("LavaZone");
        if (scene.IsValid())
            SceneManager.MoveGameObjectToScene(go, scene);

        go.transform.position = pos;
        go.transform.rotation = Quaternion.FromToRotation(Vector3.up, n);

        var zone = go.AddComponent<SpikeZone>();
        zone.Setup(zoneRadius);
        _zones.Add(zone);

        if (_cfg.ShowVisuals.Value)
            BuildVisual(go, spacing);
    }

    /// <summary>
    /// Pure-arithmetic detection: zone center horizontal distance vs. player feet/body,
    /// with a vertical window. No physics queries, no Rigidbody messages.
    /// </summary>
    public bool PlayerOnLava(ENT_Player player, out float nearestHoriz, out int candidates)
    {
        nearestHoriz = float.MaxValue;
        candidates = 0;
        if (_zones.Count == 0)
            return false;

        var touch = _cfg.TouchDistance.Value;
        var vertAbove = _cfg.VerticalAbove.Value;
        var vertBelow = _cfg.VerticalBelow.Value;
        var body = player.transform.position;
        var feet = GameRefs.FeetPosition(player);

        var touched = false;

        foreach (var zone in _zones)
        {
            if (zone == null)
                continue;
            var zp = zone.transform.position;

            // Vertical window: zone Y must be within reach below the player feet.
            //   feet.y - zp.y > 0  → zone is below feet (we're standing on it / above it)
            //   feet.y - zp.y < 0  → zone is above feet (we may be hugging a floor from below)
            var dyFeet = feet.y - zp.y;
            if (dyFeet > vertAbove || dyFeet < -vertBelow)
                continue;

            candidates++;

            // Use minimum of body and feet horizontal distance for safety against
            // player root being offset from the actual collider footprint.
            var dxF = body.x - zp.x;
            var dzF = body.z - zp.z;
            var horizSq = dxF * dxF + dzF * dzF;
            var horiz = Mathf.Sqrt(horizSq);
            if (horiz < nearestHoriz)
                nearestHoriz = horiz;

            if (horiz <= zone.Radius + touch)
                touched = true;
        }

        if (nearestHoriz == float.MaxValue)
            nearestHoriz = -1f;
        return touched;
    }

    public void PruneFar(Vector3 playerPos, float maxDistance)
    {
        if (_zones.Count < _cfg.MaxZones.Value * 0.9f)
            return;

        var maxSq = maxDistance * maxDistance;
        for (var i = _zones.Count - 1; i >= 0; i--)
        {
            var z = _zones[i];
            if (z == null)
            {
                _zones.RemoveAt(i);
                continue;
            }
            if ((z.transform.position - playerPos).sqrMagnitude > maxSq)
            {
                Object.Destroy(z.gameObject);
                _zones.RemoveAt(i);
            }
        }
    }

    private static void BuildVisual(GameObject host, float spacing)
    {
        var mat = VisualMaterial.Get();
        var scale = Mathf.Clamp(spacing * 0.4f, 0.5f, 1.2f);
        for (var i = 0; i < 4; i++)
        {
            var peg = GameObject.CreatePrimitive(PrimitiveType.Cube);
            peg.transform.SetParent(host.transform, false);
            var a = i * Mathf.PI * 0.5f;
            peg.transform.localPosition = new Vector3(Mathf.Cos(a), 0.06f, Mathf.Sin(a)) * scale * 0.22f;
            peg.transform.localRotation = Quaternion.identity;
            peg.transform.localScale = new Vector3(0.08f, 0.18f, 0.08f);
            Object.Destroy(peg.GetComponent<Collider>());
            peg.GetComponent<Renderer>()!.sharedMaterial = mat;
        }

        var pad = GameObject.CreatePrimitive(PrimitiveType.Cube);
        pad.transform.SetParent(host.transform, false);
        pad.transform.localPosition = new Vector3(0f, 0.005f, 0f);
        pad.transform.localRotation = Quaternion.identity;
        pad.transform.localScale = new Vector3(scale * 0.7f, 0.01f, scale * 0.7f);
        Object.Destroy(pad.GetComponent<Collider>());
        pad.GetComponent<Renderer>()!.sharedMaterial = mat;
    }

    private static long CellKey(Vector3 p, float spacing)
    {
        unchecked
        {
            var ix = (long)Mathf.FloorToInt(p.x / spacing);
            var iy = (long)Mathf.FloorToInt(p.y / spacing);
            var iz = (long)Mathf.FloorToInt(p.z / spacing);
            return (ix * 73856093L) ^ (iy * 19349663L) ^ (iz * 83492791L);
        }
    }

    private static class VisualMaterial
    {
        private static Material? _m;

        public static Material Get()
        {
            if (_m != null)
                return _m;
            var shader = Shader.Find("Sprites/Default") ?? Shader.Find("Unlit/Color");
            _m = new Material(shader!) { color = new Color(1f, 0.25f, 0.02f, 0.95f) };
            return _m;
        }
    }
}

using HarmonyLib;

namespace SpikeBalanceMod;

[HarmonyPatch(typeof(ENT_Player), "Start")]
internal static class PlayerStartPatch
{
    static void Postfix() => Plugin.Instance?.NotifyPlayerSpawned();
}

/// <summary>Best-effort hook: trigger an extra scan when a room loads. Not required for
/// generation to keep working — the continuous world scan will find new rooms anyway.</summary>
[HarmonyPatch(typeof(HandholdManager), nameof(HandholdManager.LoadHandholds))]
internal static class RoomLoadedPatch
{
