}

internal static class HarmonySetup
{
    private static readonly System.Type HandType = AccessTools.Inner(typeof(ENT_Player), "Hand")!;

    public static void Apply(Harmony h)
    {
        h.PatchAll(typeof(Plugin).Assembly);

        h.Patch(
