using BepInEx;
using BepInEx.Logging;
using HarmonyLib;
using SpikeBalanceMod.Spikes;
using UnityEngine;

namespace SpikeBalanceMod;

[BepInPlugin(Id, Name, Version)]
public sealed class Plugin : BaseUnityPlugin
{
    public const string Id = "com.thefloorislava.whiteknuckle";
    public const string Name = "The Floor Is Lava";
    public const string Version = "1.1.0";

    public static Plugin? Instance { get; private set; }
    private static ManualLogSource Log => Instance!.Logger;

    private Config? _cfg;
    private HealthPool? _hp;
    private HealthBar? _ui;
    private SpikeField? _lava;
    private Grip? _grip;
    private Harmony? _harmony;

    private bool _run;
    private float _offSpikeTimer;
    private float _statusTimer;
    private float _damageTickTimer;
    private bool _onSpikes;

    private void Awake()
    {
        Instance = this;
        _cfg = new Config(Config);
        _hp = new HealthPool();
        _ui = new HealthBar();
        _lava = new SpikeField(_cfg);
        _grip = new Grip();
        _harmony = new Harmony(Id);
        HarmonySetup.Apply(_harmony);
        LogInfo($"{Name} v{Version}");
    }

    private void OnDestroy()
    {
        _harmony?.UnpatchSelf();
        _ui?.Destroy();
        Instance = null;
    }

    public void NotifyPlayerSpawned() => TryStartRun();

    public void NotifyRoomLoaded()
    {
        if (!_run)
            return;
        var p = GameRefs.Player();
        if (p == null)
            return;
        LogInfo("Room loaded — forcing lava scan.");
        _lava!.ForceScan(p);
    }

    private void Update()
    {
        if (ShouldStopRun())
        {
            StopRun();
            return;
        }

        var player = GameRefs.Player();
        if (!_run)
        {
            if (player != null && GameRefs.InRun(player))
                StartRun(player);
            return;
        }

        ModState.RunActive = true;

        if (player == null)
        {
            if (!_hp!.Dead)
                _ui!.Show(_hp.Current, _hp.Max);
            return;
        }

        if (_hp!.Dead)
        {
            _ui!.Hide();
            return;
        }

        // Continuous world scan — adds new lava as the player climbs into new rooms.
        _lava!.TickWorldScan(player, Time.deltaTime);

        // Always paint the health bar.
        _ui!.Show(_hp.Current, _hp.Max);

        var onSpikes = _lava.PlayerOnLava(player, out var nearestHoriz, out var candidates);
        ModState.OnSpikeZone = onSpikes;

        if (onSpikes && !_onSpikes)
            _grip!.Enter(player);
        else if (!onSpikes && _onSpikes)
            _grip!.Exit(player);

        _onSpikes = onSpikes;

        if (onSpikes)
        {
            _offSpikeTimer = 0f;
            var dmg = _cfg!.SpikeDps.Value * Time.deltaTime;
            _hp.Damage(dmg);

            _damageTickTimer += Time.deltaTime;
            if (_damageTickTimer >= 1f)
            {
                _damageTickTimer = 0f;
                LogInfo($"LAVA DAMAGE applied: hp={_hp.Current:F1}/{_hp.Max:F0} (dps={_cfg.SpikeDps.Value:F1})");
            }
        }
        else
        {
            _damageTickTimer = 0f;
            _offSpikeTimer += Time.deltaTime;
            if (_offSpikeTimer >= _cfg!.HealthRegenDelay.Value)
                _hp.Heal(_cfg.HealthRegen.Value * Time.deltaTime);
        }

        if (_cfg!.DebugLog.Value)
        {
            _statusTimer += Time.deltaTime;
            if (_statusTimer >= 1f)
            {
                _statusTimer = 0f;
                var feet = GameRefs.FeetPosition(player);
                LogInfo(
                    $"status: onLava={onSpikes} hp={_hp.Current:F0} zones={_lava.Count} " +
                    $"candidates={candidates} nearestH={(nearestHoriz < 0 ? "n/a" : nearestHoriz.ToString("F2") + "m")} " +
                    $"feet=({feet.x:F1},{feet.y:F1},{feet.z:F1}) body=({player.transform.position.x:F1},{player.transform.position.y:F1},{player.transform.position.z:F1})");
            }
        }
    }

    private void FixedUpdate()
    {
        if (!_run || !ModState.OnSpikeZone)
            return;
        var p = GameRefs.Player();
        if (p != null)
            _grip!.Regen(p, Time.fixedDeltaTime, _cfg!.GripRegen.Value);
    }

    private void TryStartRun()
    {
        var p = GameRefs.Player();
        if (p != null && GameRefs.InRun(p))
            StartRun(p);
    }

    private void StartRun(ENT_Player player)
    {
        if (_run)
            return;

        _run = true;
        ModState.RunActive = true;
        ModState.OnSpikeZone = false;
        _onSpikes = false;
        _offSpikeTimer = 0f;
        _statusTimer = 0f;
        _damageTickTimer = 0f;
        _hp!.Reset(100f);
        _lava!.Clear();
        _lava.ForceScan(player);
        _ui!.Show(_hp.Current, _hp.Max);
        LogInfo($"Run started ({player.gameObject.scene.name})");
    }

    private bool ShouldStopRun()
    {
        if (!_run)
            return false;
        if (GameRefs.RunEndedCheck())
            return true;
        var p = GameRefs.Player();
        return p != null && GameRefs.IsMenu(p.gameObject.scene.name);
    }

    private void StopRun()
    {
        if (!_run)
            return;

        var p = GameRefs.Player();
        if (p != null && _onSpikes)
            _grip!.Exit(p);

        _run = false;
        ModState.RunActive = false;
        ModState.OnSpikeZone = false;
        _onSpikes = false;
        _lava?.Clear();
        _ui?.Hide();
    }

    public static void LogInfo(string msg) => Log?.LogInfo(msg);
}

