using UnityEngine;
using UnityEngine.UI;

namespace SpikeBalanceMod;

/// <summary>
/// Health bar with an inverse-mask number that flips contrast depending on what's
/// behind it:
///   - The text is drawn TWICE: once in dark color, once in light color.
///   - The dark copy is masked by the red fill, so it shows on top of the red.
///   - The light copy sits beneath the fill, so it shows where the dark bg shows
///     through.
/// Result: numbers always have contrast regardless of fill amount.
/// </summary>
internal sealed class HealthBar
{
    private GameObject? _root;
    private Image? _fill;
    private Text? _textLight;
    private Text? _textDark;

    public void Show(float current, float max)
    {
        Build();
        if (_root != null)
            _root.SetActive(true);
        if (_fill == null || _textLight == null || _textDark == null)
            return;

        var fillAmount = max > 0f ? Mathf.Clamp01(current / max) : 0f;
        _fill.fillAmount = fillAmount;

        var label = Mathf.CeilToInt(Mathf.Max(0f, current)).ToString();
        _textLight.text = label;
        _textDark.text = label;
    }

    public void Hide()
    {
        if (_root != null)
            _root.SetActive(false);
    }

    public void Destroy()
    {
        if (_root != null)
            Object.Destroy(_root);
        _root = null;
        _fill = null;
        _textLight = null;
        _textDark = null;
    }

    private void Build()
    {
        if (_root != null)
            return;

        _root = new GameObject("TheFloorIsLava_HealthUI");
        Object.DontDestroyOnLoad(_root);

        var canvas = _root.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.ScreenSpaceOverlay;
        canvas.sortingOrder = 9500;
        _root.AddComponent<CanvasScaler>().uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;

        var sprite = WhiteSprite();
        var darkBg = new Color(0.06f, 0.06f, 0.08f, 0.92f);
        var redFill = new Color(0.9f, 0.12f, 0.1f);

        // BG container — dark background of the bar
        var bg = new GameObject("BG");
        bg.transform.SetParent(_root.transform, false);
        var bgR = bg.AddComponent<RectTransform>();
        bgR.anchorMin = new Vector2(0.5f, 1f);
        bgR.anchorMax = new Vector2(0.5f, 1f);
        bgR.pivot = new Vector2(0.5f, 1f);
        bgR.anchoredPosition = new Vector2(0f, -8f);
        bgR.sizeDelta = new Vector2(280f, 22f);
        var bgImg = bg.AddComponent<Image>();
        bgImg.sprite = sprite;
        bgImg.color = darkBg;

        // Light text — visible where the dark BG shows through (low HP)
        _textLight = MakeText(bg.transform, "HP-Light", Color.white);

        // Fill — red, horizontally filled, with Mask so children are clipped to the fill
        var fillGo = new GameObject("Fill");
        fillGo.transform.SetParent(bg.transform, false);
        var fillR = fillGo.AddComponent<RectTransform>();
        fillR.anchorMin = Vector2.zero;
        fillR.anchorMax = Vector2.one;
        fillR.offsetMin = Vector2.zero;
        fillR.offsetMax = Vector2.zero;
        _fill = fillGo.AddComponent<Image>();
        _fill.sprite = sprite;
        _fill.color = redFill;
        _fill.type = Image.Type.Filled;
        _fill.fillMethod = Image.FillMethod.Horizontal;
        _fill.fillOrigin = (int)Image.OriginHorizontal.Left;
        var mask = fillGo.AddComponent<Mask>();
        mask.showMaskGraphic = true;

        // Dark text — child of the fill, so it's masked to the red region only.
        _textDark = MakeText(fillGo.transform, "HP-Dark", new Color(0.04f, 0.04f, 0.06f));
    }

    private static Text MakeText(Transform parent, string name, Color color)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent, false);
        var r = go.AddComponent<RectTransform>();
        r.anchorMin = Vector2.zero;
        r.anchorMax = Vector2.one;
        r.offsetMin = Vector2.zero;
        r.offsetMax = Vector2.zero;
        var t = go.AddComponent<Text>();
        t.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        t.alignment = TextAnchor.MiddleCenter;
        t.fontStyle = FontStyle.Bold;
        t.color = color;
        t.fontSize = 14;
        t.horizontalOverflow = HorizontalWrapMode.Overflow;
        t.verticalOverflow = VerticalWrapMode.Overflow;
        return t;
    }

    private static Sprite? _white;

    private static Sprite WhiteSprite()
    {
        if (_white != null)
            return _white;
        var t = new Texture2D(1, 1);
        t.SetPixel(0, 0, Color.white);
        t.Apply();
        _white = Sprite.Create(t, new Rect(0, 0, 1, 1), new Vector2(0.5f, 0.5f));
        return _white;
    }
}

