private static void BuildVisual(GameObject host, float spacing)
{
    var mat = VisualMaterial.Get();
    var coneMesh = ConeMesh.Get();
    var scale = Mathf.Clamp(spacing * 0.4f, 0.5f, 1.2f);

    // Cluster of cone-shaped spikes — one centered + three around it.
    SpawnCone(host.transform, coneMesh, mat, Vector3.zero, scale * 0.22f, scale * 0.55f);
    for (var i = 0; i < 3; i++)
    {
        var a = i * Mathf.PI * 2f / 3f + 0.4f;
        var offset = new Vector3(Mathf.Cos(a), 0f, Mathf.Sin(a)) * scale * 0.28f;
        SpawnCone(host.transform, coneMesh, mat, offset, scale * 0.14f, scale * 0.36f);
    }
}

private static void SpawnCone(Transform parent, Mesh mesh, Material mat, Vector3 localPos,
                              float radius, float height)
{
    var go = new GameObject("Spike");
    go.transform.SetParent(parent, false);
    go.transform.localPosition = localPos;
    go.transform.localRotation = Quaternion.identity;
    go.transform.localScale = new Vector3(radius, height, radius);
    go.AddComponent<MeshFilter>().sharedMesh = mesh;
    go.AddComponent<MeshRenderer>().sharedMaterial = mat;
}

