    private static class VisualMaterial
    {
        private static Material? _m;

        public static Material Get()
        {
            if (_m != null)
                return _m;

            // Dark metal: try Standard shader first for metallic look, fall back to Diffuse.
            var color = new Color(0.18f, 0.18f, 0.21f, 1f);
            var standard = Shader.Find("Standard");
            if (standard != null)
            {
                _m = new Material(standard) { color = color };
                if (_m.HasProperty("_Metallic"))
                    _m.SetFloat("_Metallic", 0.95f);
                if (_m.HasProperty("_Glossiness"))
                    _m.SetFloat("_Glossiness", 0.65f);
                return _m;
            }

            var fallback = Shader.Find("Legacy Shaders/Diffuse")
                          ?? Shader.Find("Unlit/Color")
                          ?? Shader.Find("Sprites/Default");
            _m = new Material(fallback!) { color = color };
            return _m;
        }
    }

    private static class ConeMesh
    {
        private static Mesh? _mesh;

        public static Mesh Get()
        {
            if (_mesh != null)
                return _mesh;
            _mesh = Build(segments: 12);
            return _mesh;
        }

        private static Mesh Build(int segments)
        {
            // Unit cone: base on Y=0 with radius 1, tip at Y=1.
            var verts = new Vector3[segments * 2 + 2];
            var normals = new Vector3[verts.Length];
            var tris = new int[segments * 6];

            verts[0] = new Vector3(0f, 1f, 0f);
            normals[0] = Vector3.up;

            for (var i = 0; i < segments; i++)
            {
                var a = i / (float)segments * Mathf.PI * 2f;
                var c = Mathf.Cos(a);
                var s = Mathf.Sin(a);
                verts[1 + i] = new Vector3(c, 0f, s);
                normals[1 + i] = new Vector3(c, 0.4f, s).normalized;
                verts[1 + segments + i] = new Vector3(c, 0f, s);
                normals[1 + segments + i] = Vector3.down;
            }

            verts[verts.Length - 1] = Vector3.zero;
            normals[verts.Length - 1] = Vector3.down;

            var t = 0;
            for (var i = 0; i < segments; i++)
            {
                var v0 = 1 + i;
                var v1 = 1 + (i + 1) % segments;
                tris[t++] = 0;
                tris[t++] = v1;
                tris[t++] = v0;
            }
            for (var i = 0; i < segments; i++)
            {
                var v0 = 1 + segments + i;
                var v1 = 1 + segments + (i + 1) % segments;
                tris[t++] = verts.Length - 1;
                tris[t++] = v0;
                tris[t++] = v1;
            }

            var mesh = new Mesh { name = "TheFloorIsLava_Cone" };
            mesh.vertices = verts;
            mesh.normals = normals;
            mesh.triangles = tris;
            mesh.RecalculateBounds();
            return mesh;
        }
    }
}

