using BepInEx.Configuration;

namespace SpikeBalanceMod;

internal sealed class Config
{
    // ---- Player resource pool ----
    public ConfigEntry<float> MaxHealth { get; }
    public ConfigEntry<float> SpikeDps { get; }
    public ConfigEntry<float> HealthRegen { get; }
    public ConfigEntry<float> HealthRegenDelay { get; }
    public ConfigEntry<float> GripRegen { get; }

    // ---- Lava placement ----
    public ConfigEntry<float> MaxTiltDegrees { get; }
    public ConfigEntry<float> SpikeSpacing { get; }
    public ConfigEntry<int> MaxZones { get; }
    public ConfigEntry<float> WorldScanInterval { get; }
    public ConfigEntry<float> WorldScanHorizRange { get; }
    public ConfigEntry<float> WorldScanVertRange { get; }
    public ConfigEntry<float> TouchDistance { get; }
    public ConfigEntry<float> VerticalAbove { get; }
    public ConfigEntry<float> VerticalBelow { get; }
    public ConfigEntry<bool> ShowVisuals { get; }

    // ---- Misc ----
    public ConfigEntry<bool> DebugLog { get; }

    public Config(ConfigFile file)
    {
        MaxHealth = file.Bind("Balance", "MaxHealth", 100f,
            "Maximum mod HP. The bar fills to this value at run start and after healing.");
        SpikeDps = file.Bind("Balance", "LavaDamagePerSecond", 15f,
            "Mod HP lost per second while standing on lava.");
        HealthRegen = file.Bind("Balance", "HealthRegenPerSecond", 10f,
            "Mod HP regenerated per second once the regen delay has elapsed.");
        HealthRegenDelay = file.Bind("Balance", "HealthRegenDelay", 2f,
            "Seconds without taking lava damage before HP starts regenerating.");
        GripRegen = file.Bind("Balance", "GripRegenPerSecond", 0.4f,
            "Hand grip strength regenerated per second while standing on lava.");

        MaxTiltDegrees = file.Bind("Lava", "MaxTiltDegrees", 20f,
            "Max surface tilt from horizontal (degrees) that still counts as 'upward-facing'.");
        SpikeSpacing = file.Bind("Lava", "Spacing", 1.6f,
            "Distance between lava zone centers in the surface grid.");
        MaxZones = file.Bind("Lava", "MaxZones", 12000,
            "Maximum number of lava zones present at once.");
        WorldScanInterval = file.Bind("Lava", "WorldScanInterval", 1.0f,
            "Seconds between continuous world scans for newly loaded geometry.");
        WorldScanHorizRange = file.Bind("Lava", "WorldScanHorizRange", 80f,
            "Max horizontal distance from the player to scan for new floors.");
        WorldScanVertRange = file.Bind("Lava", "WorldScanVertRange", 60f,
            "Max vertical distance from the player to scan (up & down).");
        TouchDistance = file.Bind("Lava", "TouchDistance", 1.4f,
            "Extra horizontal distance to a zone center for it to count as 'on lava'.");
        VerticalAbove = file.Bind("Lava", "VerticalAbove", 1.8f,
            "Max feet height above a zone to still count as standing on it.");
        VerticalBelow = file.Bind("Lava", "VerticalBelow", 1f,
            "Max feet height below a zone to still count as touching it.");
        ShowVisuals = file.Bind("Lava", "ShowVisuals", true,
            "Show dark-metal spike cones on every floor zone.");

        DebugLog = file.Bind("Debug", "LogStatus", true,
            "Log lava state and damage diagnostics every second.");
    }
}

content.text:
Build clean. **TheFloorIsLava.dll v1.2.0** deployed.

### Summary of changes

**1. Cone-shaped dark-metal spike model** — `Spikes/SpikeField.cs`
Replaced the orange cube pegs with a procedurally generated cone mesh (12-segment, single shared `Mesh`/`Material` for performance). Each lava zone now spawns 1 large center cone + 3 smaller ones in a cluster. The material uses Unity's `Standard` shader with Metallic=0.95 / Glossiness=0.65 and a dark gunmetal color, falling back to Legacy Diffuse if Standard isn't loaded.

**2. Player dies when mod HP hits 0** — `Plugin.cs` + `GameRefs.cs`
Found `UT_DamagePlayer.DamagePlayer(float)` in the game's API. When `HealthPool.Dead` flips true, `Plugin.Update` calls `GameRefs.KillPlayer()` exactly once (`_deathTriggered` guards against re-entry), which runs lethal damage through the game's own pipeline so all the normal death effects play.

**3. Starting bottom floor exempt** — `Spikes/SpikeField.cs`
`StartRun` now calls `_lava.ExcludeStartingFloor(player)`. That casts a ray straight down from the player on spawn, records the hit collider's `InstanceID` in `_excludedColliders`, and `ScanRoot` skips any collider whose ID is in that set. So the spawn pad stays lava-free for the whole run while every other floor still gets coated.

**4. Inverse-mask HP number** — `HealthBar.cs`
The text is now drawn twice with a UI `Mask`:

```68:107:c:\Users\TFS\Documents\projects\White Knuckle Mod\SpikeBalanceMod\HealthBar.cs
        var bg = new GameObject("BG");
        bg.transform.SetParent(_root.transform, false);
        var bgR = bg.AddComponent<RectTransform>();
        bgR.anchorMin = new Vector2(0.5f, 1f);
        bgR.anchorMax = new Vector2(0.5f, 1f);
        bgR.pivot = new Vector2(0.5f, 1f);
        bgR.anchoredPosition = new Vector2(0f, -8f);
        bgR.sizeDelta = new Vector2(280f, 22f);
        var bgImg = bg.AddComponent<Image>();
        bgImg.sprite = sprite;
        bgImg.color = darkBg;

        _textLight = MakeText(bg.transform, "HP-Light", Color.white);

        var fillGo = new GameObject("Fill");
```

- Background is now dark navy/black (no more white-on-white clash).
- **Light text** (white) sits behind the fill — visible wherever the dark background shows through.
- **Dark text** (near-black) is a child of the red `Fill` image which has a `Mask` component, so it only renders inside the filled portion.
- Result: numbers always have contrast — white over the dark empty area, black over the red filled area, no matter the fill level.

**5. Configurable regen** — `Config.cs`
The `[Balance]` section now leads the config file with five clearly-named, fully end-user-configurable values:

```csharp
MaxHealth                  = 100f
LavaDamagePerSecond        = 15f
HealthRegenPerSecond       = 10f
HealthRegenDelay           = 2f
GripRegenPerSecond         = 0.4f
```

