/// <summary>
/// Walk every Renderer in the scene, find one near the player whose material
/// has an actual texture, clone its material (preserves shader + texture), and
/// tint it. The clone approach avoids any "Standard shader missing" issues.
/// </summary>
private void TrySampleLevelTexture(Scene scene, Vector3 playerPos)
{
    var rangeSq = 200f * 200f;
    var inspected = 0;
    var withMat = 0;
    var withTex = 0;

    foreach (var root in scene.GetRootGameObjects())
    {
        var rends = root.GetComponentsInChildren<Renderer>(includeInactive: false);
        foreach (var rend in rends)
        {
            if (rend == null)
                continue;
            if (rend.GetComponentInParent<SpikeZone>() != null)
                continue;
            inspected++;

            var src = rend.sharedMaterial;
            if (src == null || src.shader == null)
                continue;
            withMat++;

            var tex = ExtractMainTexture(src);
            if (tex == null)
                continue;
            withTex++;

            if ((rend.bounds.center - playerPos).sqrMagnitude > rangeSq && withTex < 4)
                continue;

            var mat = new Material(src) { name = "TheFloorIsLava_Spike" };
            mat.color = new Color(0.75f, 0.7f, 0.65f, 1f);
            if (mat.HasProperty("_Metallic"))
                mat.SetFloat("_Metallic", 0.55f);
            if (mat.HasProperty("_Glossiness"))
                mat.SetFloat("_Glossiness", 0.45f);
            if (mat.HasProperty("_Smoothness"))
                mat.SetFloat("_Smoothness", 0.45f);

            _runtimeSpikeMaterial = mat;
            Plugin.LogInfo(
                $"Sampled level texture for spikes: shader='{src.shader.name}' tex='{tex.name}' " +
                $"from '{rend.name}' (inspected={inspected}, withMat={withMat}, withTex={withTex}).");
            return;
        }
    }

    Plugin.LogInfo(
        $"No textured level renderer found yet (inspected={inspected}, withMat={withMat}, withTex={withTex}). " +
        "Falling back to dark-metal material.");
}

private static Texture? ExtractMainTexture(Material m)
{
    if (m.HasProperty("_MainTex"))
    {
        var t = m.GetTexture("_MainTex");
        if (t != null) return t;
    }
    if (m.HasProperty("_BaseMap"))
    {
        var t = m.GetTexture("_BaseMap");
        if (t != null) return t;
    }
    if (m.HasProperty("_BaseColorMap"))
    {
        var t = m.GetTexture("_BaseColorMap");
        if (t != null) return t;
    }
    return m.mainTexture;
}

