private void SpawnZone(Vector3 surface, Vector3 normal, float spacing, Scene scene)
{
    var n = normal.normalized;
    var zoneRadius = Mathf.Clamp(spacing * 0.5f, 0.45f, 0.8f);
    var pos = surface + n * 0.03f;
    var cell = CellKey(pos, spacing);
    if (!_cells.Add(cell))
        return;

    var go = new GameObject("LavaSpike");
    if (scene.IsValid())
        SceneManager.MoveGameObjectToScene(go, scene);

    go.transform.position = pos;

    // Deterministic noise per spike so it's stable across rescans of the same
    // location: hash the world position into per-instance yaw, tilt and scale.
    var seed = HashPosition(pos);
    var rng = new System.Random(seed);
    var yaw = (float)rng.NextDouble() * 360f;
    var tiltDeg = (float)(rng.NextDouble() * _cfg.SpikeTiltDegrees.Value);
    var tiltDir = (float)rng.NextDouble() * 360f;
    var scaleNoise = (float)(rng.NextDouble() * 2.0 - 1.0); // -1 .. 1
    var scaleMul = 1f + scaleNoise * _cfg.SpikeScaleJitter.Value;

    var baseRot = Quaternion.FromToRotation(Vector3.up, n);
    var yawRot = Quaternion.AngleAxis(yaw, Vector3.up);
    var tiltAxis = new Vector3(Mathf.Cos(tiltDir * Mathf.Deg2Rad), 0f, Mathf.Sin(tiltDir * Mathf.Deg2Rad));
    var tiltRot = Quaternion.AngleAxis(tiltDeg, tiltAxis);
    go.transform.rotation = baseRot * tiltRot * yawRot;

    var zone = go.AddComponent<SpikeZone>();
    zone.Setup(zoneRadius);
    _zones.Add(zone);

    if (_cfg.ShowVisuals.Value)
        BuildVisual(go, spacing, _cfg.VisualScale.Value * scaleMul, GetSpikeMaterial());
}

private static int HashPosition(Vector3 p)
{
    unchecked
    {
        var ix = Mathf.RoundToInt(p.x * 10f);
        var iy = Mathf.RoundToInt(p.y * 10f);
        var iz = Mathf.RoundToInt(p.z * 10f);
        return (ix * 73856093) ^ (iy * 19349663) ^ (iz * 83492791);
    }
}

