/// <summary>
/// Walk every Renderer in the scene, find one near the player whose material
/// has a real level texture, then build a fresh spike material using an UNLIT
/// shader so the cones are always visible regardless of scene lighting. We
/// don't clone the level material because its shader keywords / normal-map
/// expectations don't match our procedural cone mesh.
/// </summary>
private void TrySampleLevelTexture(Scene scene, Vector3 playerPos)
{
    var rangeSq = 200f * 200f;
    var inspected = 0;
    var withMat = 0;
    var withTex = 0;
    var goodTex = 0;

    Texture2D? bestTex = null;
    string bestSourceShader = "";
    string bestRendName = "";

    foreach (var root in scene.GetRootGameObjects())
    {
        var rends = root.GetComponentsInChildren<Renderer>(includeInactive: false);
        foreach (var rend in rends)
        {
            if (rend == null) continue;
            if (rend.GetComponentInParent<SpikeZone>() != null) continue;
            inspected++;

            var src = rend.sharedMaterial;
            if (src == null || src.shader == null) continue;
            withMat++;

            var tex = ExtractMainTexture(src);
            if (tex == null) continue;
            withTex++;

            if (tex is not Texture2D t2d) continue;
            if (t2d.width < 128 || t2d.height < 128) continue;
            if (IsLikelyUiTexture(t2d.name, rend.name, src.shader.name)) continue;
            goodTex++;

            if ((rend.bounds.center - playerPos).sqrMagnitude > rangeSq) continue;

            bestTex = t2d;
            bestSourceShader = src.shader.name;
            bestRendName = rend.name;
            goto found;
        }
    }

    if (bestTex == null)
    {
        Plugin.LogInfo(
            $"No suitable level texture found yet (inspected={inspected}, withMat={withMat}, withTex={withTex}, goodTex={goodTex}). " +
            "Falling back to bright-metal material.");
        BuildPlainSpikeMaterial();
        return;
    }

found:
    BuildTexturedSpikeMaterial(bestTex, bestSourceShader, bestRendName, inspected, withMat, withTex, goodTex);
}

private void BuildTexturedSpikeMaterial(Texture2D tex, string sourceShader, string rendName,
                                        int inspected, int withMat, int withTex, int goodTex)
{
    var shader = FindUsableShader(out var shaderName);
    if (shader == null)
    {
        Plugin.LogInfo("No usable shader at all — keeping fallback.");
        return;
    }

    var mat = new Material(shader) { name = "TheFloorIsLava_Spike" };
    ApplyTextureEverywhere(mat, tex);

    // Dark stone tint that matches the level palette (cool charcoal grey with a
    // hint of warmth) so the spikes blend into the surroundings.
    var tint = new Color(0.32f, 0.28f, 0.25f, 1f);
    mat.color = tint;
    SetColorIfPresent(mat, "_BaseColor", tint);
    SetColorIfPresent(mat, "_Color", tint);

    if (mat.HasProperty("_Surface")) mat.SetFloat("_Surface", 0f);
    if (mat.HasProperty("_ZWrite")) mat.SetFloat("_ZWrite", 1f);

    // Subtle warm ember emission so the dark spike still reads against shadowed
    // walls without looking like a separate decoration.
    mat.EnableKeyword("_EMISSION");
    SetColorIfPresent(mat, "_EmissionColor", new Color(0.18f, 0.07f, 0.03f, 1f));
    mat.globalIlluminationFlags = MaterialGlobalIlluminationFlags.None;

    _runtimeSpikeMaterial = mat;
    Plugin.LogInfo(
        $"Spike material built: shader='{shaderName}' tex='{tex.name}' ({tex.width}x{tex.height}) " +
        $"source='{sourceShader}' from '{rendName}' " +
        $"(inspected={inspected}, withMat={withMat}, withTex={withTex}, goodTex={goodTex}).");
}

private void BuildPlainSpikeMaterial()
{
    if (_runtimeSpikeMaterial != null) return;
    var shader = FindUsableShader(out var shaderName);
    if (shader == null) return;
    var mat = new Material(shader) { name = "TheFloorIsLava_Spike_Plain" };
    var tint = new Color(0.28f, 0.25f, 0.23f, 1f);
    mat.color = tint;
    SetColorIfPresent(mat, "_BaseColor", tint);
    SetColorIfPresent(mat, "_Color", tint);
    if (mat.HasProperty("_Surface")) mat.SetFloat("_Surface", 0f);
    mat.EnableKeyword("_EMISSION");
    SetColorIfPresent(mat, "_EmissionColor", new Color(0.22f, 0.08f, 0.03f, 1f));
    _runtimeSpikeMaterial = mat;
    Plugin.LogInfo($"Plain spike material built: shader='{shaderName}' (no level texture yet).");
}

private static void SetColorIfPresent(Material m, string prop, Color c)
{
    if (m.HasProperty(prop)) m.SetColor(prop, c);
}

/// <summary>Unlit-first chain so the cones are always visible regardless of scene lights.</summary>
private static Shader? FindUsableShader(out string name)
{
    string[] candidates =
    {
        "Universal Render Pipeline/Unlit",
        "Unlit/Texture",
        "Universal Render Pipeline/Simple Lit",
        "Universal Render Pipeline/Lit",
        "Standard",
        "Legacy Shaders/Diffuse",
        "Sprites/Default",
    };
    foreach (var n in candidates)
    {
        var s = Shader.Find(n);
        if (s != null) { name = n; return s; }
    }
    name = "";
    return null;
}

private static void ApplyTextureEverywhere(Material mat, Texture tex)
{
    if (mat.HasProperty("_BaseMap")) mat.SetTexture("_BaseMap", tex);
    if (mat.HasProperty("_MainTex")) mat.SetTexture("_MainTex", tex);
    if (mat.HasProperty("_BaseColorMap")) mat.SetTexture("_BaseColorMap", tex);
    if (mat.HasProperty("_EmissionMap")) mat.SetTexture("_EmissionMap", tex);
    mat.mainTexture = tex;
}

private static Texture? ExtractMainTexture(Material m)
{
    if (m.HasProperty("_MainTex"))
    {
        var t = m.GetTexture("_MainTex");
        if (t != null) return t;
    }
    if (m.HasProperty("_BaseMap"))
    {
        var t = m.GetTexture("_BaseMap");
        if (t != null) return t;
    }
    if (m.HasProperty("_BaseColorMap"))
    {
        var t = m.GetTexture("_BaseColorMap");
        if (t != null) return t;
    }
    return m.mainTexture;
}

private static bool IsLikelyUiTexture(string texName, string rendName, string shaderName)
{
    bool BadName(string n) =>
        n.IndexOf("icon", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
        n.IndexOf("ui", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
        n.IndexOf("hud", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
        n.IndexOf("sprite", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
        n.IndexOf("font", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
        n.IndexOf("decal", System.StringComparison.OrdinalIgnoreCase) >= 0;
    return BadName(texName) || BadName(rendName) ||
           shaderName.IndexOf("UI", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
           shaderName.IndexOf("Sprite", System.StringComparison.OrdinalIgnoreCase) >= 0;
}

