/// <summary>
/// Build the procedural lava-patch material (radial heat gradient texture with
/// dirty industrial noise, additive blending, HDR emission) and a companion
/// material for drip ribbons that hang under thin floors.
/// </summary>
private void BuildLavaMaterials()
{
    if (_lavaMaterial != null) return;

    var shader = FindLavaShader(out var shaderName);
    if (shader == null)
    {
        Plugin.LogInfo("No usable shader found for lava patches!");
        return;
    }

    var gradient = LavaTexture.GradientPatch();
    var dripTex = LavaTexture.DripStrip();

    _lavaMaterial = BuildPatchMaterial(shader, gradient, "TheFloorIsLava_Patch");
    _lavaDripMaterial = BuildPatchMaterial(shader, dripTex, "TheFloorIsLava_Drip");

    Plugin.LogInfo(
        $"Lava material built: shader='{shaderName}' " +
        $"patchTex={gradient.width}x{gradient.height} dripTex={dripTex.width}x{dripTex.height}.");
}

private Material BuildPatchMaterial(Shader shader, Texture2D tex, string name)
{
    var mat = new Material(shader) { name = name };
    mat.mainTexture = tex;
    if (mat.HasProperty("_BaseMap")) mat.SetTexture("_BaseMap", tex);
    if (mat.HasProperty("_MainTex")) mat.SetTexture("_MainTex", tex);
    if (mat.HasProperty("_EmissionMap")) mat.SetTexture("_EmissionMap", tex);

    var white = new Color(1f, 1f, 1f, 1f);
    mat.color = white;
    if (mat.HasProperty("_BaseColor")) mat.SetColor("_BaseColor", white);
    if (mat.HasProperty("_Color")) mat.SetColor("_Color", white);

    // Transparent + additive so neighboring patches add up brightness when they
    // overlap — that's what makes adjacent puddles look merged and flowing.
    if (mat.HasProperty("_Surface")) mat.SetFloat("_Surface", 1f);
    if (mat.HasProperty("_Blend")) mat.SetFloat("_Blend", 1f); // Premultiply-ish
    if (mat.HasProperty("_SrcBlend")) mat.SetFloat("_SrcBlend", (float)UnityEngine.Rendering.BlendMode.SrcAlpha);
    if (mat.HasProperty("_DstBlend")) mat.SetFloat("_DstBlend", (float)UnityEngine.Rendering.BlendMode.One);
    if (mat.HasProperty("_ZWrite")) mat.SetFloat("_ZWrite", 0f);
    if (mat.HasProperty("_Cull")) mat.SetFloat("_Cull", 0f);
    if (mat.HasProperty("_AlphaClip")) mat.SetFloat("_AlphaClip", 0f);
    mat.EnableKeyword("_SURFACE_TYPE_TRANSPARENT");
    mat.EnableKeyword("_ALPHABLEND_ON");
    mat.DisableKeyword("_ALPHATEST_ON");
    mat.renderQueue = (int)UnityEngine.Rendering.RenderQueue.Transparent;

    // Strong warm emission so the lava patches glow on top of the gradient even
    // when scene lighting is off (URP/Unlit ignores _EmissionColor; the base
    // texture already encodes the heat colors, so this only kicks in if the
    // shader happens to be lit).
    mat.EnableKeyword("_EMISSION");
    var em = new Color(1.6f, 0.7f, 0.18f) * _cfg.LavaEmissionStrength.Value;
    if (mat.HasProperty("_EmissionColor")) mat.SetColor("_EmissionColor", em);
    mat.globalIlluminationFlags = MaterialGlobalIlluminationFlags.None;
    return mat;
}

private static Shader? FindLavaShader(out string name)
{
    string[] candidates =
    {
        "Universal Render Pipeline/Unlit",
        "Unlit/Transparent",
        "Sprites/Default",
        "Legacy Shaders/Particles/Alpha Blended",
        "Standard",
        "Universal Render Pipeline/Lit",
    };
    foreach (var n in candidates)
    {
        var s = Shader.Find(n);
        if (s != null) { name = n; return s; }
    }
    name = "";
    return null;
}

