private Material GetSpikeMaterial()
{
    if (_runtimeSpikeMaterial != null) return _runtimeSpikeMaterial;
    BuildPlainSpikeMaterial();
    return _runtimeSpikeMaterial ?? VisualMaterial.Get();
}

private static void BuildVisual(GameObject host, float spacing, float visualScale, Material mat)
{
    var coneMesh = ConeMesh.Get();
    var scale = Mathf.Clamp(spacing * 0.4f, 0.5f, 1.2f) * Mathf.Max(0.1f, visualScale);

    // One dominant spike — the cluster is gone in favour of a smoother noise
    // distribution at the surface level. Per-instance rotation/tilt/scale jitter
    // is applied by the caller via the parent transform.
    SpawnCone(host.transform, coneMesh, mat, Vector3.zero, scale * 0.34f, scale * 0.85f);
}

private static void SpawnCone(Transform parent, Mesh mesh, Material mat, Vector3 localPos,
                              float radius, float height)
{
    var go = new GameObject("SpikeMesh");
    go.transform.SetParent(parent, false);
    go.transform.localPosition = localPos;
    go.transform.localRotation = Quaternion.identity;
    go.transform.localScale = new Vector3(radius, height, radius);
    go.AddComponent<MeshFilter>().sharedMesh = mesh;
    go.AddComponent<MeshRenderer>().sharedMaterial = mat;
}

