private void BuildLavaVisual(GameObject host, float spacing, float visualScale,
                             float densityNoise, bool thinFloor, int seed)
{
    if (_lavaMaterial == null)
        BuildLavaMaterials();
    if (_lavaMaterial == null)
        return;

    // Generate a unique irregular patch mesh per instance — varying radius per
    // segment + slight dome height. Density noise nudges the size: cells with
    // higher noise get larger, taller blobs.
    var baseRadius = Mathf.Clamp(spacing * 0.55f, 0.45f, 1.1f) * Mathf.Max(0.2f, visualScale);
    var sizeBoost = 0.8f + densityNoise * 0.6f; // 0.8 .. 1.4
    var radius = baseRadius * sizeBoost;
    var height = _cfg.LavaHeightVariance.Value * (0.4f + densityNoise * 0.8f);
    var shapeJitter = _cfg.LavaShapeJitter.Value;

    var mesh = LavaPatchMesh.Build(seed, radius, height, shapeJitter);

    var patch = new GameObject("LavaPatchMesh");
    patch.transform.SetParent(host.transform, false);
    patch.transform.localPosition = Vector3.zero;
    patch.transform.localRotation = Quaternion.identity;
    patch.transform.localScale = Vector3.one;
    patch.AddComponent<MeshFilter>().sharedMesh = mesh;
    patch.AddComponent<MeshRenderer>().sharedMaterial = _lavaMaterial;

    // Drip ribbon hanging under thin floors. Only for thin floors and only when
    // the density noise picks it (gives drips a natural sparsity).
    if (thinFloor && _lavaDripMaterial != null && densityNoise > 0.45f)
    {
        var dripMesh = LavaPatchMesh.BuildDrip(seed ^ 0x77, radius * 0.35f,
            length: Mathf.Lerp(0.15f, 0.6f, densityNoise));
        var drip = new GameObject("LavaDrip");
        drip.transform.SetParent(host.transform, false);
        drip.transform.localPosition = new Vector3(0f, -0.02f, 0f);
        drip.transform.localRotation = Quaternion.identity;
        drip.transform.localScale = Vector3.one;
        drip.AddComponent<MeshFilter>().sharedMesh = dripMesh;
        drip.AddComponent<MeshRenderer>().sharedMaterial = _lavaDripMaterial;
    }
}

