    private static class VisualMaterial
    {
        private static Material? _m;

        public static Material Get()
        {
            if (_m != null)
                return _m;

            // Brightened metal fallback (used only when no level texture is available).
            var color = new Color(0.45f, 0.43f, 0.42f, 1f);
            var standard = Shader.Find("Standard");
            if (standard != null)
            {
                _m = new Material(standard) { color = color };
                if (_m.HasProperty("_Metallic"))
                    _m.SetFloat("_Metallic", 0.95f);
                if (_m.HasProperty("_Glossiness"))
                    _m.SetFloat("_Glossiness", 0.65f);
                return _m;
            }

            var fallback = Shader.Find("Legacy Shaders/Diffuse")
                          ?? Shader.Find("Unlit/Color")
                          ?? Shader.Find("Sprites/Default");
            _m = new Material(fallback!) { color = color };
            return _m;
        }
    }

    private static class ConeMesh
    {
        private static Mesh? _mesh;

        public static Mesh Get()
        {
            if (_mesh != null)
                return _mesh;
            _mesh = Build(segments: 12);
            return _mesh;
        }

        private static Mesh Build(int segments)
        {
            // Unit cone: base on Y=0 with radius 1, tip at Y=1.
            // We give each side triangle its OWN tip vertex (with a per-tri UV) so the
            // texture wraps without a singularity at the apex, and we generate UVs +
            // tangents so URP / Standard shaders can light & sample correctly.

            var sideVertCount = segments * 3;    // 1 tip + 2 base per side, unique per face
            var capVertCount = segments + 1;     // ring + center
            var totalVerts = sideVertCount + capVertCount;

            var verts = new Vector3[totalVerts];
            var normals = new Vector3[totalVerts];
            var uvs = new Vector2[totalVerts];
            var tris = new int[segments * 6];

            var triIdx = 0;
            for (var i = 0; i < segments; i++)
            {
                var a0 = i / (float)segments * Mathf.PI * 2f;
                var a1 = (i + 1) / (float)segments * Mathf.PI * 2f;
                var c0 = Mathf.Cos(a0); var s0 = Mathf.Sin(a0);
                var c1 = Mathf.Cos(a1); var s1 = Mathf.Sin(a1);

                var baseIdx = i * 3;
                var vTip = baseIdx;
                var vB0 = baseIdx + 1;
                var vB1 = baseIdx + 2;

                verts[vTip] = new Vector3(0f, 1f, 0f);
                verts[vB0] = new Vector3(c0, 0f, s0);
                verts[vB1] = new Vector3(c1, 0f, s1);

                // Face normal: lean outward and a bit up
                var n0 = new Vector3(c0, 0.5f, s0).normalized;
                var n1 = new Vector3(c1, 0.5f, s1).normalized;
                var nTip = ((n0 + n1) * 0.5f).normalized;
                normals[vTip] = nTip;
                normals[vB0] = n0;
                normals[vB1] = n1;

                uvs[vTip] = new Vector2((i + 0.5f) / segments, 1f);
                uvs[vB0] = new Vector2(i / (float)segments, 0f);
                uvs[vB1] = new Vector2((i + 1f) / segments, 0f);

                tris[triIdx++] = vTip;
                tris[triIdx++] = vB1;
                tris[triIdx++] = vB0;
            }

            var ringStart = sideVertCount;
            var centerIdx = totalVerts - 1;
            for (var i = 0; i < segments; i++)
            {
                var a = i / (float)segments * Mathf.PI * 2f;
                var c = Mathf.Cos(a);
                var s = Mathf.Sin(a);
                var idx = ringStart + i;
                verts[idx] = new Vector3(c, 0f, s);
                normals[idx] = Vector3.down;
                uvs[idx] = new Vector2((c + 1f) * 0.5f, (s + 1f) * 0.5f);
            }
            verts[centerIdx] = Vector3.zero;
            normals[centerIdx] = Vector3.down;
            uvs[centerIdx] = new Vector2(0.5f, 0.5f);

            // Append base-cap triangles (wind to face down).
            var capTris = new int[segments * 3];
            for (var i = 0; i < segments; i++)
            {
                capTris[i * 3 + 0] = centerIdx;
                capTris[i * 3 + 1] = ringStart + i;
                capTris[i * 3 + 2] = ringStart + (i + 1) % segments;
            }

            var allTris = new int[tris.Length + capTris.Length];
            tris.CopyTo(allTris, 0);
            capTris.CopyTo(allTris, tris.Length);

            var mesh = new Mesh { name = "TheFloorIsLava_Cone" };
            mesh.vertices = verts;
            mesh.normals = normals;
            mesh.uv = uvs;
            mesh.triangles = allTris;
            mesh.RecalculateBounds();
            mesh.RecalculateTangents();
            return mesh;
        }
    }
}

