    /// <summary>Builds the irregular puddle mesh and the optional drip ribbon.
    /// Each mesh is unique per seed so neighbours don't look identical, and the
    /// outline is biased outward in a wobbly noise pattern so adjacent patches
    /// visually overlap and "flow" into one another.</summary>
    private static class LavaPatchMesh
    {
        public static Mesh Build(int seed, float radius, float domeHeight, float shapeJitter)
        {
            const int segments = 18;
            var rng = new System.Random(seed);

            // Two control values per segment used to wobble the outline outward.
            // We pre-sample them so the silhouette stays correlated and looks like
            // a smooth amoeba instead of a noisy zig-zag.
            var radii = new float[segments];
            var heights = new float[segments];
            for (var i = 0; i < segments; i++)
            {
                var u = i / (float)segments;
                var nLow = Mathf.PerlinNoise(seed * 0.001f + u * 2.4f, 1.7f);
                var nHigh = Mathf.PerlinNoise(seed * 0.001f + u * 6.1f, 4.3f) * 0.4f;
                var wobble = (nLow + nHigh - 0.7f) * shapeJitter;
                radii[i] = Mathf.Clamp(1f + wobble, 0.5f, 1.7f);
                heights[i] = (float)rng.NextDouble() * domeHeight * 0.25f;
            }

            // Layout:
            //   verts[0]                       = raised center
            //   verts[1 .. segments]           = ring at y=heights[i]
            //   verts[segments+1 .. 2*segments] = duplicate ring at y=0 (for soft fade)
            var verts = new Vector3[1 + segments * 2];
            var uvs = new Vector2[verts.Length];
            var colors = new Color[verts.Length];

            // Hot center — bright HDR yellow.
            verts[0] = new Vector3(0f, domeHeight, 0f);
            uvs[0] = new Vector2(0.5f, 0.5f);
            colors[0] = new Color(1f, 1f, 1f, 1f);

            for (var i = 0; i < segments; i++)
            {
                var a = i / (float)segments * Mathf.PI * 2f;
                var c = Mathf.Cos(a);
                var s = Mathf.Sin(a);
                var r = radius * radii[i];

                // Inner ring vertex (slightly raised — molten crust)
                var inner = 1 + i;
                verts[inner] = new Vector3(c * r * 0.75f, heights[i] * 0.6f, s * r * 0.75f);
                uvs[inner] = new Vector2(0.5f + c * 0.3f, 0.5f + s * 0.3f);
                colors[inner] = new Color(1f, 1f, 1f, 0.85f);

                // Outer ring vertex (at floor level, alpha=0 → fades into ground)
                var outer = 1 + segments + i;
                verts[outer] = new Vector3(c * r, 0f, s * r);
                uvs[outer] = new Vector2(0.5f + c * 0.5f, 0.5f + s * 0.5f);
                colors[outer] = new Color(1f, 1f, 1f, 0f);
            }

            // Triangles: triangle fan from center to inner ring, then strip from
            // inner ring outward to the outer ring (creates the soft falloff edge).
            var tris = new int[segments * 9];
            var ti = 0;
            for (var i = 0; i < segments; i++)
            {
                var iNext = (i + 1) % segments;
                var inner0 = 1 + i;
                var inner1 = 1 + iNext;
                var outer0 = 1 + segments + i;
                var outer1 = 1 + segments + iNext;

                // Center → inner1 → inner0
                tris[ti++] = 0;
                tris[ti++] = inner1;
                tris[ti++] = inner0;

                // Inner ring → outer ring (two triangles per quad).
                tris[ti++] = inner0;
                tris[ti++] = inner1;
                tris[ti++] = outer0;

                tris[ti++] = inner1;
                tris[ti++] = outer1;
                tris[ti++] = outer0;
            }

            var mesh = new Mesh { name = "TheFloorIsLava_Patch" };
            mesh.vertices = verts;
            mesh.uv = uvs;
            mesh.colors = colors;
            mesh.triangles = tris;
            mesh.RecalculateNormals();
            mesh.RecalculateBounds();
            mesh.RecalculateTangents();
            return mesh;
        }

        /// <summary>Quad-strip drip ribbon that hangs under thin floors. Tapers
        /// to a point at the bottom and fades alpha as it descends.</summary>
        public static Mesh BuildDrip(int seed, float radius, float length)
        {
            var rng = new System.Random(seed);
            const int rungs = 6;
            var verts = new Vector3[rungs * 2];
            var uvs = new Vector2[verts.Length];
            var colors = new Color[verts.Length];
            var tris = new int[(rungs - 1) * 6];

            for (var i = 0; i < rungs; i++)
            {
                var t = i / (float)(rungs - 1);
                var y = -length * t;
                var taper = Mathf.Lerp(1f, 0.15f, t);
                var sway = (float)(rng.NextDouble() - 0.5) * radius * 0.25f * t;
                var width = radius * taper;

                verts[i * 2 + 0] = new Vector3(-width + sway, y, 0f);
                verts[i * 2 + 1] = new Vector3(width + sway, y, 0f);
                uvs[i * 2 + 0] = new Vector2(0f, t);
                uvs[i * 2 + 1] = new Vector2(1f, t);
                var alpha = Mathf.Lerp(0.95f, 0f, t * t);
                colors[i * 2 + 0] = new Color(1f, 1f, 1f, alpha);
                colors[i * 2 + 1] = new Color(1f, 1f, 1f, alpha);
            }

            var k = 0;
            for (var i = 0; i < rungs - 1; i++)
            {
                var a = i * 2;
                var b = a + 1;
                var c = a + 2;
                var d = a + 3;
                tris[k++] = a; tris[k++] = c; tris[k++] = b;
                tris[k++] = b; tris[k++] = c; tris[k++] = d;
            }

            var mesh = new Mesh { name = "TheFloorIsLava_Drip" };
            mesh.vertices = verts;
            mesh.uv = uvs;
            mesh.colors = colors;
            mesh.triangles = tris;
            mesh.RecalculateNormals();
            mesh.RecalculateBounds();
            return mesh;
        }
    }

    /// <summary>Procedural "dirty industrial lava" textures: radial heat gradient
    /// for puddles + a vertical heat strip for drips. Both are baked at startup
    /// and shared across every lava patch in the run.</summary>
    private static class LavaTexture
    {
        private static Texture2D? _patch;
        private static Texture2D? _drip;

        public static Texture2D GradientPatch()
        {
            if (_patch != null) return _patch;
            const int size = 128;
            var tex = new Texture2D(size, size, TextureFormat.RGBA32, mipChain: false)
            {
                name = "TheFloorIsLava_GradientPatch",
                wrapMode = TextureWrapMode.Clamp,
                filterMode = FilterMode.Bilinear,
            };
            var center = (size - 1) * 0.5f;
            var maxDist = center;

            for (var y = 0; y < size; y++)
            {
                for (var x = 0; x < size; x++)
                {
                    var dx = x - center;
                    var dy = y - center;
                    var dist = Mathf.Sqrt(dx * dx + dy * dy) / maxDist;
                    var t = Mathf.Clamp01(dist);

                    // Heat ramp: white-hot core → yellow → orange → red → black crust.
                    Color heat = SampleHeatRamp(t);

                    // Outward flow streaks: angular noise modulates brightness in
                    // radial bands so each patch looks like it's flowing out.
                    var angle = Mathf.Atan2(dy, dx);
                    var streak = Mathf.PerlinNoise(angle * 1.6f + 5.4f, dist * 4.5f);
                    var flow = Mathf.Lerp(0.7f, 1.15f, streak);

                    // Dirty industrial mottle: low-freq Perlin scratches.
                    var dirt = Mathf.PerlinNoise(x * 0.06f + 3.1f, y * 0.06f) * 0.35f
                             + Mathf.PerlinNoise(x * 0.22f + 11.0f, y * 0.22f) * 0.15f;
                    var dim = Mathf.Clamp01(1f - dirt * (1f - t));

                    heat.r = Mathf.Clamp01(heat.r * flow * dim);
                    heat.g = Mathf.Clamp01(heat.g * flow * dim * 0.95f);
                    heat.b = Mathf.Clamp01(heat.b * flow * dim * 0.8f);

                    // Soft edge fade for additive blending; mid-patch stays opaque.
                    var alpha = Mathf.SmoothStep(1f, 0f, Mathf.Clamp01((t - 0.55f) / 0.45f));
                    heat.a = alpha;

                    tex.SetPixel(x, y, heat);
                }
            }
            tex.Apply(updateMipmaps: false, makeNoLongerReadable: true);
            _patch = tex;
            return tex;
        }

        public static Texture2D DripStrip()
        {
            if (_drip != null) return _drip;
            const int w = 32, h = 64;
            var tex = new Texture2D(w, h, TextureFormat.RGBA32, mipChain: false)
            {
                name = "TheFloorIsLava_DripStrip",
                wrapMode = TextureWrapMode.Clamp,
                filterMode = FilterMode.Bilinear,
            };
            for (var y = 0; y < h; y++)
            {
                var t = y / (float)(h - 1);
                var heat = SampleHeatRamp(t * 0.7f + 0.15f);
                for (var x = 0; x < w; x++)
                {
                    var u = x / (float)(w - 1);
                    var edge = 1f - Mathf.Abs(u - 0.5f) * 2f;
                    edge = Mathf.SmoothStep(0f, 1f, edge);
                    var mottle = Mathf.PerlinNoise(x * 0.3f, y * 0.18f) * 0.25f;
                    var c = new Color(
                        Mathf.Clamp01(heat.r - mottle),
                        Mathf.Clamp01(heat.g - mottle * 1.1f),
                        Mathf.Clamp01(heat.b - mottle * 0.9f),
                        edge * Mathf.Lerp(0.95f, 0f, t)
                    );
                    tex.SetPixel(x, y, c);
                }
            }
            tex.Apply(updateMipmaps: false, makeNoLongerReadable: true);
            _drip = tex;
            return tex;
        }

        private static Color SampleHeatRamp(float t)
        {
            // Five anchor stops walking from molten white through to black crust.
            if (t < 0.18f)
                return Color.Lerp(new Color(1.00f, 0.97f, 0.78f), new Color(1.00f, 0.85f, 0.20f), t / 0.18f);
            if (t < 0.45f)
                return Color.Lerp(new Color(1.00f, 0.85f, 0.20f), new Color(1.00f, 0.45f, 0.05f), (t - 0.18f) / 0.27f);
            if (t < 0.75f)
                return Color.Lerp(new Color(1.00f, 0.45f, 0.05f), new Color(0.70f, 0.13f, 0.03f), (t - 0.45f) / 0.30f);
            return Color.Lerp(new Color(0.70f, 0.13f, 0.03f), new Color(0.18f, 0.04f, 0.02f), (t - 0.75f) / 0.25f);
        }
    }
}

