    // Transparent + additive so neighboring patches add up brightness when they
    // overlap — that's what makes adjacent puddles look merged and flowing.
    if (mat.HasProperty("_Surface")) mat.SetFloat("_Surface", 1f);
    if (mat.HasProperty("_Blend")) mat.SetFloat("_Blend", 1f); // Premultiply-ish
    if (mat.HasProperty("_SrcBlend")) mat.SetFloat("_SrcBlend", (float)UnityEngine.Rendering.BlendMode.SrcAlpha);
