/// <summary>Builds the irregular puddle mesh and the optional drip ribbon.
/// Each mesh is unique per seed so neighbours don't look identical, and the
/// outline is biased outward in a wobbly noise pattern so adjacent patches
/// visually overlap and "flow" into one another.</summary>
private static class LavaPatchMesh
{
    public static Mesh Build(int seed, float radius, float domeHeight, float shapeJitter)
    {
        const int segments = 18;
        var rng = new System.Random(seed);

        // Two control values per segment used to wobble the outline outward.
        // We pre-sample them so the silhouette stays correlated and looks like
        // a smooth amoeba instead of a noisy zig-zag.
        var radii = new float[segments];
        var heights = new float[segments];
        for (var i = 0; i < segments; i++)
        {
            var u = i / (float)segments;
            var nLow = Mathf.PerlinNoise(seed * 0.001f + u * 2.4f, 1.7f);
            var nHigh = Mathf.PerlinNoise(seed * 0.001f + u * 6.1f, 4.3f) * 0.4f;
            var wobble = (nLow + nHigh - 0.7f) * shapeJitter;
            radii[i] = Mathf.Clamp(1f + wobble, 0.5f, 1.7f);
            heights[i] = (float)rng.NextDouble() * domeHeight * 0.25f;
        }

        // Layout:
        //   verts[0]                       = raised center
        //   verts[1 .. segments]           = ring at y=heights[i]
        //   verts[segments+1 .. 2*segments] = duplicate ring at y=0 (for soft fade)
        var verts = new Vector3[1 + segments * 2];
        var uvs = new Vector2[verts.Length];
        var colors = new Color[verts.Length];

        // Hot center — bright HDR yellow.
        verts[0] = new Vector3(0f, domeHeight, 0f);
        uvs[0] = new Vector2(0.5f, 0.5f);
        colors[0] = new Color(1f, 1f, 1f, 1f);

        for (var i = 0; i < segments; i++)
        {
            var a = i / (float)segments * Mathf.PI * 2f;
            var c = Mathf.Cos(a);
            var s = Mathf.Sin(a);
            var r = radius * radii[i];

            // Inner ring vertex (slightly raised — molten crust)
            var inner = 1 + i;
            verts[inner] = new Vector3(c * r * 0.75f, heights[i] * 0.6f, s * r * 0.75f);
            uvs[inner] = new Vector2(0.5f + c * 0.3f, 0.5f + s * 0.3f);
            colors[inner] = new Color(1f, 1f, 1f, 0.85f);

            // Outer ring vertex (at floor level, alpha=0 → fades into ground)
            var outer = 1 + segments + i;
            verts[outer] = new Vector3(c * r, 0f, s * r);
            uvs[outer] = new Vector2(0.5f + c * 0.5f, 0.5f + s * 0.5f);
            colors[outer] = new Color(1f, 1f, 1f, 0f);
        }

        // Triangles: triangle fan from center to inner ring, then strip from
        // inner ring outward to the outer ring (creates the soft falloff edge).
        var tris = new int[segments * 9];
        var ti = 0;
        for (var i = 0; i < segments; i++)
        {
            var iNext = (i + 1) % segments;
            var inner0 = 1 + i;
            var inner1 = 1 + iNext;
            var outer0 = 1 + segments + i;
            var outer1 = 1 + segments + iNext;

            // Center → inner1 → inner0
            tris[ti++] = 0;
            tris[ti++] = inner1;
            tris[ti++] = inner0;

            // Inner ring → outer ring (two triangles per quad).
            tris[ti++] = inner0;
            tris[ti++] = inner1;
            tris[ti++] = outer0;

            tris[ti++] = inner1;
            tris[ti++] = outer1;
            tris[ti++] = outer0;
        }

        var mesh = new Mesh { name = "TheFloorIsLava_Patch" };
        mesh.vertices = verts;
        mesh.uv = uvs;
        mesh.colors = colors;
        mesh.triangles = tris;
        mesh.RecalculateNormals();
        mesh.RecalculateBounds();
        mesh.RecalculateTangents();
        return mesh;
    }

