/// <summary>Hardened-lava patch mesh: a slightly domed wobbly disc that stays
/// fully opaque (no soft alpha fade ring — the texture handles the edge look).
/// Outline wobble is inward-only so patches always stay within the requested
/// radius and never overhang a ledge.</summary>
private static class LavaPatchMesh
{
    public static Mesh Build(int seed, float radius, float domeHeight, float shapeJitter)
    {
        const int segments = 14;
        var rng = new System.Random(seed);

        var radii = new float[segments];
        var heights = new float[segments];
        for (var i = 0; i < segments; i++)
        {
            var u = i / (float)segments;
            var nLow = Mathf.PerlinNoise(seed * 0.001f + u * 3.4f, 1.7f);
            var nHigh = Mathf.PerlinNoise(seed * 0.001f + u * 7.3f, 4.3f) * 0.35f;
            // Inward-only wobble: (n - 1) is always <= 0, scaled by jitter.
            var wobble = ((nLow + nHigh) - 1.35f) * shapeJitter;
            radii[i] = Mathf.Clamp(1f + wobble, 0.5f, 1f);
            heights[i] = (float)rng.NextDouble() * domeHeight * 0.4f;
        }

        // Simple triangle fan: center + single ring. The texture provides the
        // crust/crack visual; the mesh just gives a solid wobbly silhouette.
        var verts = new Vector3[1 + segments];
        var uvs = new Vector2[verts.Length];
        var colors = new Color[verts.Length];

        verts[0] = new Vector3(0f, domeHeight, 0f);
        uvs[0] = new Vector2(0.5f, 0.5f);
        colors[0] = new Color(1f, 1f, 1f, 1f);

        for (var i = 0; i < segments; i++)
        {
            var a = i / (float)segments * Mathf.PI * 2f;
            var c = Mathf.Cos(a);
            var s = Mathf.Sin(a);
            var r = radius * radii[i];

            var idx = 1 + i;
            verts[idx] = new Vector3(c * r, heights[i] * 0.5f, s * r);
            uvs[idx] = new Vector2(0.5f + c * 0.5f, 0.5f + s * 0.5f);
            colors[idx] = new Color(1f, 1f, 1f, 1f);
        }

        var tris = new int[segments * 3];
        var ti = 0;
        for (var i = 0; i < segments; i++)
        {
            var iNext = (i + 1) % segments;
            tris[ti++] = 0;
            tris[ti++] = 1 + iNext;
            tris[ti++] = 1 + i;
        }

        var mesh = new Mesh { name = "TheFloorIsLava_Patch" };
        mesh.vertices = verts;
        mesh.uv = uvs;
        mesh.colors = colors;
        mesh.triangles = tris;
        mesh.RecalculateNormals();
        mesh.RecalculateBounds();
        mesh.RecalculateTangents();
        return mesh;
    }

