    /// <summary>Procedural cracked-basalt lava textures: dark crusty surface with
    /// glowing cracks breaking through, plus subtle horizontal layer banding.
    /// Baked once at startup and shared across every patch in the run.</summary>
    private static class LavaTexture
    {
        private static Texture2D? _patch;
        private static Texture2D? _drip;

        // Colour stops used both for the heat through the cracks and inside the
        // drips. Tuned to match cooled-lava reference photography.
        private static readonly Color CrustDark = new Color(0.05f, 0.04f, 0.035f, 1f);
        private static readonly Color CrustMid = new Color(0.10f, 0.08f, 0.07f, 1f);
        private static readonly Color GlowHot = new Color(1.00f, 0.55f, 0.10f, 1f);
        private static readonly Color GlowCore = new Color(1.00f, 0.85f, 0.30f, 1f);
        private static readonly Color GlowFaint = new Color(0.55f, 0.12f, 0.03f, 1f);

        public static Texture2D GradientPatch()
        {
            if (_patch != null) return _patch;
            const int size = 256;
            var tex = new Texture2D(size, size, TextureFormat.RGBA32, mipChain: false)
            {
                name = "TheFloorIsLava_GradientPatch",
                wrapMode = TextureWrapMode.Clamp,
                filterMode = FilterMode.Bilinear,
            };
            var center = (size - 1) * 0.5f;
            var maxDist = center;

            for (var y = 0; y < size; y++)
            {
                for (var x = 0; x < size; x++)
                {
                    var dx = x - center;
                    var dy = y - center;
                    var dist = Mathf.Sqrt(dx * dx + dy * dy) / maxDist;
                    var t = Mathf.Clamp01(dist);

                    // Crack mask: 3 octaves of Perlin combined into a ridged pattern.
                    // SmoothStep keeps the boundary between crust and glow sharp.
                    var n1 = Mathf.PerlinNoise(x * 0.020f + 3.1f, y * 0.020f + 11.0f);
                    var n2 = Mathf.PerlinNoise(x * 0.060f + 17.3f, y * 0.060f + 5.1f);
                    var n3 = Mathf.PerlinNoise(x * 0.180f + 31.5f, y * 0.180f + 71.2f);
                    var combined = n1 * 0.55f + n2 * 0.30f + n3 * 0.15f;

                    // Bias: centre slightly hotter (more cracks visible), edges
                    // are cooler / mostly crust — matches real lava that has cooled
                    // around the outside.
                    combined += Mathf.Lerp(0.08f, -0.12f, t);

                    // 1 = crust, 0 = glow. Sharp threshold = hard-looking surface.
                    var crustMask = Mathf.SmoothStep(0.46f, 0.54f, combined);

                    // Horizontal layer banding — faint stratification you can read
                    // on the dark crust pieces.
                    var bandPhase = y * 0.16f + Mathf.Sin(x * 0.04f + 1.7f) * 1.3f;
                    var band = (Mathf.Sin(bandPhase) * 0.5f + 0.5f) * 0.5f + 0.5f;

                    // Crust colour: very dark with subtle warm tint, modulated by
                    // banding so it doesn't look like a flat fill.
                    var crustTone = Color.Lerp(CrustDark, CrustMid, band);
                    // Tiny ember speckle on the crust so it isn't pure black.
                    var speckle = Mathf.PerlinNoise(x * 0.45f, y * 0.45f);
                    if (speckle > 0.78f)
                    {
                        crustTone.r += (speckle - 0.78f) * 0.6f;
                        crustTone.g += (speckle - 0.78f) * 0.25f;
                    }

                    // Glow colour through cracks: hot at the centre of the patch,
                    // cooler at the edges. Adds inner-glow vibe per pixel.
                    var glow = Color.Lerp(GlowCore, GlowHot, t * 0.7f);
                    glow = Color.Lerp(glow, GlowFaint, Mathf.Clamp01((t - 0.4f) / 0.6f));
                    // Slight depth into the crack — pixels close to the crust edge
                    // are dimmer than the crack centre.
                    var crackDepth = Mathf.SmoothStep(0.34f, 0.46f, combined); // 0 at crack centre
                    glow = Color.Lerp(glow, CrustDark, crackDepth * 0.55f);

                    var color = Color.Lerp(glow, crustTone, crustMask);

                    // Hard alpha across most of the patch. The very outer 8% fades
                    // softly so the wobbly mesh edge anti-aliases against the floor.
                    var alpha = t < 0.92f ? 1f : Mathf.SmoothStep(1f, 0f, (t - 0.92f) / 0.08f);
                    // Outermost crust ring slightly darker on top, matching photo.
                    if (t > 0.82f)
                    {
                        var darken = Mathf.SmoothStep(0f, 1f, (t - 0.82f) / 0.18f) * 0.35f;
                        color.r *= 1f - darken;
                        color.g *= 1f - darken;
                        color.b *= 1f - darken;
                    }
                    color.a = alpha;

                    tex.SetPixel(x, y, color);
                }
            }
            tex.Apply(updateMipmaps: false, makeNoLongerReadable: true);
            _patch = tex;
            return tex;
        }

        public static Texture2D DripStrip()
        {
            if (_drip != null) return _drip;
            const int w = 32, h = 64;
            var tex = new Texture2D(w, h, TextureFormat.RGBA32, mipChain: false)
            {
                name = "TheFloorIsLava_DripStrip",
                wrapMode = TextureWrapMode.Clamp,
                filterMode = FilterMode.Bilinear,
            };
            for (var y = 0; y < h; y++)
            {
                var t = y / (float)(h - 1);
                // Drip is mostly bright at the top (still molten from the patch)
                // cooling as it goes down — opposite of the patch surface.
                var heat = Color.Lerp(GlowCore, GlowFaint, t);
                for (var x = 0; x < w; x++)
                {
                    var u = x / (float)(w - 1);
                    var edge = 1f - Mathf.Abs(u - 0.5f) * 2f;
                    edge = Mathf.SmoothStep(0f, 1f, edge);
                    var mottle = Mathf.PerlinNoise(x * 0.3f, y * 0.18f) * 0.25f;
                    var c = new Color(
                        Mathf.Clamp01(heat.r - mottle),
                        Mathf.Clamp01(heat.g - mottle * 1.1f),
                        Mathf.Clamp01(heat.b - mottle * 0.9f),
                        edge * Mathf.Lerp(0.95f, 0f, t)
                    );
                    tex.SetPixel(x, y, c);
                }
            }
            tex.Apply(updateMipmaps: false, makeNoLongerReadable: true);
            _drip = tex;
            return tex;
        }
    }
}

