    _lavaMaterial = BuildSurfaceMaterial(shader, surfaceTex, "TheFloorIsLava_Surface");
    _lavaDripMaterial = BuildSurfaceMaterial(shader, dripTex, "TheFloorIsLava_Drip");

    Plugin.LogInfo(
