public void Rebuild(Material? mat, Material? dripMat, float gridStep, float influence,
    float texScale, bool enableDrips, float thinThreshold)
{
    if (Collider == null || Root == null || mat == null) return;
    if (ZonePositions.Count == 0) return;

    var b = Collider.bounds;
    IsThinFloor = b.size.y < thinThreshold;
    Center = b.center;
    Root.transform.position = Center;

    // Build the merged mesh.
    var newMesh = LavaSurfaceMesh.Build(b, ZonePositions, gridStep, influence,
        texScale, Center);
    if (newMesh == null) return;

    if (Mesh != null) Object.Destroy(Mesh);
    Mesh = newMesh;

    var mf = Root.GetComponent<MeshFilter>();
    if (mf == null) mf = Root.AddComponent<MeshFilter>();
    mf.sharedMesh = Mesh;

    Renderer = Root.GetComponent<MeshRenderer>();
    if (Renderer == null) Renderer = Root.AddComponent<MeshRenderer>();
    Renderer.sharedMaterial = mat;
    Renderer.shadowCastingMode = UnityEngine.Rendering.ShadowCastingMode.Off;
    Renderer.receiveShadows = false;
    Renderer.lightProbeUsage = UnityEngine.Rendering.LightProbeUsage.Off;
    Renderer.reflectionProbeUsage = UnityEngine.Rendering.ReflectionProbeUsage.Off;

    // Optional drip ribbons under the thinnest floors. One drip per zone is
    // overkill — pick a sparse subset (every 3rd) so it reads as occasional.
    if (enableDrips && IsThinFloor && dripMat != null)
    {
        EnsureDrips(dripMat);
    }
    else
    {
        ClearDrips();
    }
}

