    private static Texture2D? _surface;
    private static Texture2D? _drip;

    public static Texture2D Surface()
    {
        if (_surface != null) return _surface;
        const int size = 512;
        var tex = new Texture2D(size, size, TextureFormat.RGBA32, mipChain: true)
        {
            name = "TheFloorIsLava_SurfaceTex",
            wrapMode = TextureWrapMode.Repeat,
            filterMode = FilterMode.Trilinear,
            anisoLevel = 4,
        };

        // Colour palette. CrustDark/Mid build the cooled basalt; the glow ramp
        // is for the molten material visible through cracks.
        var crustDark = new Color(0.045f, 0.040f, 0.035f);
        var crustMid = new Color(0.135f, 0.105f, 0.085f);
        var crustHi = new Color(0.22f, 0.18f, 0.15f);
        var glowDeep = new Color(0.75f, 0.20f, 0.04f);
        var glowMid = new Color(1.00f, 0.55f, 0.10f);
        var glowHot = new Color(1.00f, 0.85f, 0.30f);

        for (var y = 0; y < size; y++)
        {
            for (var x = 0; x < size; x++)
            {
                // Ridged noise creates vein-like cracks (high where Perlin ~0.5).
                var p1 = Mathf.PerlinNoise(x * 0.010f, y * 0.010f);
                var ridge1 = 1f - Mathf.Abs(p1 * 2f - 1f);
                ridge1 = Mathf.Pow(ridge1, 5f);

                var p2 = Mathf.PerlinNoise(x * 0.024f + 137f, y * 0.024f + 51f);
                var ridge2 = 1f - Mathf.Abs(p2 * 2f - 1f);
                ridge2 = Mathf.Pow(ridge2, 7f) * 0.65f;

                var p3 = Mathf.PerlinNoise(x * 0.055f + 311f, y * 0.055f + 213f);
                var ridge3 = 1f - Mathf.Abs(p3 * 2f - 1f);
                ridge3 = Mathf.Pow(ridge3, 9f) * 0.35f;

                var crack = Mathf.Max(ridge1, Mathf.Max(ridge2, ridge3));

                // Crust surface detail: combine fractal noise + horizontal banding
                // so the dark plates show the layered cooled-lava texture.
                var detailA = Mathf.PerlinNoise(x * 0.05f + 300f, y * 0.05f + 150f);
                var detailB = Mathf.PerlinNoise(x * 0.15f + 500f, y * 0.15f + 700f);
                var detailC = Mathf.PerlinNoise(x * 0.40f + 870f, y * 0.40f + 230f);
                var crustDetail = detailA * 0.55f + detailB * 0.30f + detailC * 0.15f;

                // Subtle stratification with a wavy phase so it doesn't read as
                // a flat ruled pattern.
                var bandPhase = y * 0.045f + Mathf.Sin(x * 0.015f + 1.3f) * 2.6f;
                var band = Mathf.Sin(bandPhase) * 0.5f + 0.5f;
                var bandShade = band * 0.4f + 0.6f;

                var crustTone = Color.Lerp(crustDark, crustMid, crustDetail);
                crustTone = Color.Lerp(crustTone, crustHi, detailB * 0.4f);
                crustTone.r *= bandShade;
                crustTone.g *= bandShade;
                crustTone.b *= bandShade;

                // Sparse warm embers visible on the cooler crust.
                var ember = Mathf.PerlinNoise(x * 0.09f + 800f, y * 0.09f + 900f);
                if (ember > 0.74f && crack < 0.25f)
                {
                    var hot = (ember - 0.74f) / 0.26f;
                    crustTone.r += hot * 0.28f;
                    crustTone.g += hot * 0.08f;
                }

                // Glow colour varies along the cracks.
                var glowVar = Mathf.PerlinNoise(x * 0.03f + 1100f, y * 0.03f + 1300f);
                Color glow;
                if (glowVar < 0.4f)
                    glow = Color.Lerp(glowDeep, glowMid, glowVar / 0.4f);
                else
                    glow = Color.Lerp(glowMid, glowHot, (glowVar - 0.4f) / 0.6f);

                // Sharpen the crack-vs-crust boundary so the surface looks hard
                // (definite plates) rather than a soft glowing cloud.
                var crustMask = 1f - Mathf.SmoothStep(0.25f, 0.55f, crack);

                // Slight darken at very top of bands to emulate the "darker on
                // top of crust" look from the reference photo.
                if (band > 0.75f && crustMask > 0.6f)
                {
                    var topShade = (band - 0.75f) / 0.25f * 0.3f;
                    crustTone.r *= 1f - topShade;
                    crustTone.g *= 1f - topShade;
                    crustTone.b *= 1f - topShade;
                }

                var color = Color.Lerp(glow, crustTone, crustMask);
                color.a = 1f;
                tex.SetPixel(x, y, color);
            }
        }
        tex.Apply(updateMipmaps: true, makeNoLongerReadable: true);
        _surface = tex;
        return tex;
    }

