using UnityEngine;

namespace SpikeBalanceMod;

/// <summary>
/// Hidden "throw the HP bar away" easter egg.
///
/// Trigger: while in a run, look almost straight down, crouch, and grip a
/// handhold with BOTH hands at the same time for ~1 second. The HP bar UI
/// detaches from the screen, spawns as a small red-and-white physical tablet
/// at the player's feet, and lava damage is permanently disabled for the rest
/// of the run. The prop has a Rigidbody + collider so the player can kick it
/// around the level.
/// </summary>
internal sealed class EasterEgg
{
    private const float HoldDuration = 1.0f;
    private const float LookDownThreshold = -0.85f; // forward.y < this == looking nearly straight down

    private float _conditionTime;
    private bool _triggered;
    private GameObject? _droppedProp;

    public bool Triggered => _triggered;

    public void Reset()
    {
        _conditionTime = 0f;
        _triggered = false;
        if (_droppedProp != null)
        {
            Object.Destroy(_droppedProp);
            _droppedProp = null;
        }
    }

    public void Tick(ENT_Player player, float dt, HealthBar ui)
    {
        if (_triggered) return;
        if (player == null) { _conditionTime = 0f; return; }

        if (ConditionsMet(player))
        {
            _conditionTime += dt;
            if (_conditionTime >= HoldDuration)
                Trigger(player, ui);
        }
        else
        {
            _conditionTime = 0f;
        }
    }

    private static bool ConditionsMet(ENT_Player player)
    {
        var look = GameRefs.LookForward(player);
        if (look.y > LookDownThreshold) return false;
        if (!GameRefs.IsCrouching(player)) return false;
        if (!GameRefs.BothHandsHolding(player)) return false;
        return true;
    }

    private void Trigger(ENT_Player player, HealthBar ui)
    {
        _triggered = true;
        Plugin.LogInfo("EASTER EGG: HP bar detached and thrown into the level — lava is now harmless.");
        ui.Hide();
        _droppedProp = SpawnDroppedHpBar(player);
    }

    /// <summary>Builds a small red-and-white "HP-bar tablet" GameObject with
    /// physics so the player can knock it around. It's just visual flair —
    /// no game-mechanic effect beyond the easter-egg state.</summary>
    private static GameObject? SpawnDroppedHpBar(ENT_Player player)
    {
        var pos = player.transform.position + Vector3.up * 0.4f + player.transform.forward * 0.45f;
        var root = new GameObject("TheFloorIsLava_ThrownHpBar");
        root.transform.position = pos;
        root.transform.rotation = Quaternion.LookRotation(player.transform.forward, Vector3.up);

        // Outer white "frame" cube.
        var frame = GameObject.CreatePrimitive(PrimitiveType.Cube);
        Object.Destroy(frame.GetComponent<Collider>());
        frame.transform.SetParent(root.transform, false);
        frame.transform.localScale = new Vector3(0.40f, 0.07f, 0.18f);
        frame.transform.localPosition = Vector3.zero;
        var frameMat = MakeUnlit(Color.white);
        frame.GetComponent<MeshRenderer>().sharedMaterial = frameMat;

        // Inner red "fill" cube, slightly inset on every face so the white shows
        // around it like the on-screen UI bar.
        var fill = GameObject.CreatePrimitive(PrimitiveType.Cube);
        Object.Destroy(fill.GetComponent<Collider>());
        fill.transform.SetParent(root.transform, false);
        fill.transform.localScale = new Vector3(0.36f, 0.078f, 0.14f);
        fill.transform.localPosition = Vector3.zero;
        var fillMat = MakeUnlit(new Color(0.92f, 0.13f, 0.10f));
        fill.GetComponent<MeshRenderer>().sharedMaterial = fillMat;

        // Single collider on the root and a rigidbody so it tumbles freely.
        var col = root.AddComponent<BoxCollider>();
        col.size = new Vector3(0.40f, 0.07f, 0.18f);
        var rb = root.AddComponent<Rigidbody>();
        rb.mass = 0.35f;
        rb.linearDamping = 0.3f;
        rb.angularDamping = 0.5f;

        // Give it a little forward + downward push so it visibly drops away.
        var fwd = player.transform.forward;
        fwd.y = 0f;
        if (fwd.sqrMagnitude < 0.01f) fwd = Vector3.forward;
        fwd.Normalize();
        rb.AddForce(fwd * 1.8f + Vector3.up * 0.3f, ForceMode.Impulse);
        rb.AddTorque(new Vector3(Random.Range(-1f, 1f), Random.Range(-1f, 1f), Random.Range(-1f, 1f)) * 0.4f,
            ForceMode.Impulse);

        return root;
    }

    private static Material MakeUnlit(Color c)
    {
        Shader? s = null;
        foreach (var n in new[] { "Universal Render Pipeline/Unlit", "Unlit/Color", "Standard" })
        {
            s = Shader.Find(n);
            if (s != null) break;
        }
        if (s == null) s = Shader.Find("Hidden/InternalErrorShader");
        var m = new Material(s!) { name = "TheFloorIsLava_HpBarChunk" };
        if (m.HasProperty("_BaseColor")) m.SetColor("_BaseColor", c);
        if (m.HasProperty("_Color")) m.SetColor("_Color", c);
        m.color = c;
        return m;
    }
}

