/// <summary>True when both grab BUTTONS are pressed (regardless of whether
/// the hand actually catches a handhold). Reads each Hand's configured
/// fireButton via Unity Input; falls back to mouse buttons if the input
/// axis isn't registered.</summary>
public static bool BothHandsGrabbing(ENT_Player player)
{
    if (Hands.GetValue(player) is not Array arr || arr.Length < 2) return false;
    var h0 = arr.GetValue(0);
    var h1 = arr.GetValue(1);
    if (h0 == null || h1 == null) return false;
    return IsHandGrabPressed(h0, 0) && IsHandGrabPressed(h1, 1);
}

private static bool IsHandGrabPressed(object hand, int fallbackMouseButton)
{
    if (FireButtonF != null)
    {
        try
        {
            if (FireButtonF.GetValue(hand) is string btn && !string.IsNullOrEmpty(btn))
            {
                try { return Input.GetButton(btn); }
                catch { /* unregistered axis — fall through to mouse */ }
            }
        }
        catch { /* fall through */ }
    }
    try { return Input.GetMouseButton(fallbackMouseButton); }
    catch { return false; }
}

