using UnityEngine;

namespace SpikeBalanceMod;

/// <summary>
/// "Rip the HP bar out of the screen" easter egg.
///
/// Gesture: look straight down + crouch + press both grab buttons. Holding the
/// gesture for 1 second triggers a short "rip" animation on the UI bar (shake
/// → stretch + pull → fade), after which the bar becomes a slim, translucent
/// 3D tablet spawned at the player's feet. The tablet is built on top of an
/// existing CL_Prop clone so the game's hand-interaction system can pick it
/// up and throw it like any other in-world prop. Lava damage is disabled for
/// the rest of the run.
/// </summary>
internal sealed class EasterEgg
{
    private const float HoldDuration = 1.0f;
    private const float LookDownThreshold = -0.90f;
    private const float AnimDuration = 1.0f;

    private float _conditionTime;
    private bool _triggered;
    private float _animTime;
    private bool _propSpawned;
    private GameObject? _droppedProp;

    private bool _prevLookDown;
    private bool _prevCrouch;
    private bool _prevGrab;
    private float _progressLogTimer;
    private float _liveLogTimer;
    private bool _diagnosticsLogged;

    /// <summary>True once the gesture has fired (lava damage stops, animation
    /// is running OR finished).</summary>
    public bool Triggered => _triggered;

    /// <summary>True once the animation has fully played out and the 3D prop
    /// has spawned. The UI is already hidden by this point.</summary>
    public bool Done => _propSpawned;

    public void Reset()
    {
        _conditionTime = 0f;
        _triggered = false;
        _animTime = 0f;
        _propSpawned = false;
        _prevLookDown = false;
        _prevCrouch = false;
        _prevGrab = false;
        _progressLogTimer = 0f;
        _liveLogTimer = 0f;
        _diagnosticsLogged = false;
        if (_droppedProp != null)
        {
            Object.Destroy(_droppedProp);
            _droppedProp = null;
        }
    }

    public void Tick(ENT_Player player, float dt, HealthBar ui)
    {
        if (_propSpawned) return;
        if (player == null) { _conditionTime = 0f; return; }

        // Animation phase — runs after the gesture is confirmed.
        if (_triggered)
        {
            _animTime += dt;
            UpdateRipAnimation(_animTime, ui);
            if (_animTime >= AnimDuration)
                SpawnDroppedHpBar(player, ui);
            return;
        }

        // Gesture detection.
        if (!_diagnosticsLogged)
        {
            _diagnosticsLogged = true;
            Plugin.LogInfo("EasterEgg diag: " + GameRefs.DiagnoseEasterEgg(player));
        }

        var look = GameRefs.LookForward(player);
        var lookDown = look.y < LookDownThreshold;
        var crouch = GameRefs.IsCrouching(player);
        var grab = GameRefs.BothHandsGrabbing(player);
        var all = lookDown && crouch && grab;

        if (lookDown != _prevLookDown)
            Plugin.LogInfo($"EasterEgg: lookDown -> {lookDown} (forward.y={look.y:F2}, threshold<{LookDownThreshold:F2})");
        if (crouch != _prevCrouch)
            Plugin.LogInfo($"EasterEgg: crouching -> {crouch}");
        if (grab != _prevGrab)
            Plugin.LogInfo($"EasterEgg: bothHandsGrabbing -> {grab}");
        _prevLookDown = lookDown;
        _prevCrouch = crouch;
        _prevGrab = grab;

        if (crouch)
        {
            _liveLogTimer += dt;
            if (_liveLogTimer >= 1f)
            {
                _liveLogTimer = 0f;
                Plugin.LogInfo($"EasterEgg live: look.y={look.y:F2} crouch={crouch} " +
                               $"mouse0={UnityEngine.Input.GetMouseButton(0)} " +
                               $"mouse1={UnityEngine.Input.GetMouseButton(1)} " +
                               $"grabResult={grab}");
            }
        }
        else _liveLogTimer = 0f;

        if (all)
        {
            _conditionTime += dt;
            _progressLogTimer += dt;
            if (_progressLogTimer >= 0.25f)
            {
                _progressLogTimer = 0f;
                Plugin.LogInfo($"EasterEgg: holding gesture {_conditionTime:F2}/{HoldDuration:F1}s");
            }
            if (_conditionTime >= HoldDuration && !_triggered)
            {
                _triggered = true;
                _animTime = 0f;
                Plugin.LogInfo("EasterEgg: gesture COMPLETE — ripping HP bar out of the UI...");
            }
        }
        else
        {
            if (_conditionTime > 0f)
                Plugin.LogInfo($"EasterEgg: gesture broken (held {_conditionTime:F2}s).");
            _conditionTime = 0f;
            _progressLogTimer = 0f;
        }
    }

    /// <summary>
    /// 1.0-second three-phase rip animation driven from <see cref="HealthBar"/>'s
    /// container RectTransform + CanvasGroup.
    /// </summary>
    private static void UpdateRipAnimation(float t, HealthBar ui)
    {
        var rect = ui.Container;
        var grp = ui.Group;
        if (rect == null || grp == null) return;

        // Phase 1 (0.00 - 0.30s): both "hands grip" — bar shakes in place.
        if (t < 0.30f)
        {
            var shake = Mathf.Sin(t * 70f) * 4f;
            var bob = Mathf.Sin(t * 90f + 1.3f) * 1.6f;
            rect.anchoredPosition = new Vector2(shake, 16f + bob);
            rect.localScale = new Vector3(1f + Mathf.Sin(t * 50f) * 0.04f, 1f + Mathf.Sin(t * 50f + 0.6f) * 0.06f, 1f);
            rect.localRotation = Quaternion.Euler(0f, 0f, Mathf.Sin(t * 55f) * 1.2f);
            grp.alpha = 1f;
            return;
        }

        // Phase 2 (0.30 - 0.75s): the hands pull — bar stretches outward and
        // sags down toward the screen bottom, simulating it being torn loose.
        if (t < 0.75f)
        {
            var p = (t - 0.30f) / 0.45f;
            var eased = Mathf.SmoothStep(0f, 1f, p);
            rect.localScale = new Vector3(1f + eased * 0.55f, 1f + eased * 0.85f, 1f);
            rect.anchoredPosition = new Vector2(0f, 16f - eased * 28f);
            rect.localRotation = Quaternion.Euler(0f, 0f, Mathf.Sin(p * 18f) * 2f);
            grp.alpha = Mathf.Lerp(1f, 0.85f, eased);
            return;
        }

        // Phase 3 (0.75 - 1.00s): rip complete — bar snaps closed and fades.
        {
            var p = (t - 0.75f) / 0.25f;
            var eased = Mathf.SmoothStep(0f, 1f, p);
            rect.localScale = new Vector3(1.55f * (1f - eased), 1.85f * (1f - eased), 1f);
            rect.anchoredPosition = new Vector2(0f, -12f - eased * 40f);
            grp.alpha = Mathf.Lerp(0.85f, 0f, eased);
        }
    }

    private void SpawnDroppedHpBar(ENT_Player player, HealthBar ui)
    {
        _propSpawned = true;
        ui.Hide();
        ui.ResetTransform();

        var pos = player.transform.position + Vector3.up * 0.3f + player.transform.forward * 0.45f;
        var rot = Quaternion.LookRotation(player.transform.forward, Vector3.up);

        _droppedProp = TryCloneCLProp(pos, rot, player) ?? CreateFreeProp(pos, rot, player);
        Plugin.LogInfo($"EasterEgg: HP-bar tablet spawned as '{_droppedProp?.name}'. Lava damage is now disabled.");
    }

    // -------------------------------------------------------------------------

    /// <summary>Try to clone an existing CL_Prop in the scene so the spawned
    /// HP-bar tablet inherits the full hand-grab/throw pipeline (Rigidbody,
    /// Colliders, CL_Prop component, sounds, etc.). Falls back to a plain
    /// physics object if no template prop is found.</summary>
    private static GameObject? TryCloneCLProp(Vector3 pos, Quaternion rot, ENT_Player player)
    {
        CL_Prop? template = null;
        foreach (var p in Object.FindObjectsOfType<CL_Prop>())
        {
            if (p != null && p.gameObject != null && p.gameObject.activeInHierarchy)
            {
                template = p;
                break;
            }
        }
        if (template == null)
        {
            Plugin.LogInfo("EasterEgg: no CL_Prop in scene to clone — using free physics object.");
            return null;
        }

        GameObject clone;
        try { clone = Object.Instantiate(template.gameObject); }
        catch (System.Exception e)
        {
            Plugin.LogInfo($"EasterEgg: failed to clone CL_Prop '{template.name}': {e.Message}");
            return null;
        }

        clone.name = "TheFloorIsLava_HpBarProp";
        clone.transform.position = pos;
        clone.transform.rotation = rot;
        clone.transform.localScale = Vector3.one;

        // Disable cloned visuals.
        foreach (var mr in clone.GetComponentsInChildren<MeshRenderer>(true))
            mr.enabled = false;
        foreach (var sr in clone.GetComponentsInChildren<SkinnedMeshRenderer>(true))
            sr.enabled = false;

        // Resize box colliders to match the HP-bar tablet shape so the grab
        // raycast hits something the right size.
        var halfSize = new Vector3(0.225f, 0.013f, 0.05f);
        foreach (var col in clone.GetComponentsInChildren<Collider>(true))
        {
            if (col is BoxCollider box)
            {
                box.size = halfSize * 2f;
                box.center = Vector3.zero;
                box.enabled = true;
            }
            else if (col is MeshCollider mc)
            {
                mc.enabled = false; // mesh collider would still have the original shape
            }
        }
        if (clone.GetComponent<BoxCollider>() == null && clone.GetComponentInChildren<BoxCollider>() == null)
        {
            var box = clone.AddComponent<BoxCollider>();
            box.size = halfSize * 2f;
        }

        // Build and attach the slim translucent tablet visual.
        var visual = BuildHpBarVisual();
        visual.transform.SetParent(clone.transform, false);
        visual.transform.localPosition = Vector3.zero;
        visual.transform.localRotation = Quaternion.identity;

        // Stop and re-throw the cloned rigidbody.
        var rb = clone.GetComponent<Rigidbody>() ?? clone.GetComponentInChildren<Rigidbody>();
        if (rb != null)
        {
            rb.velocity = Vector3.zero;
            rb.angularVelocity = Vector3.zero;
            rb.useGravity = true;
            rb.isKinematic = false;
            ApplyThrowImpulse(rb, player);
        }

        return clone;
    }

    /// <summary>Fallback: spawn a fresh GameObject with our own Rigidbody +
    /// BoxCollider + visual. Won't integrate with the game's hand pickup, but
    /// at least bounces around the level as a real physics object.</summary>
    private static GameObject CreateFreeProp(Vector3 pos, Quaternion rot, ENT_Player player)
    {
        var go = BuildHpBarVisual();
        go.name = "TheFloorIsLava_HpBarProp_Free";
        go.transform.position = pos;
        go.transform.rotation = rot;
        var col = go.AddComponent<BoxCollider>();
        col.size = new Vector3(0.45f, 0.026f, 0.10f);
        var rb = go.AddComponent<Rigidbody>();
        rb.mass = 0.35f;
        rb.drag = 0.3f;
        rb.angularDrag = 0.5f;
        ApplyThrowImpulse(rb, player);
        return go;
    }

    private static void ApplyThrowImpulse(Rigidbody rb, ENT_Player player)
    {
        var fwd = player.transform.forward;
        fwd.y = 0f;
        if (fwd.sqrMagnitude < 0.01f) fwd = Vector3.forward;
        fwd.Normalize();
        rb.AddForce(fwd * 1.6f + Vector3.up * 0.4f, ForceMode.Impulse);
        rb.AddTorque(new Vector3(Random.Range(-0.4f, 0.4f), Random.Range(-0.4f, 0.4f),
            Random.Range(-0.4f, 0.4f)), ForceMode.Impulse);
    }

    /// <summary>Builds the slim translucent HP-bar tablet — a single thin cube
    /// textured with the same red-fill-on-white-border look as the UI bar.</summary>
    private static GameObject BuildHpBarVisual()
    {
        var root = new GameObject("HpBarTablet");

        var cube = GameObject.CreatePrimitive(PrimitiveType.Cube);
        Object.Destroy(cube.GetComponent<Collider>());
        cube.transform.SetParent(root.transform, false);
        cube.transform.localScale = new Vector3(0.45f, 0.026f, 0.10f);
        cube.transform.localPosition = Vector3.zero;
        var mr = cube.GetComponent<MeshRenderer>();
        mr.shadowCastingMode = UnityEngine.Rendering.ShadowCastingMode.Off;
        mr.receiveShadows = false;
        mr.sharedMaterial = BuildBarMaterial();
        return root;
    }

    /// <summary>Translucent material with the same UI-bar look: a 1px white
    /// border framing a red interior, baked to a 128×32 tileable texture.</summary>
    private static Material? _barMaterial;
    private static Material BuildBarMaterial()
    {
        if (_barMaterial != null) return _barMaterial;

        Shader? shader = null;
        foreach (var n in new[]
                 {
                     "Universal Render Pipeline/Unlit",
                     "Unlit/Transparent",
                     "Legacy Shaders/Particles/Alpha Blended",
                     "Standard",
                 })
        {
            shader = Shader.Find(n);
            if (shader != null) break;
        }
        if (shader == null) shader = Shader.Find("Hidden/InternalErrorShader");

        var mat = new Material(shader!) { name = "TheFloorIsLava_HpBarTablet" };
        mat.mainTexture = BuildBarTexture();
        if (mat.HasProperty("_BaseMap")) mat.SetTexture("_BaseMap", mat.mainTexture);
        if (mat.HasProperty("_MainTex")) mat.SetTexture("_MainTex", mat.mainTexture);

        var tint = new Color(1f, 1f, 1f, 1f);
        mat.color = tint;
        if (mat.HasProperty("_BaseColor")) mat.SetColor("_BaseColor", tint);
        if (mat.HasProperty("_Color")) mat.SetColor("_Color", tint);

        if (mat.HasProperty("_Surface")) mat.SetFloat("_Surface", 1f); // Transparent
        if (mat.HasProperty("_Blend")) mat.SetFloat("_Blend", 0f);
        if (mat.HasProperty("_SrcBlend")) mat.SetFloat("_SrcBlend", (float)UnityEngine.Rendering.BlendMode.SrcAlpha);
        if (mat.HasProperty("_DstBlend")) mat.SetFloat("_DstBlend", (float)UnityEngine.Rendering.BlendMode.OneMinusSrcAlpha);
        if (mat.HasProperty("_ZWrite")) mat.SetFloat("_ZWrite", 0f);
        if (mat.HasProperty("_AlphaClip")) mat.SetFloat("_AlphaClip", 0f);
        mat.EnableKeyword("_SURFACE_TYPE_TRANSPARENT");
        mat.EnableKeyword("_ALPHABLEND_ON");
        mat.DisableKeyword("_ALPHATEST_ON");
        mat.renderQueue = (int)UnityEngine.Rendering.RenderQueue.Transparent;

        _barMaterial = mat;
        return mat;
    }

    private static Texture2D? _barTexture;
    private static Texture2D BuildBarTexture()
    {
        if (_barTexture != null) return _barTexture;
        const int w = 128, h = 32;
        var tex = new Texture2D(w, h, TextureFormat.RGBA32, mipChain: false)
        {
            name = "TheFloorIsLava_HpBarTabletTex",
            wrapMode = TextureWrapMode.Clamp,
            filterMode = FilterMode.Bilinear,
        };
        var border = new Color(1f, 1f, 1f, 0.85f);  // partially translucent white
        var fill = new Color(0.92f, 0.13f, 0.10f, 0.75f); // partially translucent red
        var pixels = new Color[w * h];
        const int borderPx = 2;
        for (var y = 0; y < h; y++)
        {
            for (var x = 0; x < w; x++)
            {
                var isBorder = x < borderPx || x >= w - borderPx || y < borderPx || y >= h - borderPx;
                pixels[y * w + x] = isBorder ? border : fill;
            }
        }
        tex.SetPixels(pixels);
        tex.Apply(updateMipmaps: false, makeNoLongerReadable: true);
        _barTexture = tex;
        return tex;
    }
}

