private void SpawnDroppedHpBar(ENT_Player player, HealthBar ui)
{
    _propSpawned = true;
    ui.Hide();
    ui.ResetTransform();

    // Spawn at the camera's forward vector, NOT at the player root. Player
    // root can be at the feet (so +0.3y is inside the body and the prop
    // spawns inside the player capsule), or it can be at head-height — we
    // don't know. Camera + forward is reliably "where the player is
    // looking" and is guaranteed to be visible.
    var cam = Camera.main;
    Vector3 camPos, camFwd;
    if (cam != null)
    {
        camPos = cam.transform.position;
        camFwd = cam.transform.forward;
    }
    else
    {
        camPos = player.transform.position + Vector3.up * 1.6f;
        camFwd = player.transform.forward;
    }

    // 0.7m in front of the camera, slightly below sight line so the player
    // sees the tablet drop into view (and so it doesn't immediately
    // collide with whatever they were looking at face-on).
    var horiz = camFwd; horiz.y = 0f;
    if (horiz.sqrMagnitude < 0.01f) horiz = Vector3.forward; else horiz.Normalize();
    var pos = camPos + horiz * 0.7f + Vector3.up * -0.15f;
    var rot = Quaternion.LookRotation(horiz, Vector3.up);

    Plugin.LogInfo($"EasterEgg: spawning HP-bar prop. camPos={camPos} camFwd={camFwd} " +
                   $"spawnPos={pos} playerPos={player.transform.position}");

    // Reliable path first: spawn a fresh physics object with our HP-bar
    // visual. This is guaranteed to render and not be killed by any game
    // entity-tracking logic. (We dropped the CL_Prop clone path because it
    // was the prop that disappeared — the cloned entity's Start() seems
    // to immediately deactivate itself in this build.)
    _droppedProp = CreateFreeProp(pos, rot, player);
    if (_droppedProp == null)
    {
        Plugin.LogInfo("EasterEgg: !! prop spawn returned NULL — nothing will be visible !!");
        return;
    }

    var rends = _droppedProp.GetComponentsInChildren<MeshRenderer>(true);
    var firstMr = rends.Length > 0 ? rends[0] : null;
    Plugin.LogInfo(
        $"EasterEgg: HP-bar tablet spawned as '{_droppedProp.name}' " +
        $"pos={_droppedProp.transform.position} active={_droppedProp.activeInHierarchy} " +
        $"renderers={rends.Length} firstMrEnabled={firstMr?.enabled} " +
        $"firstMatShader='{firstMr?.sharedMaterial?.shader?.name}' " +
        $"bounds={firstMr?.bounds.ToString() ?? "n/a"}. Lava damage is now disabled.");
}

