/// <summary>Try to clone an existing CL_Prop in the scene so the spawned
/// HP-bar tablet inherits the full hand-grab/throw pipeline (Rigidbody,
/// Colliders, CL_Prop component, sounds, etc.). Falls back to a plain
/// physics object if no template prop is found.</summary>
private static GameObject? TryCloneCLProp(Vector3 pos, Quaternion rot, ENT_Player player)
{
    CL_Prop? template = null;
    foreach (var p in Object.FindObjectsOfType<CL_Prop>())
    {
        if (p != null && p.gameObject != null && p.gameObject.activeInHierarchy)
        {
            template = p;
            break;
        }
    }
    if (template == null)
    {
        Plugin.LogInfo("EasterEgg: no CL_Prop in scene to clone — using free physics object.");
        return null;
    }

    GameObject clone;
    try { clone = Object.Instantiate(template.gameObject); }
    catch (System.Exception e)
    {
        Plugin.LogInfo($"EasterEgg: failed to clone CL_Prop '{template.name}': {e.Message}");
        return null;
    }

    clone.name = "TheFloorIsLava_HpBarProp";
    clone.transform.position = pos;
    clone.transform.rotation = rot;
    clone.transform.localScale = Vector3.one;

    // Disable cloned visuals.
    foreach (var mr in clone.GetComponentsInChildren<MeshRenderer>(true))
        mr.enabled = false;
    foreach (var sr in clone.GetComponentsInChildren<SkinnedMeshRenderer>(true))
        sr.enabled = false;

    // Resize box colliders to match the HP-bar tablet shape so the grab
    // raycast hits something the right size.
    var halfSize = new Vector3(0.225f, 0.013f, 0.05f);
    foreach (var col in clone.GetComponentsInChildren<Collider>(true))
    {
        if (col is BoxCollider box)
        {
            box.size = halfSize * 2f;
            box.center = Vector3.zero;
            box.enabled = true;
        }
        else if (col is MeshCollider mc)
        {
            mc.enabled = false; // mesh collider would still have the original shape
        }
    }
    if (clone.GetComponent<BoxCollider>() == null && clone.GetComponentInChildren<BoxCollider>() == null)
    {
        var box = clone.AddComponent<BoxCollider>();
        box.size = halfSize * 2f;
    }

    // Build and attach the slim translucent tablet visual.
    var visual = BuildHpBarVisual();
    visual.transform.SetParent(clone.transform, false);
    visual.transform.localPosition = Vector3.zero;
    visual.transform.localRotation = Quaternion.identity;

    // Stop and re-throw the cloned rigidbody.
    var rb = clone.GetComponent<Rigidbody>() ?? clone.GetComponentInChildren<Rigidbody>();
    if (rb != null)
    {
        rb.velocity = Vector3.zero;
        rb.angularVelocity = Vector3.zero;
        rb.useGravity = true;
        rb.isKinematic = false;
        ApplyThrowImpulse(rb, player);
    }

    return clone;
}

