using System.Collections.Generic;
using UnityEngine;

namespace SpikeBalanceMod;

/// <summary>
/// "Fan the lava" ability: repeated grab-button press/release cycles while
/// standing on lava cool a radial spot under the player, scaling damage by
/// local heat. Fully cooled spots pause before reheating; partial spots
/// reheat immediately once fanning stops.
/// </summary>
internal sealed class FanningSystem
{
    private readonly Config _cfg;
    private readonly List<CoolingSpot> _spots = new();

    private readonly HandCycleTracker _hand0 = new();
    private readonly HandCycleTracker _hand1 = new();

    private int _completedCycles;
    private float _hand0LastCycleTime = -999f;
    private float _hand1LastCycleTime = -999f;
    private float _lastCoolCycleTime = -999f;
    private bool _wasOnLava;

    private static Material? _patchMaterial;
    private static Material? _gustMaterial;

    public bool FanningActive => Time.time - _lastCoolCycleTime < 0.4f;
    public int CompletedCycles => _completedCycles;
    public int SpotCount => _spots.Count;

    public FanningSystem(Config cfg) => _cfg = cfg;

    public void Reset()
    {
        _completedCycles = 0;
        _hand0LastCycleTime = -999f;
        _hand1LastCycleTime = -999f;
        _lastCoolCycleTime = -999f;
        _wasOnLava = false;
        _hand0.Reset();
        _hand1.Reset();
        ClearSpots();
    }

    public void Tick(ENT_Player player, float dt, bool onLava)
    {
        if (!_cfg.FanningEnabled.Value)
            return;

        if (!onLava)
        {
            if (_wasOnLava)
            {
                _completedCycles = 0;
                _hand0.Reset();
                _hand1.Reset();
            }
            _wasOnLava = false;
            UpdateSpots(dt);
            return;
        }

        _wasOnLava = true;

        GameRefs.TryGetHand(player, 0, out var h0);
        GameRefs.TryGetHand(player, 1, out var h1);

        var c0 = h0 != null && _hand0.Tick(h0);
        var c1 = h1 != null && _hand1.Tick(h1);

        if (c0) OnHandCycle(player, 0, h0!);
        if (c1) OnHandCycle(player, 1, h1!);

        UpdateSpots(dt);
    }

    /// <summary>Effective lava heat at world position [0=fully cooled, 1=full damage].
    /// Uses the coolest overlapping spot within radius.</summary>
    public float GetEffectiveHeatAt(Vector3 worldPos)
    {
        if (_spots.Count == 0)
            return 1f;

        var radius = _cfg.FanningSpotRadius.Value;
        var radiusSq = radius * radius;
        var best = 1f;
        var found = false;

        foreach (var spot in _spots)
        {
            var dx = worldPos.x - spot.Center.x;
            var dz = worldPos.z - spot.Center.z;
            if (dx * dx + dz * dz > radiusSq)
                continue;
            found = true;
            if (spot.Heat < best)
                best = spot.Heat;
        }

        return found ? Mathf.Clamp01(best) : 1f;
    }

    private void OnHandCycle(ENT_Player player, int handIndex, object hand)
    {
        _completedCycles++;
        var now = Time.time;
        if (handIndex == 0) _hand0LastCycleTime = now;
        else _hand1LastCycleTime = now;

        if (_completedCycles < _cfg.FanningActivationCycles.Value)
        {
            Plugin.LogInfo($"Fanning: warmup cycle {_completedCycles}/{_cfg.FanningActivationCycles.Value} (no cool yet).");
            return;
        }

        var sync = _cfg.FanningBothHandsSyncWindow.Value;
        var otherTime = handIndex == 0 ? _hand1LastCycleTime : _hand0LastCycleTime;
        var bothHands = Mathf.Abs(now - otherTime) <= sync;

        var coolAmount = bothHands
            ? _cfg.FanningCoolPerCycleBoth.Value
            : _cfg.FanningCoolPerCycleSingle.Value;
        var gripCost = bothHands
            ? _cfg.FanningCostPerCycleBoth.Value
            : _cfg.FanningCostPerCycleSingle.Value;

        if (!GameRefs.DamageGripOnHand(hand, gripCost))
        {
            Plugin.LogInfo($"Fanning: hand {handIndex} out of grip ({GameRefs.GetGripStrength(hand):F1} < {gripCost:F1}).");
            return;
        }

        var feet = GameRefs.FeetPosition(player);
        var spot = GetOrCreateSpot(feet);
        spot.Heat = Mathf.Clamp01(spot.Heat - coolAmount);
        spot.LastFanTime = now;
        spot.UpdateVisual(_cfg.FanningSpotRadius.Value);

        _lastCoolCycleTime = now;

        GustEffect.Play(player, handIndex, bothHands);

        Plugin.LogInfo(
            $"Fanning: hand={handIndex} both={bothHands} spotHeat={spot.Heat:F2} " +
            $"gripLeft={GameRefs.GetGripStrength(hand):F1} spots={_spots.Count}");
    }

    private CoolingSpot GetOrCreateSpot(Vector3 feet)
    {
        var merge = _cfg.FanningSpotMergeRadius.Value;
        var mergeSq = merge * merge;
        CoolingSpot? best = null;
        var bestDistSq = float.MaxValue;

        foreach (var spot in _spots)
        {
            var dx = feet.x - spot.Center.x;
            var dz = feet.z - spot.Center.z;
            var distSq = dx * dx + dz * dz;
            if (distSq <= mergeSq && distSq < bestDistSq)
            {
                bestDistSq = distSq;
                best = spot;
            }
        }

        if (best != null)
            return best;

        var surface = SampleSurface(feet);
        var created = new CoolingSpot(surface.point, surface.normal, BuildPatchMaterial());
        _spots.Add(created);
        EnforceSpotCap();
        created.UpdateVisual(_cfg.FanningSpotRadius.Value);
        return created;
    }

    private static (Vector3 point, Vector3 normal) SampleSurface(Vector3 near)
    {
        var origin = near + Vector3.up * 0.35f;
        if (Physics.Raycast(origin, Vector3.down, out var hit, 1.5f, ~0, QueryTriggerInteraction.Ignore))
            return (hit.point + hit.normal * 0.025f, hit.normal);
        return (near, Vector3.up);
    }

    private void UpdateSpots(float dt)
    {
        if (_spots.Count == 0)
            return;

        var delay = _cfg.FanningHeatRecoveryDelay.Value;
        var recoveryRate = _cfg.FanningHeatRecoveryTime.Value > 0.01f
            ? 1f / _cfg.FanningHeatRecoveryTime.Value
            : 0.25f;
        var fanningRecently = Time.time - _lastCoolCycleTime < 0.35f;
        var radius = _cfg.FanningSpotRadius.Value;

        for (var i = _spots.Count - 1; i >= 0; i--)
        {
            var spot = _spots[i];
            if (!fanningRecently)
            {
                var fullyCooled = spot.Heat <= 0.001f;
                var canRecover = !fullyCooled || Time.time - spot.LastFanTime >= delay;
                if (canRecover)
                    spot.Heat = Mathf.Min(1f, spot.Heat + recoveryRate * dt);
            }

            if (spot.Heat >= 0.999f)
            {
                spot.Dispose();
                _spots.RemoveAt(i);
                continue;
            }

            spot.UpdateVisual(radius);
        }
    }

    private void EnforceSpotCap()
    {
        var cap = _cfg.FanningSpotMaxCount.Value;
        while (_spots.Count > cap)
        {
            _spots[0].Dispose();
            _spots.RemoveAt(0);
        }
    }

    private void ClearSpots()
    {
        foreach (var s in _spots)
            s.Dispose();
        _spots.Clear();
    }

    private static Material BuildPatchMaterial()
    {
        if (_patchMaterial != null) return _patchMaterial;

        Shader? shader = null;
        foreach (var n in new[] { "Universal Render Pipeline/Unlit", "Standard", "Unlit/Texture" })
        {
            shader = Shader.Find(n);
            if (shader != null) break;
        }
        if (shader == null) shader = Shader.Find("Hidden/InternalErrorShader");

        _patchMaterial = new Material(shader!) { name = "TheFloorIsLava_CoolPatch" };
        if (_patchMaterial.HasProperty("_Surface")) _patchMaterial.SetFloat("_Surface", 0f);
        if (_patchMaterial.HasProperty("_AlphaClip")) _patchMaterial.SetFloat("_AlphaClip", 1f);
        if (_patchMaterial.HasProperty("_Cutoff")) _patchMaterial.SetFloat("_Cutoff", 0.05f);
        _patchMaterial.EnableKeyword("_ALPHATEST_ON");
        _patchMaterial.renderQueue = (int)UnityEngine.Rendering.RenderQueue.AlphaTest + 2;
        return _patchMaterial;
    }

