    private sealed class CoolingSpot
    {
        public Vector3 Center;
        public Vector3 Normal;
        public float Heat = 1f;
        public float LastFanTime;
        private readonly GameObject _visual;
        private readonly MeshRenderer _renderer;
        private readonly Material _matInstance;

        public CoolingSpot(Vector3 center, Vector3 normal, Material sharedMat)
        {
            Center = center;
            Normal = normal;
            LastFanTime = Time.time;

            _visual = GameObject.CreatePrimitive(PrimitiveType.Cube);
            _visual.name = "TheFloorIsLava_CoolSpot";
            Object.Destroy(_visual.GetComponent<Collider>());
            _visual.transform.position = center;
            _visual.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);
            _visual.transform.localScale = new Vector3(1f, 0.012f, 1f);

            _renderer = _visual.GetComponent<MeshRenderer>();
            _matInstance = new Material(sharedMat) { name = "TheFloorIsLava_CoolSpotMat" };
            _renderer.sharedMaterial = _matInstance;
            _renderer.shadowCastingMode = UnityEngine.Rendering.ShadowCastingMode.Off;
            _renderer.receiveShadows = false;
        }

        public void UpdateVisual(float radius)
        {
            if (_visual == null) return;
            var diameter = radius * 2f;
            _visual.transform.localScale = new Vector3(diameter, 0.012f, diameter);

            // heat 0 = dark cooled patch, heat 1 = invisible (fully reheated).
            var coolStrength = 1f - Heat;
            var dark = new Color(0.06f, 0.06f, 0.08f, 1f);
            var warm = new Color(0.35f, 0.12f, 0.05f, 1f);
            var col = Color.Lerp(warm, dark, coolStrength);
            _matInstance.color = col;
            if (_matInstance.HasProperty("_BaseColor")) _matInstance.SetColor("_BaseColor", col);
            if (_matInstance.HasProperty("_EmissionColor"))
            {
                var em = col * (0.4f + coolStrength * 0.8f);
                _matInstance.SetColor("_EmissionColor", em);
                _matInstance.EnableKeyword("_EMISSION");
            }
        }

        public void Dispose()
        {
            if (_visual != null) Object.Destroy(_visual);
            if (_matInstance != null) Object.Destroy(_matInstance);
        }
    }
}

/// <summary>Short-lived puff quads at the fanning hand(s).</summary>
internal static class GustEffect
{
    private static readonly List<GustPuff> _active = new();
    private static Material? _mat;

    public static void Play(ENT_Player player, int handIndex, bool bothHands)
    {
        SpawnAt(player, handIndex);
        if (bothHands)
            SpawnAt(player, handIndex == 0 ? 1 : 0);
    }

    public static void Tick(float dt)
    {
        for (var i = _active.Count - 1; i >= 0; i--)
        {
            if (!_active[i].Tick(dt))
                _active.RemoveAt(i);
        }
    }

    private static void SpawnAt(ENT_Player player, int handIndex)
    {
        var model = GameRefs.GetHandModel(player, handIndex);
        if (model == null) return;

        var cam = Camera.main;
        var fwd = cam != null ? cam.transform.forward : player.transform.forward;
        fwd.y = 0f;
        if (fwd.sqrMagnitude < 0.01f) fwd = Vector3.forward;
        fwd.Normalize();

        _active.Add(new GustPuff(model.position + fwd * 0.08f + Vector3.down * 0.05f, fwd, BuildMaterial()));
    }

    private static Material BuildMaterial()
    {
        if (_mat != null) return _mat;
        Shader? shader = Shader.Find("Universal Render Pipeline/Unlit") ?? Shader.Find("Standard");
        _mat = new Material(shader!) { name = "TheFloorIsLava_Gust" };
        if (_mat.HasProperty("_AlphaClip")) _mat.SetFloat("_AlphaClip", 1f);
        if (_mat.HasProperty("_Cutoff")) _mat.SetFloat("_Cutoff", 0.05f);
        _mat.EnableKeyword("_ALPHATEST_ON");
        _mat.renderQueue = (int)UnityEngine.Rendering.RenderQueue.Transparent;
        return _mat;
    }

    private sealed class GustPuff
    {
        private readonly GameObject _go;
        private readonly MeshRenderer _mr;
        private readonly Material _inst;
        private readonly Vector3 _velocity;
        private float _life = 0.28f;

        public GustPuff(Vector3 pos, Vector3 dir, Material shared)
        {
            _go = GameObject.CreatePrimitive(PrimitiveType.Cube);
            _go.name = "TheFloorIsLava_Gust";
            Object.Destroy(_go.GetComponent<Collider>());
            _go.transform.position = pos;
            _go.transform.localScale = new Vector3(0.06f, 0.02f, 0.14f);
            _go.transform.rotation = Quaternion.LookRotation(dir, Vector3.up);
            _mr = _go.GetComponent<MeshRenderer>();
            _inst = new Material(shared);
            _mr.sharedMaterial = _inst;
            _mr.shadowCastingMode = UnityEngine.Rendering.ShadowCastingMode.Off;
            _velocity = dir * 1.8f + Vector3.up * 0.25f;
            SetAlpha(0.75f);
        }

        public bool Tick(float dt)
        {
            _life -= dt;
            _go.transform.position += _velocity * dt;
            _go.transform.localScale += Vector3.one * (dt * 0.35f);
            SetAlpha(Mathf.Clamp01(_life / 0.28f) * 0.75f);
            return _life > 0f;
        }

        private void SetAlpha(float a)
        {
            var c = new Color(0.85f, 0.92f, 1f, a);
            _inst.color = c;
            if (_inst.HasProperty("_BaseColor")) _inst.SetColor("_BaseColor", c);
        }
    }
}

