private void OnFanCycle(ENT_Player player, object primaryHand, object? secondaryHand, bool bothHands)
{
    _completedCycles++;
    var now = Time.time;

    // Track both hands' cycle times when simultaneous.
    _hand0LastCycleTime = now;
    _hand1LastCycleTime = now;

    if (_completedCycles < _cfg.FanningActivationCycles.Value)
    {
        Plugin.LogInfo($"Fanning: warmup cycle {_completedCycles}/{_cfg.FanningActivationCycles.Value} (no cool yet).");
        return;
    }

    var coolAmount = bothHands
        ? _cfg.FanningCoolPerCycleBoth.Value
        : _cfg.FanningCoolPerCycleSingle.Value;
    var gripCost = bothHands
        ? _cfg.FanningCostPerCycleBoth.Value
        : _cfg.FanningCostPerCycleSingle.Value;

    if (!GameRefs.DamageGripOnHand(primaryHand, gripCost))
    {
        Plugin.LogInfo($"Fanning: not enough grip ({GameRefs.GetGripStrength(primaryHand):F1} < {gripCost:F1}).");
        return;
    }

    if (bothHands && secondaryHand != null)
        GameRefs.DamageGripOnHand(secondaryHand, gripCost);

    var feet = GameRefs.FeetPosition(player);
    var spot = GetOrCreateSpot(feet);
    spot.Heat = Mathf.Clamp01(spot.Heat - coolAmount);
    spot.LastFanTime = now;
    spot.UpdateVisual(_cfg.FanningSpotRadius.Value);

    _lastCoolCycleTime = now;

    var handIndex = GameRefs.TryGetHand(player, 0, out var h0) && ReferenceEquals(h0, primaryHand) ? 0 : 1;
    GustEffect.Play(player, handIndex, bothHands);

    Plugin.LogInfo(
        $"Fanning: both={bothHands} spotHeat={spot.Heat:F2} " +
        $"grip={GameRefs.GetGripStrength(primaryHand):F1} spots={_spots.Count}");
}

