/// <summary>Effective lava heat at the player's position [0=fully cooled, 1=full damage].
/// Checks both feet and body XZ against every spot within radius.</summary>
public float GetEffectiveHeatAt(Vector3 feet, Vector3 body)
{
    if (_spots.Count == 0)
        return 1f;

    // Small grace so feet/body jitter doesn't miss a spot the player is standing on.
    var radius = _cfg.FanningSpotRadius.Value + 0.15f;
    var radiusSq = radius * radius;
    var best = 1f;
    var found = false;

    foreach (var spot in _spots)
    {
        if (!spot.Overlaps(feet, radiusSq) && !spot.Overlaps(body, radiusSq))
            continue;
        found = true;
        if (spot.Heat < best)
            best = spot.Heat;
    }

    return found ? Mathf.Clamp01(best) : 1f;
}

