private static Material BuildPatchMaterial()
{
    if (_patchMaterial != null) return _patchMaterial;

    Shader? shader = null;
    foreach (var n in new[]
             {
                 "Universal Render Pipeline/Unlit",
                 "Unlit/Transparent",
                 "Legacy Shaders/Transparent/Diffuse",
                 "Standard",
             })
    {
        shader = Shader.Find(n);
        if (shader != null) break;
    }
    if (shader == null) shader = Shader.Find("Hidden/InternalErrorShader");

    _patchMaterial = new Material(shader!) { name = "TheFloorIsLava_CoolPatch" };

    // Grey translucent overlay — alpha scales with how cooled the spot is.
    var grey = new Color(0.42f, 0.42f, 0.46f, 0.55f);
    _patchMaterial.color = grey;
    if (_patchMaterial.HasProperty("_BaseColor")) _patchMaterial.SetColor("_BaseColor", grey);
    if (_patchMaterial.HasProperty("_Color")) _patchMaterial.SetColor("_Color", grey);

    if (_patchMaterial.HasProperty("_Surface")) _patchMaterial.SetFloat("_Surface", 1f);
    if (_patchMaterial.HasProperty("_Blend")) _patchMaterial.SetFloat("_Blend", 0f);
    if (_patchMaterial.HasProperty("_SrcBlend"))
        _patchMaterial.SetFloat("_SrcBlend", (float)UnityEngine.Rendering.BlendMode.SrcAlpha);
    if (_patchMaterial.HasProperty("_DstBlend"))
        _patchMaterial.SetFloat("_DstBlend", (float)UnityEngine.Rendering.BlendMode.OneMinusSrcAlpha);
    if (_patchMaterial.HasProperty("_ZWrite")) _patchMaterial.SetFloat("_ZWrite", 0f);
    if (_patchMaterial.HasProperty("_Cull")) _patchMaterial.SetFloat("_Cull", 0f);
    if (_patchMaterial.HasProperty("_AlphaClip")) _patchMaterial.SetFloat("_AlphaClip", 0f);
    _patchMaterial.EnableKeyword("_SURFACE_TYPE_TRANSPARENT");
    _patchMaterial.EnableKeyword("_ALPHABLEND_ON");
    _patchMaterial.DisableKeyword("_ALPHATEST_ON");
    _patchMaterial.renderQueue = (int)UnityEngine.Rendering.RenderQueue.Transparent;
    return _patchMaterial;
}

/// <summary>Flat radial disc mesh with soft edge falloff baked into vertex alpha.</summary>
private static Mesh CreateDiscMesh(int segments = 32)
{
    var mesh = new Mesh { name = "TheFloorIsLava_CoolDisc" };
    var vertCount = segments + 1;
    var verts = new Vector3[vertCount];
    var colors = new Color[vertCount];
    var uvs = new Vector2[vertCount];
    var tris = new int[segments * 3];

    verts[0] = Vector3.zero;
    colors[0] = new Color(1f, 1f, 1f, 1f);
    uvs[0] = new Vector2(0.5f, 0.5f);

    for (var i = 0; i < segments; i++)
    {
        var t = i / (float)segments * Mathf.PI * 2f;
        var c = Mathf.Cos(t);
        var s = Mathf.Sin(t);
        var idx = i + 1;
        verts[idx] = new Vector3(c, 0f, s);
        colors[idx] = new Color(1f, 1f, 1f, 0f); // soft radial edge
        uvs[idx] = new Vector2(c * 0.5f + 0.5f, s * 0.5f + 0.5f);
        tris[i * 3] = 0;
        tris[i * 3 + 1] = idx;
        tris[i * 3 + 2] = idx == segments ? 1 : idx + 1;
    }

    mesh.vertices = verts;
    mesh.colors = colors;
    mesh.uv = uvs;
    mesh.triangles = tris;
    mesh.RecalculateNormals();
    mesh.RecalculateBounds();
    return mesh;
}

