    private sealed class CoolingSpot
    {
        public Vector3 Center;
        public Vector3 Normal;
        public float Heat = 1f;
        public float LastFanTime;
        private readonly GameObject _visual;
        private readonly MeshRenderer _renderer;
        private readonly Material _matInstance;
        private static Mesh? _discMesh;

        public CoolingSpot(Vector3 feet, Vector3 surfacePoint, Vector3 normal, Material sharedMat)
        {
            Normal = normal;
            LastFanTime = Time.time;
            Center = new Vector3(feet.x, surfacePoint.y, feet.z);

            _visual = new GameObject("TheFloorIsLava_CoolSpot");
            var mf = _visual.AddComponent<MeshFilter>();
            _discMesh ??= CreateDiscMesh();
            mf.sharedMesh = _discMesh;
            _renderer = _visual.AddComponent<MeshRenderer>();
            _matInstance = new Material(sharedMat) { name = "TheFloorIsLava_CoolSpotMat" };
            _renderer.sharedMaterial = _matInstance;
            _renderer.shadowCastingMode = UnityEngine.Rendering.ShadowCastingMode.Off;
            _renderer.receiveShadows = false;

            ApplyTransform(surfacePoint, normal);
        }

        public void Reposition(Vector3 feet, Vector3 surfacePoint, Vector3 normal)
        {
            Normal = normal;
            Center = new Vector3(feet.x, surfacePoint.y, feet.z);
            ApplyTransform(surfacePoint, normal);
        }

        public bool Overlaps(Vector3 worldPos, float radiusSq)
        {
            var dx = worldPos.x - Center.x;
            var dz = worldPos.z - Center.z;
            return dx * dx + dz * dz <= radiusSq;
        }

        private void ApplyTransform(Vector3 surfacePoint, Vector3 normal)
        {
            _visual.transform.position = new Vector3(Center.x, surfacePoint.y + 0.03f, Center.z);
            _visual.transform.rotation = Quaternion.FromToRotation(Vector3.up, normal);
        }

        public void UpdateVisual(float radius)
        {
            if (_visual == null) return;
            var diameter = radius * 2f;
            _visual.transform.localScale = new Vector3(diameter, 1f, diameter);

            // heat 1 = invisible, heat 0 = visible grey mask at full strength.
            var maskStrength = (1f - Heat) * 0.55f;
            var col = new Color(0.42f, 0.42f, 0.46f, maskStrength);
            _matInstance.color = col;
            if (_matInstance.HasProperty("_BaseColor")) _matInstance.SetColor("_BaseColor", col);
            if (_matInstance.HasProperty("_Color")) _matInstance.SetColor("_Color", col);
        }

        public void Dispose()
        {
            if (_visual != null) Object.Destroy(_visual);
            if (_matInstance != null) Object.Destroy(_matInstance);
        }
    }
}

