private float ComputeStandingHeat(ENT_Player player)
{
    if (_spots.Count == 0)
        return 1f;

    var pos = player.transform.position;
    var feet = GameRefs.FeetPosition(player);
    var radius = _cfg.FanningSpotRadius.Value + 0.5f;
    var radiusSq = radius * radius;
    var best = 1f;

    foreach (var spot in _spots)
